export const qbMerchProblemSolving = [
  { "FABM1-MerchBusActgPCQ-001": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Cash Discount", "type": "Problem Solving", "competency": "Apply", "question": "Goods were purchased for ₱20,000 with terms 2/10, n/30. If payment is made within the discount period, how much is paid?", "solution": 19600, "explanation": "Original Invoice: ₱20,000 * (1 - (Discount Rate: 0.02)) = Amount Paid: ₱19,600" } },
  { "FABM1-MerchBusActgPCQ-002": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Cash Discount", "type": "Problem Solving", "competency": "Apply", "question": "Purchased goods for ₱50,000, terms 2/10, n/30. Returned ₱5,000 worth of defective goods before payment. If paid within the discount period, calculate the amount paid.", "solution": 44100, "explanation": "Initial Purchase: ₱50,000 - Purchase Returns: 5,000 = Net Purchase: ₱45,000 * (1 - (Discount Rate: 0.02)): 0.98 = Amount Paid: ₱44,100" } },
  { "FABM1-MerchBusActgPCQ-003": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Cost of Goods Sold", "type": "Problem Solving", "competency": "Apply", "question": "Beginning Inventory: ₱10,000. Net Purchases: ₱40,000. Ending Inventory: ₱12,000. Calculate Cost of Goods Sold.", "solution": 38000, "explanation": "Beginning Inventory: ₱10,000 + Net Purchases: 40,000 - Ending Inventory: 12,000 = Cost of Goods Sold: ₱38,000" } },
  { "FABM1-MerchBusActgPCQ-004": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Cost of Goods Sold", "type": "Problem Solving", "competency": "Analyze", "question": "Cost of Goods Available for Sale is ₱100,000. Cost of Goods Sold is ₱70,000. What is the value of Ending Inventory?", "solution": 30000, "explanation": "Total Goods Available for Sale: ₱100,000 - Ending Inventory (X):  = Cost of Goods Sold: ₱70,000. To find for X. Total Goods Available for Sale: ₱100,000 - Cost of Goods sold: 70,000 = Ending Inventory Value: ₱30,000." } },
  { "FABM1-MerchBusActgPCQ-005": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "FIFO Costing", "type": "Problem Solving", "competency": "Apply", "question": "Beginning Inventory: 10 units @ 10 PHP. Purchased: 20 units @ 12 PHP. Sold: 15 units. Calculate the value of Ending Inventory using FIFO.", "solution": 180, "explanation": "Beginning units: 10 + Purchased units: 20 - Sold units: 15 = Remaining units: 15. Under FIFO, ending inventory comes from the latest purchases: Remaining units: 15 * Latest Unit Cost per unit:  ₱12 = Ending Inventory Value:  ₱180" } },
  { "FABM1-MerchBusActgPCQ-006": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "FIFO Costing", "type": "Problem Solving", "competency": "Apply", "question": "Beginning Inventory: 10 units @ 10 PHP. Purchased: 20 units @ 12 PHP. Sold: 15 units. Calculate COGS using FIFO.", "solution": 160, "explanation": "Sold 15 units. FIFO uses beginning inventory first (10 units * ₱10): ₱100 + Remaining 5 from purchase from first purchase (5 units * 12):  60 = Total COGS: ₱160" } },
  { "FABM1-MerchBusActgPCQ-007": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Freight In", "type": "Problem Solving", "competency": "Apply", "question": "Purchases are 80,000 PHP, Purchase Returns 2,000 PHP, Purchase Discounts 1,000 PHP, and Freight In 500 PHP. Calculate Net Cost of Purchases.", "solution": 77500, "explanation": "Purchases:  ₱80,000 - Purchase Returns:  ₱2,000 - Purchase Discounts:  ₱1,000 + Freight In:  ₱500 = Net Cost of Purchases:  ₱77,500" } },
  { "FABM1-MerchBusActgPCQ-008": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Freight Out", "type": "Problem Solving", "competency": "Analyze", "question": "A seller sold goods FOB Destination. The shipping cost was 1,500 PHP. The goods cost 10,000 PHP and were sold for 15,000 PHP. What amount is recorded as Freight Out expense?", "solution": 1500, "explanation": "FOB Destination means seller pays freight. Selling paid freight is selling or delivery expense that is usually called Freight Out." } },
  { "FABM1-MerchBusActgPCQ-009": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Merchandising Operations", "type": "Problem Solving", "competency": "Apply", "question": "Net Sales are 200,000 PHP and Cost of Goods Sold is 120,000 PHP. Calculate Gross Profit.", "solution": 80000, "explanation": "Net Sales:  ₱200,000 - Cost of Goods Sold:  ₱120,000 = Gross Profit:  ₱80,000" } },
  { "FABM1-MerchBusActgPCQ-010": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Merchandising Operations", "type": "Problem Solving", "competency": "Apply", "question": "Gross Profit is 60,000 PHP. Operating Expenses are 25,000 PHP. Calculate Net Income.", "solution": 35000, "explanation": "Gross Profit:  ₱60,000 - Operating Expenses:  ₱25,000 = Net Income:  ₱35,000" } },
  { "FABM1-MerchBusActgPCQ-011": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Moving Average Costing", "type": "Problem Solving", "competency": "Apply", "question": "Jan 1 Balance: 10 units @ 20 PHP. Jan 5 Purchase: 10 units @ 24 PHP. Calculate the new moving average unit cost after Jan 5 purchase.", "solution": 22, "explanation": "Jan 1 purchase (10 units @ P20 per unit):  ₱200 + Jan 5 purchase (10 units @ P24 per unit):  ₱240 = Total Value:  ₱440 / Total Units (Jan 1 purchase: 10 units + Jan 5 purchase: 10 units): 20 = Moving Average Cost per unit:  ₱22" } },
  { "FABM1-MerchBusActgPCQ-012": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Net Sales", "type": "Problem Solving", "competency": "Apply", "question": "Gross Sales are 150,000 PHP. Sales Returns are 5,000 PHP and Sales Discounts are 2,000 PHP. Calculate Net Sales.", "solution": 143000, "explanation": "Gross Sales:  ₱150,000 - Sales Returns:  ₱5,000 - Sales Discounts:  ₱2,000 = Net Sales:  ₱143,000" } },
  { "FABM1-MerchBusActgPCQ-013": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Periodic Inventory System", "type": "Problem Solving", "competency": "Apply", "question": "Beginning Inventory is  ₱5,000. Purchases are  ₱25,000. Freight In is  ₱1,000. Purchase Returns are  ₱2,000. Calculate Cost of Goods Available for Sale.", "solution": 29000, "explanation": "Beginning Inventory:  ₱5,000 + Purchases:  ₱25,000 + Freight In:  ₱1,000 - Purchase Returns:  ₱2,000 = Cost of Goods Available for Sale:  ₱29,000" } },
  { "FABM1-MerchBusActgPCQ-014": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Perpetual Inventory System", "type": "Problem Solving", "competency": "Analyze", "question": "Inventory record shows a balance of  ₱50,000. Physical count shows  ₱48,500. Calculate the amount of inventory shrinkage/shortage.", "solution": 1500, "explanation": "Recorded Inventory Balance:  ₱50,000 - Physical Count Balance:  ₱48,500 = Inventory Shrinkage:  ₱1,500" } },
  { "FABM1-MerchBusActgPCQ-015": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Purchase Returns", "type": "Problem Solving", "competency": "Apply", "question": "A company bought goods for  ₱10,000 on credit. They returned 1,500 worth of goods. What is the remaining Accounts Payable balance?", "solution": 8500, "explanation": "Original Purchase on Credit:  ₱10,000 - Returned Goods Value:  ₱1,500 = Remaining Accounts Payable:  ₱8,500" } },
  { "FABM1-MerchBusActgPCQ-016": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Sales Returns", "type": "Problem Solving", "competency": "Apply", "question": "Sold goods for  ₱100,000 on account. Customer returned  ₱10,000 worth of goods. Subsequently, the customer paid the balance within the discount period of 2%. Calculate the cash received.", "solution": 88200, "explanation": "Receivable balance: Original Sale:  ₱100,000 - Sales Returns:  ₱10,000 = Net Receivable:  ₱90,000 - Discount (Net Receivable: 90,000) * (Discount Rate: 0.02):  ₱1,800 = Cash Received:  ₱88,200" } },
  { "FABM1-MerchBusActgPCQ-017": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Trade Discount", "type": "Problem Solving", "competency": "Apply", "question": "A merchandiser buys an item with a list price of  ₱50,000 subject to a 20% trade discount. Calculate the invoice price.", "solution": 40000, "explanation": "List Price:  ₱50,000 * (1 - (Trade Discount Rate: 0.20)): 0.80 = Invoice Price:  ₱40,000" } },
  { "FABM1-MerchBusActgPCQ-018": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Trade Discount", "type": "Problem Solving", "competency": "Apply", "question": "A list price of  ₱100,000 is subject to trade discounts of 20% and 10%. Calculate the net invoice price.", "solution": 72000, "explanation": "List Price:  ₱100,000 * (1 - (First Trade Discount: 0.20)): 0.80 = Price after First Discount:  ₱80,000 * (1 - (Second Trade Discount: 0.10)): 0.90 = Net Invoice Price: ₱72,000" } },
  { "FABM1-MerchBusActgPCQ-019": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Weighted Average Costing", "type": "Problem Solving", "competency": "Apply", "question": "Beginning Inv: 100 units @ ₱10. Purchase: 100 units @ ₱14. Calculate the weighted average unit cost.", "solution": 12, "explanation": "Beginning Inventory (100 units @ ₱10 per unit): P1,000 + Purchase (100 units * ₱14 per unit): ₱1,400 = Total Cost: ₱2,400 / Total units (100 beginning units + 100 purcahsed units): 200 = Weighted Average Cost: ₱12" } },
  { "FABM1-MerchBusActgPCQ-020": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Weighted Average Costing", "type": "Problem Solving", "competency": "Apply", "question": "Using the weighted average cost of ₱12 per unit, if 150 units are sold, calculate the Cost of Goods Sold.", "solution": 1800, "explanation": "Sold units: 150 * Weighted Average Cost: ₱12 = Cost of Goods Sold: ₱1,800" } },

  { "FAR-CashAndCashEq-001": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Classification of Cash Equivalents", "type": "Problem Solving", "competency": "Apply", "question": "Tranvia Company had the following balances on December 31, 2023: Cash in checking account ₱350,000; Cash in money market account ₱750,000; Treasury bill, purchased November 1, 2023 maturing January 31, 2024: ₱3,500,000; Time deposit purchased December 1, 2023 maturing March 31, 2024: ₱4,000,000. What amount should be reported as cash and cash equivalents on December 31, 2023?", "solution": 4600000, "explanation": "Cash in checking account: ₱350,000 + Cash in money market account: 750,000 + Treasury bill (three month term): 3,500,000 = Total cash and cash equivalents: ₱4,600,000. Under PAS 7, the time deposit is excluded from cash equivalents because its term is four months from December 1 to March 31, which exceeds the strict short maturity requirement of three months or less from the date of acquisition. The Treasury bill is included because it matures within exactly three months from its purchase date." } },
  { "FAR-CashAndCashEq-002": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Bank Overdrafts and Restrictions", "type": "Problem Solving", "competency": "Analyze", "question": "A company reported the following: Cash in bank Bank A Checking ₱500,000; Cash in bank Bank A Savings ₱200,000; Cash in bank Bank B Checking overdraft ₱100,000; Legally restricted compensating balance in Bank C ₱150,000; Cash on hand ₱50,000. What is the total cash and cash equivalents?", "solution": 750000, "explanation": "Cash in bank Bank A Checking: ₱500,000 + Cash in bank Bank A Savings: 200,000 + Cash on hand: 50,000 = Total cash and cash equivalents: ₱750,000. The overdraft in Bank B is excluded and reported as a current liability because overdrafts cannot be offset against positive balances in different banks due to the lack of mutual creditor and debtor relationships. The legally restricted compensating balance is excluded from cash because it is legally frozen as collateral and is not available for general business use." } },
  { "FAR-CashAndCashEq-003": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Adjustments to Cash Balance", "type": "Problem Solving", "competency": "Apply", "question": "The unadjusted cash balance of ₱1,500,000 includes the following: Customer postdated check ₱100,000; Customer NSF check ₱50,000; Unreleased company check ₱150,000; Company check postdated to next year ₱200,000. Calculate the adjusted cash balance.", "solution": 1700000, "explanation": "Unadjusted cash balance: ₱1,500,000 - Customer postdated check: 100,000 - Customer NSF check: 50,000 + Unreleased company check: 150,000 + Postdated company check: 200,000 = Adjusted cash balance: ₱1,700,000. Customer postdated and NSF checks are deducted because they are not valid cash collections and must revert to receivables. The unreleased company check is added back to cash because the payment is not consummated until physical delivery to the payee. The postdated company check is added back because the check cannot be validly encashed by the payee until the future date." } },
  { "FAR-CashAndCashEq-004": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Petty Cash Fund", "type": "Problem Solving", "competency": "Apply", "question": "The petty cash fund has a ledger balance of ₱20,000. A count reveals: Bills and coins ₱5,000; Employee IOUs ₱3,000; Unreplenished vouchers for supplies ₱10,000; Replenishment check drawn to the custodian ₱2,000. What is the correct petty cash balance?", "solution": 7000, "explanation": "Bills and coins: ₱5,000 + Replenishment check: 2,000 = Correct petty cash fund: ₱7,000. IOUs are excluded from cash because they are essentially advances or receivables from employees. Unreplenished vouchers are excluded because they represent expenses that have already been paid out from the fund and simply await formal recording." } },
  { "FAR-CashAndCashEq-005": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Short Term Investments", "type": "Problem Solving", "competency": "Analyze", "question": "Evaluate these investments: 90 day treasury bill ₱1,000,000; 180 day treasury bill purchased 30 days before maturity ₱500,000; 1 year treasury bill purchased 3 months before maturity ₱800,000; Equity securities purchased to sell in 2 months ₱600,000. Calculate the total cash equivalents.", "solution": 2300000, "explanation": "90 day treasury bill: ₱1,000,000 + 180 day treasury bill purchased 30 days before maturity: 500,000 + 1 year treasury bill purchased 3 months before maturity: 800,000 = Total cash equivalents: ₱2,300,000. Equity securities are completely excluded from cash equivalents, regardless of how soon they will be sold, because they represent ownership rather than debt and inherently lack a fixed maturity date." } },
  { "FAR-CashAndCashEq-006": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Cash on Hand Components", "type": "Problem Solving", "competency": "Apply", "question": "A company cash on hand includes: Currency and coins ₱120,000; Postal stamps ₱2,000; Travel advances ₱15,000; Manager check ₱30,000; Traveler check ₱40,000. Compute the correct cash on hand.", "solution": 190000, "explanation": "Currency and coins: ₱120,000 + Manager check: 30,000 + Traveler check: 40,000 = Correct cash on hand: ₱190,000. Postal stamps are excluded because they are physical goods classified as prepaid office supplies. Travel advances are excluded because they represent a future liquidation of expenses or receivables from traveling employees." } },
  { "FAR-CashAndCashEq-007": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Foreign Currency and Time Deposits", "type": "Problem Solving", "competency": "Apply", "question": "A firm has a Checking account ₱800,000; Unrestricted foreign bank account ₱1,200,000; Restricted foreign bank account ₱500,000; and a 60 day Time deposit ₱400,000. Compute the total cash and cash equivalents.", "solution": 2400000, "explanation": "Checking account: ₱800,000 + Unrestricted foreign bank account: 1,200,000 + 60 day time deposit: 400,000 = Total cash and cash equivalents: ₱2,400,000. The restricted foreign bank account is excluded from the current cash balance because restrictions block the company from freely utilizing the funds to settle current operating obligations." } },
  { "FAR-CashAndCashEq-008": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Compensating Balances", "type": "Problem Solving", "competency": "Analyze", "question": "An unadjusted cash balance of ₱3,000,000 includes a legally restricted compensating balance of ₱400,000 and an informal unrestricted compensating balance of ₱200,000. A 3 month money market placement of ₱600,000 is not yet recorded. What is the correct cash and cash equivalents?", "solution": 3200000, "explanation": "Unadjusted cash balance: ₱3,000,000 - Legally restricted compensating balance: 400,000 + 3 month money market placement: 600,000 = Correct cash and cash equivalents: ₱3,200,000. The legally restricted compensating balance is deducted because it serves as blocked collateral for a loan. The informal compensating balance remains part of cash because there is no binding legal agreement preventing its withdrawal." } },
  { "FAR-CashAndCashEq-009": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Restricted Funds", "type": "Problem Solving", "competency": "Analyze", "question": "Determine cash and cash equivalents given the following: Cash on hand ₱100,000; Cash in bank ₱900,000; Sinking fund cash ₱400,000; Cash in escrow ₱250,000; 60 day commercial paper ₱350,000.", "solution": 1350000, "explanation": "Cash on hand: ₱100,000 + Cash in bank: 900,000 + 60 day commercial paper: 350,000 = Total cash and cash equivalents: ₱1,350,000. Sinking fund cash is excluded because it is earmarked specifically for retiring noncurrent debt. Cash in escrow is excluded because its release is strictly tied to the completion of a pending contract or condition." } },
  { "FAR-CashAndCashEq-010": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Adjusted Bank Balance", "type": "Problem Solving", "competency": "Apply", "question": "The balance per bank statement is ₱1,200,000. Deposits in transit are ₱300,000. Outstanding checks amount to ₱450,000. A bank error incorrectly charged the company account for ₱50,000. Calculate the adjusted cash in bank balance.", "solution": 1100000, "explanation": "Balance per bank: ₱1,200,000 + Deposits in transit: 300,000 - Outstanding checks: 450,000 + Bank error erroneous charge: 50,000 = Adjusted cash in bank: ₱1,100,000. The erroneous bank charge is added back because the bank wrongfully deducted it from the company account, so correcting the bank balance requires restoring the improperly charged amount." } },
  { "FAR-CashAndCashEq-011": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Classification of Cash Equivalents", "type": "Problem Solving", "competency": "Analyze", "question": "On December 31, a company has: Cash in bank ₱2,000,000; 120 day treasury bill purchased December 1 ₱500,000; 90 day time deposit ₱400,000; 180 day commercial paper purchased November 1 ₱600,000. Calculate total cash and cash equivalents.", "solution": 2400000, "explanation": "Cash in bank: ₱2,000,000 + 90 day time deposit: 400,000 = Total cash and cash equivalents: ₱2,400,000. The 120 day treasury bill and 180 day commercial paper are excluded because their original maturity strictly measured from the date of acquisition exceeds the permissible maximum of three months." } },
  { "FAR-CashAndCashEq-012": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Cash Count Valuation", "type": "Problem Solving", "competency": "Apply", "question": "A cash count reveals: Coins and currency ₱22,000; Checks payable to company ₱15,000 containing a ₱5,000 postdated check; Stamps ₱1,000; IOUs from employees ₱4,000. Calculate the total cash on hand.", "solution": 320000, "explanation": "Coins and currency: ₱22,000 + Valid checks on hand: 10,000 = Total cash on hand: ₱32,000. The postdated check is excluded because it cannot be deposited or cashed until the specified future date. Stamps and IOUs are excluded because they represent office supplies and receivables, respectively." } },
  { "FAR-CashAndCashEq-013": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Checkbook Adjustments", "type": "Problem Solving", "competency": "Apply", "question": "The checkbook balance is ₱4,000,000. It includes: a check payable to a supplier for ₱200,000 drawn and recorded but not yet mailed; a check for ₱150,000 dated January 15 of next year drawn and recorded. Compute the adjusted cash in bank.", "solution": 4350000, "explanation": "Checkbook balance: ₱4,000,000 + Undelivered check: 200,000 + Postdated company check: 150,000 = Adjusted cash in bank: ₱4,350,000. The undelivered check is added back because the underlying payment requires physical delivery to the payee to be considered complete. The postdated check is added back because it is not negotiable by the supplier until the following year." } },
  { "FAR-CashAndCashEq-014": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Bank Overdrafts Offsetting", "type": "Problem Solving", "competency": "Analyze", "question": "A company has the following bank accounts: Cash in bank First Bank ₱1,500,000; Cash in bank Second Bank overdraft ₱200,000; Cash in bank Third Bank ₱800,000; Cash in bank Third Bank overdraft ₱100,000. What is the total reportable cash in bank?", "solution": 2200000, "explanation": "Cash in bank First Bank: ₱1,500,000 + Net cash in Third Bank: 700,000 = Total cash in bank: ₱2,200,000. The overdraft in Second Bank is treated as a liability because it cannot be offset against First Bank. The overdraft in Third Bank is offset against the positive balance in Third Bank because legal compensation and the right of setoff naturally exist between accounts in the same bank." } },
  { "FAR-CashAndCashEq-015": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Window Dressing Adjustments", "type": "Problem Solving", "competency": "Apply", "question": "The cash ledger shows ₱3,500,000. This includes January collections of ₱300,000 improperly recorded as December receipts. Also, a check of ₱100,000 in payment of accounts payable was recorded in December but actually mailed in January. Calculate the adjusted cash balance.", "solution": 3300000, "explanation": "Unadjusted cash balance: ₱3,500,000 - January collections recorded in December: 300,000 + Undelivered check: 100,000 = Adjusted cash balance: ₱3,300,000. January collections are deducted because they belong to the subsequent reporting period and artificially inflate the current cash balance. The undelivered check is added back because cash has not legally changed hands." } },
  { "FAR-CashAndCashEq-016": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Classification of Specific Funds", "type": "Problem Solving", "competency": "Analyze", "question": "The cash account balance of ₱5,000,000 includes: Plant expansion fund ₱1,000,000; Dividend fund ₱500,000; Payroll fund ₱300,000; Pension fund ₱400,000. Only the plant expansion fund is reserved for a noncurrent asset. Compute cash and cash equivalents.", "solution": 4000000, "explanation": "Total cash account: ₱5,000,000 - Plant expansion fund: 1,000,000 = Cash and cash equivalents: ₱4,000,000. Funds set aside for the payment of current operating liabilities like dividends and payroll remain classified as current cash. The plant expansion fund is excluded because it is earmarked for noncurrent asset acquisitions." } },
  { "FAR-CashAndCashEq-017": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Reconciliation to Adjusted Balance", "type": "Problem Solving", "competency": "Apply", "question": "The balance per ledger is ₱2,000,000. The bank service charge is ₱10,000. A note collected by the bank is ₱250,000. An NSF check amounts to ₱40,000. Outstanding checks are ₱300,000. What is the adjusted cash balance?", "solution": 2200000, "explanation": "Balance per ledger: ₱2,000,000 + Note collected by bank: 250,000 - Bank service charge: 10,000 - NSF check: 40,000 = Adjusted cash balance: ₱2,200,000. Outstanding checks are completely ignored in this calculation because they are reconciling items that adjust the bank statement balance, not the internal ledger balance." } },
  { "FAR-CashAndCashEq-018": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Foreign Currency Translation", "type": "Problem Solving", "competency": "Apply", "question": "An unadjusted cash balance of ₱4,000,000 includes a US Dollar account of 50,000 dollars originally recorded at ₱50 per dollar. The exchange rate on December 31 is ₱55 per dollar. What is the adjusted cash balance?", "solution": 4250000, "explanation": "Unadjusted cash balance: ₱4,000,000 + Foreign exchange gain on translation: 250,000 = Adjusted cash balance: ₱4,250,000. Foreign currency bank accounts are monetary assets that must be restated using the closing exchange rate at the reporting date, yielding an unrealized foreign exchange gain." } },
  { "FAR-CashAndCashEq-019": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Equity and Noncurrent Distractors", "type": "Problem Solving", "competency": "Analyze", "question": "The accounting records show: Cash in checking account ₱1,200,000; Cash in savings account ₱800,000; Treasury shares ₱300,000; Bond sinking fund ₱500,000. Compute total cash and cash equivalents.", "solution": 2000000, "explanation": "Cash in checking account: ₱1,200,000 + Cash in savings account: 800,000 = Total cash and cash equivalents: ₱2,000,000. Treasury shares are excluded because they are contra equity accounts representing repurchased stock. The bond sinking fund is excluded because it is restricted for the long term purpose of retiring bonds." } },
  { "FAR-CashAndCashEq-020": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Adjustments for Excluded Items", "type": "Problem Solving", "competency": "Apply", "question": "On December 31, a company unadjusted cash balance was ₱2,500,000. A review revealed the following inclusions: travel advances ₱50,000; an unreleased check payable to a supplier ₱200,000; and a customer check marked DAIF by the bank ₱150,000. What is the correct cash balance?", "solution": 2500000, "explanation": "Unadjusted cash balance: ₱2,500,000 - Travel advances: 50,000 + Undelivered check: 200,000 - Customer NSF check: 150,000 = Correct cash balance: ₱2,500,000. Travel advances are excluded because they are receivables owed by employees. The undelivered check is added back because physical transmission is required for payment consummation. The DAIF check is deducted because the cash collection failed and must be restored to receivables." } },
  { "FAR-CashAndCashEq-021": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Cash on Hand Components", "type": "Problem Solving", "competency": "Analyze", "question": "An unadjusted cash count yielded ₱500,000. This includes: coins and bills ₱150,000; manager check ₱50,000; traveler check ₱40,000; customer postdated check ₱60,000; customer NSF check ₱30,000; unreplenished expense vouchers ₱20,000; employee IOUs ₱10,000; and an unreleased company check payable to a supplier for ₱140,000. Calculate the correct cash on hand.", "solution": 520000, "explanation": "Unadjusted cash balance: ₱500,000 - Customer postdated check: 60,000 - Customer NSF check: 30,000 - Unreplenished expense vouchers: 20,000 - Employee IOUs: 10,000 + Unreleased company check: 140,000 = Correct cash balance: ₱520,000. Customer postdated checks and NSF checks are invalid for cash and revert to receivables. Vouchers and IOUs represent expenses and advances. The unreleased company check is added back because the payment is not consummated until the instrument is physically delivered to the payee." } },
  { "FAR-CashAndCashEq-022": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Bank Overdrafts and Restrictions", "type": "Problem Solving", "competency": "Analyze", "question": "A firm holds the following accounts: Bank A checking ₱1,000,000; Bank A savings ₱500,000; Bank B time deposit ₱400,000; Bank B overdraft ₱200,000; Bank C checking legally restricted for a noncurrent loan ₱300,000; Bank D checking ₱800,000; Bank D overdraft ₱150,000. Compute the total cash and cash equivalents.", "solution": 2350000, "explanation": "Bank A checking: ₱1,000,000 + Bank A savings: 500,000 + Bank B time deposit: 400,000 - Bank B overdraft: 200,000 + Bank D checking: 800,000 - Bank D overdraft: 150,000 = Total cash and cash equivalents: ₱2,350,000. Overdrafts in Bank B and Bank D are offset against the positive balances in those exact same banks due to legal compensation rules. The checking account in Bank C is excluded because it is legally restricted to settle a noncurrent liability." } },
  { "FAR-CashAndCashEq-023": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Classification of Cash Equivalents", "type": "Problem Solving", "competency": "Analyze", "question": "Evaluate these investments for cash equivalent classification: One year Treasury bill purchased two months before maturity ₱1,000,000; Six month Time deposit purchased three months before maturity ₱800,000; Ninety day Commercial paper purchased forty five days before maturity ₱600,000; One hundred twenty day Treasury bill purchased one hundred days before maturity ₱500,000.", "solution": 2400000, "explanation": "One year Treasury bill purchased two months before maturity: ₱1,000,000 + Six month Time deposit purchased three months before maturity: 800,000 + Ninety day Commercial paper: 600,000 = Total cash equivalents: ₱2,400,000. The one hundred twenty day treasury bill is excluded because it was acquired more than three months before its maturity date. The standard explicitly states that classification depends solely on the three month rule evaluated from the date of acquisition, regardless of the original life of the instrument." } },
  { "FAR-CashAndCashEq-024": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Compensating Balances", "type": "Problem Solving", "competency": "Analyze", "question": "An unadjusted bank balance of ₱5,000,000 includes a legally restricted compensating balance for a short term loan of ₱500,000, a legally restricted compensating balance for a long term loan of ₱800,000, and an unrestricted compensating balance for a short term loan of ₱400,000. Calculate the correct cash in bank.", "solution": 3700000, "explanation": "Unadjusted bank balance: ₱5,000,000 - Legally restricted balance for short term loan: 500,000 - Legally restricted balance for long term loan: 800,000 = Correct cash in bank: ₱3,700,000. Legally restricted compensating balances are entirely excluded from cash regardless of the term of the related loan because they are blocked from operational use. The unrestricted compensating balance remains fully part of cash because no legal agreement prevents its withdrawal." } },
  { "FAR-CashAndCashEq-025": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Window Dressing Adjustments", "type": "Problem Solving", "competency": "Analyze", "question": "The cash book was held open until January five. The unadjusted December balance is ₱4,500,000. January cash receipts of ₱600,000 were recorded as December receipts. January cash disbursements of ₱400,000 were recorded as December disbursements. Additionally, unreleased checks actually drawn in December amount to ₱300,000. Compute the adjusted cash balance.", "solution": 4600000, "explanation": "Unadjusted cash balance: ₱4,500,000 - January receipts recorded in December: 600,000 + January disbursements recorded in December: 400,000 + Unreleased checks drawn in December: 300,000 = Adjusted cash balance: ₱4,600,000. Receipts and disbursements occurring after the reporting period must be reversed to properly reflect the true cutoff date. Unreleased checks are added back because cash is not legally reduced until the check is physically delivered to the payee." } },
  { "FAR-CashAndCashEq-026": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Foreign Currency Translation", "type": "Problem Solving", "competency": "Apply", "question": "A company holds a US Dollar account of 100,000 dollars at a historical rate of ₱50 per dollar, and a Euro account of 50,000 euros at a historical rate of ₱60 per euro. The current exchange rates on December 31 are ₱56 per dollar and ₱62 per euro. Calculate the adjusted total cash balance in Philippine Pesos.", "solution": 8700000, "explanation": "US Dollar account at current rate: ₱5,600,000 + Euro account at current rate: 3,100,000 = Adjusted cash balance: ₱8,700,000. Foreign currency bank accounts are monetary assets that must be restated using the closing exchange rate prevailing at the reporting date." } },
  { "FAR-CashAndCashEq-027": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Petty Cash Fund", "type": "Problem Solving", "competency": "Analyze", "question": "An imprest petty cash fund was established at ₱50,000. A year end count reveals: Coins and bills ₱12,000; Paid expense vouchers ₱30,000; Employee IOUs ₱5,000; and a check drawn to replenish the fund ₱2,000. What is the amount of the petty cash shortage?", "solution": 1000, "explanation": "Imprest petty cash fund amount: ₱50,000 - Coins and bills: 12,000 - Paid expense vouchers: 30,000 - Employee IOUs: 5,000 - Replenishment check: 2,000 = Petty cash shortage: ₱1,000. The shortage is computed by deducting the total sum of all valid physical items and documents found during the cash count from the legally established imprest accountability." } },
  { "FAR-CashAndCashEq-028": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Classification of Specific Funds", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the cash to be reported for current operations given these funds: Payroll fund ₱400,000; Interest fund ₱200,000; Dividend fund ₱300,000; Tax fund ₱100,000; and a Sinking fund for bonds maturing in five years ₱1,000,000.", "solution": 1000000, "explanation": "Payroll fund: ₱400,000 + Interest fund: 200,000 + Dividend fund: 300,000 + Tax fund: 100,000 = Total cash for current operations: ₱1,000,000. Funds set aside specifically for the payment of current operating liabilities are included in cash. The sinking fund is strictly excluded because it is earmarked for the settlement of a noncurrent liability." } },
  { "FAR-CashAndCashEq-029": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Adjusted Bank Balance", "type": "Problem Solving", "competency": "Analyze", "question": "The unadjusted ledger balance is ₱3,620,000. A bank reconciliation reveals a note collected by the bank of ₱300,000, a bank service charge of ₱20,000, and a book error where a company payment was erroneously overstated by ₱100,000. Calculate the adjusted cash balance.", "solution": 4000000, "explanation": "Unadjusted ledger balance: ₱3,620,000 + Note collected by bank: 300,000 - Bank service charge: 20,000 + Book error overstating disbursement: 100,000 = Adjusted cash balance: ₱4,000,000. Valid adjustments to the internal book balance include bank credits not yet recorded, bank debits not yet recorded, and the correction of internal company errors. Overstating a payment means too much was deducted initially, so the excess must be added back." } },
  { "FAR-CashAndCashEq-030": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Bank Overdrafts Offsetting", "type": "Problem Solving", "competency": "Analyze", "question": "A company holds accounts across multiple institutions: Bank A checking ₱1,200,000; Bank A overdraft ₱300,000; Bank B checking ₱500,000; Bank C overdraft ₱150,000; Bank D legally restricted account ₱400,000. What is the total reportable cash in bank?", "solution": 1400000, "explanation": "Bank A checking: ₱1,200,000 - Bank A overdraft: 300,000 + Bank B checking: 500,000 = Total cash in bank: ₱1,400,000. The overdraft in Bank A is legally offset against the positive balance because they reside in the same financial institution. The overdraft in Bank C cannot be offset and is reported as a separate current liability, while the legally restricted account in Bank D is excluded from cash." } },
  { "FAR-CashAndCashEq-031": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Checkbook Adjustments", "type": "Problem Solving", "competency": "Analyze", "question": "An unadjusted cash balance is ₱2,500,000. Included as deductions are: an undelivered check ₱200,000; a postdated check drawn ₱150,000; a check held at payee request ₱100,000; and a check lost in the mail ₱50,000. Compute the adjusted cash balance.", "solution": 2950000, "explanation": "Unadjusted cash balance: ₱2,500,000 + Undelivered check: 200,000 + Postdated check drawn: 150,000 + Check held at payee request: 100,000 = Adjusted cash balance: ₱2,950,000. Undelivered checks, postdated checks drawn, and checks deliberately held from encashment do not constitute valid completed payments at year end and must be restored to the cash ledger. The check lost in the mail was successfully released and remains an outstanding check rather than a book adjustment." } },
  { "FAR-CashAndCashEq-032": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Petty Cash Fund", "type": "Problem Solving", "competency": "Analyze", "question": "Determine total cash and cash equivalents: Cash in bank ₱1,500,000; Money market placement ₱500,000; Petty cash fund ledger balance ₱30,000 consisting of ₱10,000 coins and bills, ₱15,000 unreplenished vouchers, and ₱5,000 employee IOUs.", "solution": 2010000, "explanation": "Cash in bank: ₱1,500,000 + Money market placement: 500,000 + Petty cash coins and bills: 10,000 = Total cash and cash equivalents: ₱2,010,000. Only the actual physical currency and bills found in the petty cash box are classified as cash. The unreplenished vouchers and employee IOUs must be reclassified to their respective expense and receivable accounts." } },
  { "FAR-CashAndCashEq-033": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Short Term Investments", "type": "Problem Solving", "competency": "Analyze", "question": "Select the valid cash equivalents: Ninety day Treasury bill ₱800,000; Sixty day Time deposit ₱500,000; Ordinary equity shares intended for trading ₱300,000; Redeemable preference shares purchased two months before mandatory redemption ₱400,000. Calculate total cash equivalents.", "solution": 1700000, "explanation": "Ninety day Treasury bill: ₱800,000 + Sixty day Time deposit: 500,000 + Redeemable preference shares: 400,000 = Total cash equivalents: ₱1,700,000. Redeemable preference shares containing a mandatory redemption date acquired within three months of that date act like debt instruments and qualify as cash equivalents. Ordinary equity shares are completely excluded because they represent permanent ownership." } },
  { "FAR-CashAndCashEq-034": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Restricted Funds", "type": "Problem Solving", "competency": "Analyze", "question": "Identify total cash given the following accounts: General checking ₱2,000,000; Payroll bank account ₱600,000; VAT bank account ₱400,000; Escrow account for a legal dispute ₱500,000; Cash frozen in a closed bank ₱200,000.", "solution": 3000000, "explanation": "General checking account: ₱2,000,000 + Payroll bank account: 600,000 + VAT bank account: 400,000 = Total cash and cash equivalents: ₱3,000,000. Accounts strictly designated for the payment of current operating liabilities like payroll and taxes remain classified as cash. The escrow account is excluded due to legal contingencies, and cash in a closed bank is reclassified as a receivable." } },
  { "FAR-CashAndCashEq-035": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Cash Count Valuation", "type": "Problem Solving", "competency": "Analyze", "question": "A cash count totaling ₱150,000 includes: ₱50,000 coins and bills; a ₱40,000 manager check; a ₱30,000 customer postdated check; a ₱20,000 customer NSF check; and a ₱10,000 stale customer check. Determine the correct cash on hand.", "solution": 90000, "explanation": "Coins and bills: ₱50,000 + Manager check: 40,000 = Correct cash on hand: ₱90,000. The postdated check, NSF check, and stale check are excluded because they are practically uncashable instruments at the reporting date and must be formally reverted to accounts receivable." } },
  { "FAR-CashAndCashEq-036": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Classification of Cash Equivalents", "type": "Problem Solving", "competency": "Analyze", "question": "A company holds four treasury bills. Bill A was purchased two months before maturity for ₱500,000. Bill B was purchased three months before maturity for ₱400,000. Bill C is a standard ninety day bill for ₱300,000. Bill D was purchased five months before maturity for ₱200,000. Calculate cash equivalents.", "solution": 1200000, "explanation": "Treasury bill purchased two months before maturity: ₱500,000 + Treasury bill purchased three months before maturity: 400,000 + Ninety day treasury bill: 300,000 = Total cash equivalents: ₱1,200,000. The primary criterion is strictly the date of acquisition, meaning any instrument acquired three months or less before its maturity uniquely qualifies. The treasury bill purchased five months before maturity fails this test and is booked as a short term investment." } },
  { "FAR-CashAndCashEq-037": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Short Term Investments", "type": "Problem Solving", "competency": "Analyze", "question": "An unadjusted cash balance of ₱6,000,000 includes a ₱1,000,000 time deposit originally placed for one year but now maturing in two months, and a ₱500,000 legally restricted compensating balance. Calculate the correct cash and cash equivalents.", "solution": 4500000, "explanation": "Unadjusted cash balance: ₱6,000,000 - Time deposit maturing in two months: 1,000,000 - Restricted compensating balance: 500,000 = Correct cash and cash equivalents: ₱4,500,000. The time deposit is completely excluded because its original term established at the date of acquisition was one year, prohibiting it from becoming a cash equivalent merely because its remaining term is now short. The restricted compensating balance is likewise excluded." } },
  { "FAR-CashAndCashEq-038": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Bank Overdrafts Offsetting", "type": "Problem Solving", "competency": "Analyze", "question": "Evaluate these accounts: Checking account A ₱800,000; Checking account B in a different bank overdraft ₱100,000; Savings account A ₱300,000; Savings account B in a different bank ₱150,000; Payroll account A ₱400,000. Compute total cash in bank.", "solution": 1650000, "explanation": "Checking account A: ₱800,000 + Savings account A: 300,000 + Savings account B: 150,000 + Payroll account A: 400,000 = Total cash in bank: ₱1,650,000. The overdraft in Bank B strictly cannot be offset against any of the positive accounts in Bank A because the legal right of compensation does not exist between completely separate and independent financial institutions." } },
  { "FAR-CashAndCashEq-039": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Adjusted Bank Balance", "type": "Problem Solving", "competency": "Analyze", "question": "The unadjusted ledger balance is ₱2,800,000. The bank reconciliation shows outstanding checks of ₱400,000 which includes a certified check of ₱50,000. The bank collected a note of ₱110,000. A book error recorded a ₱100,000 collection as ₱10,000. Calculate the adjusted cash balance.", "solution": 3000000, "explanation": "Unadjusted ledger balance: ₱2,800,000 + Note collected by bank: 110,000 + Book error understating collection: 90,000 = Adjusted cash balance: ₱3,000,000. The certified check is an adjusting item for the bank statement balance, not the ledger, and is uniquely excluded from normal outstanding checks because the bank deducts it immediately upon certification. The internal book error understated the collection by ninety thousand, requiring an addition." } },
  { "FAR-CashAndCashEq-040": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Comprehensive Cash Adjustments", "type": "Problem Solving", "competency": "Analyze", "question": "Compute cash and cash equivalents: Cash on hand ₱200,000 including a ₱50,000 postdated check; Cash in Bank A ₱1,000,000 including an unrestricted compensating balance of ₱150,000; Cash in Bank B ₱500,000 including a legally restricted compensating balance of ₱200,000; Sixty day treasury bill ₱800,000; One hundred twenty day treasury bill ₱400,000.", "solution": 2250000, "explanation": "Cash on hand excluding postdated check: ₱150,000 + Cash in bank A: 1,000,000 + Cash in bank B excluding restricted balance: 300,000 + Sixty day treasury bill: 800,000 = Total cash and cash equivalents: ₱2,250,000. The unrestricted compensating balance remains in cash, while the legally restricted balance is removed. The postdated check is reclassified as a receivable, and the one hundred twenty day treasury bill fails the acquisition maturity test." } },
  { "FAR-CashAndCashEq-041": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Comprehensive Cash Equivalents", "type": "Problem Solving", "competency": "Analyze", "question": "The trial balance shows: Bank One checking ₱2,500,000; Bank One overdraft ₱300,000; Bank Two checking ₱1,200,000; Bank Two overdraft ₱1,500,000; Ninety day money market placement ₱800,000; One hundred twenty day treasury bill purchased sixty days before maturity ₱500,000; Sinking fund for bond retirement ₱1,000,000. Compute total cash and cash equivalents.", "solution": 4700000, "explanation": "Bank One checking: ₱2,500,000 - Bank One overdraft: 300,000 + Bank Two checking: 1,200,000 + Ninety day money market placement: 800,000 + Treasury bill purchased sixty days before maturity: 500,000 = Total cash and cash equivalents: ₱4,700,000. The overdraft in Bank One is offset because it is in the same bank. The Bank Two overdraft cannot offset the positive checking account in Bank One and is reported as a current liability. The treasury bill is a cash equivalent because it was purchased within three months of its exact maturity date. The sinking fund is strictly excluded as it is a noncurrent asset designated for long term debt." } },
  { "FAR-CashAndCashEq-042": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Petty Cash Imprest System", "type": "Problem Solving", "competency": "Analyze", "question": "A petty cash fund is established at ₱50,000. A surprise count reveals: Currency ₱5,000; Replenishment check drawn to custodian ₱15,000; Accommodated customer check ₱4,000; Postdated employee check ₱6,000; Unreplenished paid vouchers ₱18,000; Counterfeit bill ₱1,000. What is the correct petty cash balance to be reported?", "solution": 240000, "explanation": "Currency and coins: ₱5,000 + Replenishment check: 15,000 + Accommodated customer check: 4,000 = Correct petty cash fund: ₱24,000. The accommodated customer check is valid cash as it is an instrument ready for immediate deposit. The postdated employee check is a receivable. Paid vouchers are unrecorded expenses. The counterfeit bill is worthless and represents a cash shortage." } },
  { "FAR-CashAndCashEq-043": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Window Dressing Receipts", "type": "Problem Solving", "competency": "Analyze", "question": "The cash book was held open until January four. The unadjusted December cash balance is ₱6,200,000. January cash collections of ₱800,000 were recorded as December receipts. Included in the December collections is a customer check of ₱150,000 dated January ten. Calculate the adjusted cash balance.", "solution": 5250000, "explanation": "Unadjusted cash balance: ₱6,200,000 - January collections recorded in December: 800,000 - Postdated customer check: 150,000 = Adjusted cash balance: ₱5,250,000. Keeping the cash book open artificially inflates cash so the subsequent period collections must be reversed. The postdated customer check received in December is not valid cash until its date arrives and must be reverted to accounts receivable." } },
  { "FAR-CashAndCashEq-044": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Window Dressing Disbursements", "type": "Problem Solving", "competency": "Analyze", "question": "The cash ledger balance is ₱4,800,000. January cash disbursements of ₱500,000 were recorded as December payments to improve the current ratio. Furthermore, unreleased checks physically drawn and recorded in December amount to ₱350,000. Compute the adjusted cash balance.", "solution": 5650000, "explanation": "Unadjusted cash balance: ₱4,800,000 + January disbursements recorded in December: 500,000 + Unreleased checks drawn in December: 350,000 = Adjusted cash balance: ₱5,650,000. Payments made in January but recorded in December must be added back to correct the early cutoff. Unreleased checks are also added back because cash is not legally transferred until the instrument is physically delivered to the payee." } },
  { "FAR-CashAndCashEq-045": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Foreign Currency Translation", "type": "Problem Solving", "competency": "Analyze", "question": "An unadjusted cash balance of ₱8,000,000 includes a US Dollar account of one hundred thousand dollars recorded at a historical rate of ₱52 per dollar, and a restricted foreign escrow account of ₱1,000,000. The exchange rate on December 31 is ₱56 per dollar. What is the adjusted cash balance?", "solution": 7400000, "explanation": "Unadjusted cash balance: ₱8,000,000 + Foreign exchange gain on translation: 400,000 - Restricted foreign escrow account: 1,000,000 = Adjusted cash balance: ₱7,400,000. The US dollar account is a monetary asset that must be restated at the closing rate yielding a four hundred thousand peso unrealized gain. The escrow account is deducted because it is restricted and unavailable for current operations." } },
  { "FAR-CashAndCashEq-046": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Compensating Balances and Credit Lines", "type": "Problem Solving", "competency": "Analyze", "question": "Bank balance is ₱9,500,000. This includes a legally restricted compensating balance of ₱1,500,000 against a short term loan, an informal compensating balance of ₱500,000 against a long term loan, and a legally restricted balance of ₱1,000,000 maintained for an unused credit line. Compute the correct cash in bank.", "solution": 7000000, "explanation": "Unadjusted bank balance: ₱9,500,000 - Restricted compensating balance for short term loan: 1,500,000 - Restricted compensating balance for unused credit line: 1,000,000 = Correct cash in bank: ₱7,000,000. Legally restricted balances are excluded regardless of whether they relate to short term loans long term loans or unused credit facilities. Informal balances remain part of cash because they lack binding legal restrictions." } },
  { "FAR-CashAndCashEq-047": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Bank Reconciliation Adjustments", "type": "Problem Solving", "competency": "Analyze", "question": "The ledger balance is ₱5,400,000. Reconciling items include: Bank service charge ₱15,000; NSF check ₱85,000; Note collected by bank including interest ₱350,000; Outstanding checks ₱600,000 including a certified check of ₱100,000; and a book error where a ₱40,000 payment was recorded as ₱4,000. Calculate the adjusted cash balance.", "solution": 5614000, "explanation": "Ledger balance: ₱5,400,000 - Bank service charge: 15,000 - NSF check: 85,000 + Note collected by bank: 350,000 - Book error understating payment: 36,000 = Adjusted cash balance: ₱5,614,000. Outstanding checks and certified checks affect the bank statement balance not the book balance. The book error understated the disbursement by thirty six thousand so this amount must be further deducted from the ledger." } },
  { "FAR-CashAndCashEq-048": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Specific Fund Classifications", "type": "Problem Solving", "competency": "Analyze", "question": "A company lists the following funds: General payroll fund ₱800,000; Travel advance fund ₱150,000; Dividend payment fund ₱600,000; Sinking fund ₱2,000,000; Tax fund ₱400,000; Preference share redemption fund ₱1,500,000. What amount is included in cash and cash equivalents?", "solution": 1800000, "explanation": "General payroll fund: ₱800,000 + Dividend payment fund: 600,000 + Tax fund: 400,000 = Total cash and cash equivalents: ₱1,800,000. Funds strictly for current operating liabilities are cash. Travel advances are receivables. Sinking funds and preference share redemption funds are noncurrent investments set aside for long term obligations." } },
  { "FAR-CashAndCashEq-049": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Short Term Investments and Equities", "type": "Problem Solving", "competency": "Analyze", "question": "Evaluate these items: Ninety day Commercial paper ₱1,200,000; One hundred eighty day Treasury bill bought ninety days before maturity ₱800,000; Equity trading securities ₱500,000; Redeemable preference shares acquired two months before mandatory redemption ₱700,000. Calculate total cash equivalents.", "solution": 2700000, "explanation": "Ninety day Commercial paper: ₱1,200,000 + Treasury bill bought ninety days before maturity: 800,000 + Redeemable preference shares: 700,000 = Total cash equivalents: ₱2,700,000. Equity trading securities are always excluded as they have no maturity date. Redeemable preference shares act like debt and qualify if acquired within three months of their fixed redemption date." } },
  { "FAR-CashAndCashEq-050": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Comprehensive Bank Accounts", "type": "Problem Solving", "competency": "Analyze", "question": "Determine reportable cash: Bank A current account ₱2,500,000; Bank A frozen account ₱300,000; Bank B savings ₱1,800,000; Bank B overdraft ₱400,000; Bank C current account ₱900,000; Bank C closed bank account ₱200,000. Calculate total cash and cash equivalents.", "solution": 4800000, "explanation": "Bank A current account: ₱2,500,000 + Bank B savings: 1,800,000 - Bank B overdraft: 400,000 + Bank C current account: 900,000 = Total cash and cash equivalents: ₱4,800,000. Bank B overdraft is properly offset against the savings account in the same bank. Frozen accounts and closed bank accounts are excluded from cash because the funds cannot be legally accessed and are reclassified as receivables." } },
  { "FAR-CashAndCashEq-051": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Postdated and Stale Checks", "type": "Problem Solving", "competency": "Analyze", "question": "A cash count shows ₱800,000. Inclusions: Customer postdated check ₱120,000; Company check postdated to a supplier ₱90,000; Customer check dated ten months ago ₱50,000; Certified customer check ₱150,000; Manager check ₱200,000. What is the correct cash on hand?", "solution": 630000, "explanation": "Unadjusted cash count: ₱800,000 - Customer postdated check: 120,000 - Customer check dated ten months ago: 50,000 = Correct cash on hand: ₱630,000. Customer postdated checks and stale checks over six months old are invalid for encashment and revert to receivables. The company postdated check drawn is not part of the physical count of cash on hand so it requires no adjustment here. Certified checks and manager checks are fully valid cash instruments." } },
  { "FAR-CashAndCashEq-052": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Investment Maturity Rules", "type": "Problem Solving", "competency": "Analyze", "question": "A company holds: Two year Treasury note purchased one month before maturity ₱1,500,000; Ninety day Time deposit placed forty five days ago ₱600,000; One hundred twenty day Commercial paper purchased today ₱400,000. Calculate total cash equivalents.", "solution": 2100000, "explanation": "Two year Treasury note purchased one month before maturity: ₱1,500,000 + Ninety day Time deposit: 600,000 = Total cash equivalents: ₱2,100,000. The long term treasury note qualifies because the sole test is the remaining maturity from the date of acquisition. The one hundred twenty day commercial paper is excluded because its maturity from the acquisition date exceeds three months." } },
  { "FAR-CashAndCashEq-053": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Petty Cash Accountability", "type": "Problem Solving", "competency": "Analyze", "question": "An imprest fund is ₱100,000. The count reveals: Bills ₱15,000; Coins ₱3,000; Check to replenish ₱30,000; Vouchers for transportation ₱18,000; Vouchers for supplies ₱25,000; Employee advances ₱12,000. Calculate the cash shortage or overage.", "solution": 3000, "explanation": "Total physical items and documents: ₱103,000 - Imprest petty cash fund amount: 100,000 = Petty cash overage: ₱3,000. By summing all the valid accountability items including coins bills the replenishment check expense vouchers and employee advances the total exceeds the established fund balance indicating an overage." } },
  { "FAR-CashAndCashEq-054": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Bank Error Adjustments", "type": "Problem Solving", "competency": "Analyze", "question": "The unadjusted book balance is ₱4,200,000. The bank erroneously credited the company account for ₱300,000 belonging to another client. The bank erroneously charged the company ₱150,000 for a check drawn by a different firm. A company check for ₱50,000 was recorded in the books as ₱500,000. Calculate the adjusted book balance.", "solution": 4650000, "explanation": "Unadjusted book balance: ₱4,200,000 + Book error overstating disbursement: 450,000 = Adjusted book balance: ₱4,650,000. Bank errors affect the bank statement balance during reconciliation but do not require adjustments to the internal company ledger. The book error originally deducted too much cash so the excess difference of four hundred fifty thousand must be added back." } },
  { "FAR-CashAndCashEq-055": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Multiple Currency Translation", "type": "Problem Solving", "competency": "Analyze", "question": "A ledger shows ₱10,000,000. This includes a Yen account of two million yen booked at ₱0.40 per yen. Current rate is ₱0.45 per yen. It also includes a legally restricted Pound account of fifty thousand pounds booked at ₱60 per pound. Current rate is ₱65 per pound. Calculate adjusted cash and cash equivalents.", "solution": 7100000, "explanation": "Unadjusted ledger balance: ₱10,000,000 + Yen account foreign exchange gain: 100,000 - Restricted Pound account original book value: 3,000,000 = Adjusted cash and cash equivalents: ₱7,100,000. The Yen account is translated at the closing rate resulting in a gain. The Pound account is completely deducted because its legal restriction disqualifies it from being reported as cash regardless of its current exchange valuation." } },
  { "FAR-CashAndCashEq-056": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Mixed Checks and Drafts", "type": "Problem Solving", "competency": "Analyze", "question": "Compute cash on hand: Cash count ₱1,200,000. Includes: Bank draft ₱150,000; Postal money order ₱50,000; Customer check returned due to insufficient funds ₱80,000; Unreleased check drawn to pay taxes ₱200,000; Postdated check received from a client ₱120,000.", "solution": 1000000, "explanation": "Unadjusted cash count: ₱1,200,000 - Customer NSF check: 80,000 - Postdated check received: 120,000 = Correct cash on hand: ₱1,000,000. Bank drafts and postal money orders are valid cash items. NSF checks and postdated checks received are excluded and reverted to receivables. The unreleased check drawn is an internal book adjustment and does not affect the physical count of cash on hand." } },
  { "FAR-CashAndCashEq-057": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Window Dressing Complete Reversal", "type": "Problem Solving", "competency": "Analyze", "question": "The December cash balance is ₱5,500,000. It was discovered that the cash receipts journal was kept open until January 8 including ₱1,200,000 of January collections. The cash disbursements journal was kept open until January 5 including ₱900,000 of January payments. Calculate the true December 31 cash balance.", "solution": 5200000, "explanation": "Unadjusted cash balance: ₱5,500,000 - January collections recorded in December: 1,200,000 + January payments recorded in December: 900,000 = True December cash balance: ₱5,200,000. To establish the correct financial position at year end all transactions that actually occurred in the subsequent period must be fully reversed regardless of when they were recorded." } },
  { "FAR-CashAndCashEq-058": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Compensating Balance on Unused Credit", "type": "Problem Solving", "competency": "Analyze", "question": "A company holds ₱8,000,000 in a checking account. The bank requires a ten percent compensating balance against a ₱5,000,000 outstanding loan and a five percent compensating balance against a ₱10,000,000 unused line of credit. Both are legally restricted. What is the reportable cash in bank?", "solution": 7000000, "explanation": "Total checking account: ₱8,000,000 - Restricted balance for outstanding loan: 500,000 - Restricted balance for unused credit line: 500,000 = Reportable cash in bank: ₱7,000,000. Any legally restricted compensating balance whether tied to an actively borrowed amount or merely an available credit facility must be excluded from cash and cash equivalents." } },
  { "FAR-CashAndCashEq-059": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Time Deposits and Placements", "type": "Problem Solving", "competency": "Analyze", "question": "Evaluate total cash equivalents: Sixty day Time deposit ₱1,500,000; One hundred twenty day Time deposit broken into two periods with thirty days remaining ₱800,000; Ninety day Money market placement ₱1,200,000; Callable preference shares ₱500,000.", "solution": 2700000, "explanation": "Sixty day Time deposit: ₱1,500,000 + Ninety day Money market placement: 1,200,000 = Total cash equivalents: ₱2,700,000. The one hundred twenty day time deposit is excluded because its original acquisition term was over three months. Callable preference shares are excluded because the issuer has the option to call them meaning the investor has no fixed guaranteed maturity date." } },
  { "FAR-CashAndCashEq-060": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Ultimate Comprehensive Adjustments", "type": "Problem Solving", "competency": "Analyze", "question": "Determine correct cash and cash equivalents: Unadjusted ledger ₱15,000,000. Includes: Bank A overdraft ₱500,000 offset against Bank B positive balance; Legally restricted balance ₱1,000,000; Sinking fund ₱2,500,000; Postdated check received ₱400,000; Unreleased check drawn ₱600,000; One hundred eighty day commercial paper purchased sixty days before maturity ₱800,000.", "solution": 12000000, "explanation": "Unadjusted ledger balance: ₱15,000,000 + Bank A overdraft wrongfully offset: 500,000 - Legally restricted balance: 1,000,000 - Sinking fund: 2,500,000 - Postdated check received: 400,000 + Unreleased check drawn: 600,000 - One hundred eighty day commercial paper: 200,000 = Correct cash and cash equivalents: ₱12,000,000. The Bank A overdraft must be added back to cash because it cannot be offset against Bank B. Restricted balances and sinking funds are excluded. Postdated checks received are receivables. Unreleased checks drawn are restored to cash. The commercial paper is already included in the unadjusted balance but must be excluded because it is an investment not a cash equivalent." } },
  
  { "FAR-StatementOfCashFlows-001": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company reported net income of ₱500,000 for the year. Additional information reveals: Depreciation expense ₱100,000; Gain on sale of equipment ₱50,000; Increase in accounts receivable ₱80,000; Decrease in inventory ₱40,000; Decrease in accounts payable ₱30,000. What amount should be reported as net cash provided by operating activities?", "solution": 480000, "explanation": "Net income: ₱500,000 + Depreciation: 100,000 - Gain on sale of equipment: 50,000 - Increase in accounts receivable: 80,000 + Decrease in inventory: 40,000 - Decrease in accounts payable: 30,000 = Net cash provided by operating activities: ₱480,000. Depreciation is a noncash expense and is added back to net income. The gain on sale is deducted because the total cash received from the sale is an investing inflow. An increase in accounts receivable implies cash collected is less than sales revenue so it is deducted. A decrease in inventory implies cost of goods sold includes inventory purchased in prior periods so it is added back. A decrease in accounts payable implies cash paid to suppliers exceeds purchases so it is deducted." } },
  { "FAR-StatementOfCashFlows-002": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "For the current year, an entity reported Sales ₱3,000,000; Cost of goods sold ₱1,200,000; Operating expenses excluding depreciation ₱800,000; Depreciation ₱300,000; Loss on sale of land ₱100,000. During the year, accounts receivable increased by ₱150,000, inventory increased by ₱200,000, and accounts payable increased by ₱250,000. Calculate the net cash provided by operating activities.", "solution": 900000, "explanation": "First compute net income. Sales: ₱3,000,000 - Cost of goods sold: 1,200,000 - Operating expenses: 800,000 - Depreciation: 300,000 - Loss on sale of land: 100,000 = Net income: ₱600,000. Next adjust net income to cash basis. Net income: ₱600,000 + Depreciation: 300,000 + Loss on sale of land: 100,000 - Increase in accounts receivable: 150,000 - Increase in inventory: 200,000 + Increase in accounts payable: 250,000 = Net cash provided by operating activities: ₱900,000. The loss on sale is added back because the sale proceeds are reported under investing activities. Increases in current operating assets are deducted while increases in current operating liabilities are added to reconcile accrual income to cash flows." } },
  { "FAR-StatementOfCashFlows-003": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported net income of ₱800,000. Adjustments included: Amortization of patent ₱50,000; Increase in prepaid expenses ₱20,000; Increase in accounts payable ₱70,000; Decrease in accounts receivable ₱110,000; Equity in earnings of associate ₱40,000. What is the net cash provided by operating activities?", "solution": 970000, "explanation": "Net income: ₱800,000 + Amortization of patent: 50,000 - Increase in prepaid expenses: 20,000 + Increase in accounts payable: 70,000 + Decrease in accounts receivable: 110,000 - Equity in earnings of associate: 40,000 = Net cash provided by operating activities: ₱970,000. Patent amortization is a noncash expense added back to net income. The equity in earnings of an associate represents investment income recognized without corresponding cash receipt so it is deducted to find the cash basis operating income." } },
  { "FAR-StatementOfCashFlows-004": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company provided the following data: Net income ₱1,200,000; Depreciation ₱250,000; Amortization of bond discount ₱30,000; Increase in accounts receivable ₱100,000; Decrease in inventory ₱80,000; Decrease in accounts payable ₱60,000; Cash dividends paid ₱150,000. Compute the net cash provided by operating activities.", "solution": 1400000, "explanation": "Net income: ₱1,200,000 + Depreciation: 250,000 + Amortization of bond discount: 30,000 - Increase in accounts receivable: 100,000 + Decrease in inventory: 80,000 - Decrease in accounts payable: 60,000 = Net cash provided by operating activities: ₱1,400,000. Amortization of bond discount is a noncash addition to interest expense and must be added back to net income. Cash dividends paid are classified as financing activities and are strictly ignored in the computation of operating cash flows." } },
  { "FAR-StatementOfCashFlows-005": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Financial records show: Net income ₱650,000; Depreciation ₱150,000; Gain on sale of machinery ₱40,000; Decrease in prepaid rent ₱15,000; Decrease in accrued wages ₱25,000; Purchase of treasury shares ₱100,000. What is the net cash flow from operations?", "solution": 750000, "explanation": "Net income: ₱650,000 + Depreciation: 150,000 - Gain on sale of machinery: 40,000 + Decrease in prepaid rent: 15,000 - Decrease in accrued wages: 25,000 = Net cash provided by operating activities: ₱750,000. A decrease in prepaid rent indicates that the rent expense recognized was greater than the cash paid so it is added back. A decrease in accrued wages means cash paid to employees exceeded the recognized expense so it is deducted. The purchase of treasury shares is a financing outflow and is ignored here." } },
  { "FAR-StatementOfCashFlows-006": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported Sales ₱4,000,000; Cost of goods sold ₱2,000,000; Depreciation ₱400,000; Other operating expenses ₱900,000; Income tax expense ₱200,000. During the year, accounts receivable decreased by ₱300,000, inventory increased by ₱150,000, and accounts payable decreased by ₱100,000. Compute the net cash provided by operating activities.", "solution": 950000, "explanation": "First compute net income. Sales: ₱4,000,000 - Cost of goods sold: 2,000,000 - Depreciation: 400,000 - Other operating expenses: 900,000 - Income tax expense: 200,000 = Net income: ₱500,000. Next adjust net income to cash basis. Net income: ₱500,000 + Depreciation: 400,000 + Decrease in accounts receivable: 300,000 - Increase in inventory: 150,000 - Decrease in accounts payable: 100,000 = Net cash provided by operating activities: ₱950,000. The decrease in accounts receivable is added to net income because the cash collections exceeded the sales revenue generated during the period." } },
  { "FAR-StatementOfCashFlows-007": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for the year: Net income ₱900,000; Depreciation ₱200,000; Loss on early retirement of bonds ₱80,000; Increase in inventory ₱120,000; Decrease in accounts payable ₱50,000; Increase in unearned revenue ₱40,000. Determine the net cash flow from operating activities.", "solution": 1050000, "explanation": "Net income: ₱900,000 + Depreciation: 200,000 + Loss on early retirement of bonds: 80,000 - Increase in inventory: 120,000 - Decrease in accounts payable: 50,000 + Increase in unearned revenue: 40,000 = Net cash provided by operating activities: ₱1,050,000. The loss on early retirement of bonds is a non-operating loss that reduced net income without a corresponding operating cash outflow so it is added back. An increase in unearned revenue means the company received cash in advance of earning it so it is added to net income." } },
  { "FAR-StatementOfCashFlows-008": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Financial information reveals: Net income ₱1,500,000; Depreciation ₱350,000; Gain on sale of land ₱150,000; Decrease in accounts receivable ₱80,000; Increase in prepaid expenses ₱30,000; Decrease in accrued liabilities ₱20,000; Bank loan received ₱500,000. What is the net cash provided by operations?", "solution": 1730000, "explanation": "Net income: ₱1,500,000 + Depreciation: 350,000 - Gain on sale of land: 150,000 + Decrease in accounts receivable: 80,000 - Increase in prepaid expenses: 30,000 - Decrease in accrued liabilities: 20,000 = Net cash provided by operating activities: ₱1,730,000. The gain on sale of land is deducted to remove its non-operating effect from net income. The bank loan received is a financing inflow and has no effect on operating cash flows." } },
  { "FAR-StatementOfCashFlows-009": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A corporation reported a net loss of ₱100,000. Adjustments include: Depreciation ₱250,000; Amortization of franchise ₱60,000; Decrease in inventory ₱90,000; Increase in accounts payable ₱110,000. Calculate the net cash flow from operating activities.", "solution": 410000, "explanation": "Net loss: ₱-100,000 + Depreciation: 250,000 + Amortization of franchise: 60,000 + Decrease in inventory: 90,000 + Increase in accounts payable: 110,000 = Net cash provided by operating activities: ₱410,000. Despite reporting a net loss the entity generated positive operating cash flow because the noncash expenses and favorable working capital changes exceeded the reported accrual loss." } },
  { "FAR-StatementOfCashFlows-010": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data available: Net income ₱750,000; Depreciation ₱120,000; Equity in earnings of associate ₱80,000; Dividends received from associate ₱50,000; Decrease in accounts receivable ₱40,000. Determine the net cash provided by operating activities.", "solution": 880000, "explanation": "Net income: ₱750,000 + Depreciation: 120,000 - Equity in earnings of associate: 80,000 + Dividends received from associate: 50,000 + Decrease in accounts receivable: 40,000 = Net cash provided by operating activities: ₱880,000. The equity in earnings is a noncash revenue that must be deducted. The dividends received represent actual cash inflows from the investment and are added to operations under the indirect method according to standard practice." } },
  { "FAR-StatementOfCashFlows-011": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported Net income ₱2,200,000; Depreciation ₱450,000; Amortization of bond premium ₱40,000; Increase in deferred tax liability ₱70,000; Increase in accounts receivable ₱180,000; Increase in accounts payable ₱90,000. Compute the net cash provided by operating activities.", "solution": 2590000, "explanation": "Net income: ₱2,200,000 + Depreciation: 450,000 - Amortization of bond premium: 40,000 + Increase in deferred tax liability: 70,000 - Increase in accounts receivable: 180,000 + Increase in accounts payable: 90,000 = Net cash provided by operating activities: ₱2,590,000. Amortization of bond premium reduces interest expense without cash outflow so it is deducted. An increase in deferred tax liability means tax expense exceeded tax paid so the noncash portion is added back." } },
  { "FAR-StatementOfCashFlows-012": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "The income statement shows Gross profit ₱1,800,000; Operating expenses including depreciation of ₱200,000 amount to ₱800,000; Gain on sale of equipment ₱50,000; Income tax expense ₱300,000. Working capital changes: Increase in accounts receivable ₱90,000; Decrease in inventory ₱110,000; Decrease in accounts payable ₱70,000. What is the operating cash flow?", "solution": 850000, "explanation": "First compute net income. Gross profit: ₱1,800,000 - Operating expenses: 800,000 + Gain on sale of equipment: 50,000 - Income tax expense: 300,000 = Net income: ₱750,000. Next adjust net income to cash basis. Net income: ₱750,000 + Depreciation: 200,000 - Gain on sale of equipment: 50,000 - Increase in accounts receivable: 90,000 + Decrease in inventory: 110,000 - Decrease in accounts payable: 70,000 = Net cash provided by operating activities: ₱850,000." } },
  { "FAR-StatementOfCashFlows-013": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm reported Net income ₱1,100,000; Depreciation ₱280,000; Loss on sale of investments ₱40,000; Increase in trading securities ₱150,000; Decrease in accounts payable ₱60,000. Compute the net cash provided by operations.", "solution": 1210000, "explanation": "Net income: ₱1,100,000 + Depreciation: 280,000 + Loss on sale of investments: 40,000 - Increase in trading securities: 150,000 - Decrease in accounts payable: 60,000 = Net cash provided by operating activities: ₱1,210,000. The loss on sale is a non-operating item added back. The increase in trading securities represents cash paid to acquire assets specifically held for short term profit generation so it is treated as an operating cash outflow." } },
  { "FAR-StatementOfCashFlows-014": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity presented Net income ₱1,350,000; Depreciation ₱310,000; Increase in provision for warranties ₱90,000; Decrease in accounts receivable ₱120,000; Increase in inventory ₱200,000. Determine the net cash flow from operating activities.", "solution": 1670000, "explanation": "Net income: ₱1,350,000 + Depreciation: 310,000 + Increase in provision for warranties: 90,000 + Decrease in accounts receivable: 120,000 - Increase in inventory: 200,000 = Net cash provided by operating activities: ₱1,670,000. An increase in the provision for warranties means the estimated warranty expense recognized in net income was greater than the actual cash paid for warranty claims during the year so the difference is added back." } },
  { "FAR-StatementOfCashFlows-015": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "For the current year: Net income ₱850,000; Depreciation ₱190,000; Amortization of software ₱30,000; Gain on expropriation of asset ₱120,000; Decrease in prepaid expenses ₱40,000; Decrease in unearned rent ₱50,000. Calculate operating cash flow.", "solution": 940000, "explanation": "Net income: ₱850,000 + Depreciation: 190,000 + Amortization of software: 30,000 - Gain on expropriation of asset: 120,000 + Decrease in prepaid expenses: 40,000 - Decrease in unearned rent: 50,000 = Net cash provided by operating activities: ₱940,000. The gain on expropriation is removed because it pertains to an investing activity. A decrease in unearned rent implies that revenue was recognized without a corresponding cash receipt in the current period so it is deducted." } },
  { "FAR-StatementOfCashFlows-016": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Company records show: Net income ₱1,600,000; Depreciation ₱400,000; Decrease in deferred tax asset ₱60,000; Increase in accounts receivable ₱220,000; Decrease in accounts payable ₱130,000; Gain on sale of equipment ₱70,000. What is the net cash from operations?", "solution": 1640000, "explanation": "Net income: ₱1,600,000 + Depreciation: 400,000 + Decrease in deferred tax asset: 60,000 - Increase in accounts receivable: 220,000 - Decrease in accounts payable: 130,000 - Gain on sale of equipment: 70,000 = Net cash provided by operating activities: ₱1,640,000. A decrease in a deferred tax asset means the company recognized tax expense that did not require a current cash outflow so it is added back to reconcile to cash basis." } },
  { "FAR-StatementOfCashFlows-017": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm reported Net income ₱950,000; Depreciation ₱210,000; Loss on sale of machinery ₱55,000; Increase in accounts receivable ₱140,000; Increase in inventory ₱90,000; Increase in accounts payable ₱110,000; Decrease in accrued expenses ₱30,000. Compute the operating cash flow.", "solution": 1065000, "explanation": "Net income: ₱950,000 + Depreciation: 210,000 + Loss on sale of machinery: 55,000 - Increase in accounts receivable: 140,000 - Increase in inventory: 90,000 + Increase in accounts payable: 110,000 - Decrease in accrued expenses: 30,000 = Net cash provided by operating activities: ₱1,065,000. The noncash loss is added back. Current operating asset increases drain cash and are deducted while current operating liability increases preserve cash and are added." } },
  { "FAR-StatementOfCashFlows-018": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "The income statement indicates Sales ₱5,000,000; Cost of goods sold ₱2,500,000; Salaries expense ₱1,000,000; Depreciation ₱500,000; Amortization ₱100,000; Gain on sale of investment ₱200,000. Changes in working capital are: Decrease in accounts receivable ₱400,000; Increase in inventory ₱250,000; Increase in accounts payable ₱150,000. Determine the net cash flow from operations.", "solution": 1800000, "explanation": "First compute net income. Sales: ₱5,000,000 - Cost of goods sold: 2,500,000 - Salaries expense: 1,000,000 - Depreciation: 500,000 - Amortization: 100,000 + Gain on sale of investment: 200,000 = Net income: ₱1,100,000. Next adjust net income to cash basis. Net income: ₱1,100,000 + Depreciation: 500,000 + Amortization: 100,000 - Gain on sale of investment: 200,000 + Decrease in accounts receivable: 400,000 - Increase in inventory: 250,000 + Increase in accounts payable: 150,000 = Net cash provided by operating activities: ₱1,800,000." } },
  { "FAR-StatementOfCashFlows-019": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity provided the following: Net income ₱1,050,000; Depreciation ₱270,000; Amortization of bond discount ₱25,000; Share based compensation expense ₱45,000; Decrease in accounts receivable ₱130,000; Increase in inventory ₱160,000. Calculate net cash from operating activities.", "solution": 1360000, "explanation": "Net income: ₱1,050,000 + Depreciation: 270,000 + Amortization of bond discount: 25,000 + Share based compensation expense: 45,000 + Decrease in accounts receivable: 130,000 - Increase in inventory: 160,000 = Net cash provided by operating activities: ₱1,360,000. Share based compensation expense is recognized in the income statement but settled in equity instruments rather than cash so it is added back as a noncash adjustment." } },
  { "FAR-StatementOfCashFlows-020": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Company records reveal: Net income ₱1,450,000; Depreciation ₱320,000; Unrealized gain on trading securities ₱60,000; Decrease in accounts receivable ₱90,000; Increase in accounts payable ₱110,000. What is the operating cash flow?", "solution": 1910000, "explanation": "Net income: ₱1,450,000 + Depreciation: 320,000 - Unrealized gain on trading securities: 60,000 + Decrease in accounts receivable: 90,000 + Increase in accounts payable: 110,000 = Net cash provided by operating activities: ₱1,910,000. The unrealized gain on trading securities increases net income but does not generate actual cash until the securities are sold so it is deducted." } },
  { "FAR-StatementOfCashFlows-021": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm reported Net income ₱1,750,000; Depreciation ₱380,000; Impairment loss on goodwill ₱120,000; Increase in prepaid expenses ₱50,000; Decrease in accrued salaries ₱40,000. Determine the net cash flow from operations.", "solution": 2160000, "explanation": "Net income: ₱1,750,000 + Depreciation: 380,000 + Impairment loss on goodwill: 120,000 - Increase in prepaid expenses: 50,000 - Decrease in accrued salaries: 40,000 = Net cash provided by operating activities: ₱2,160,000. An impairment loss is a noncash charge recognizing a decline in asset value and is added back to reconcile net income to net cash flow." } },
  { "FAR-StatementOfCashFlows-022": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "During the year an entity suffered a Net loss of ₱200,000. Adjustments include: Depreciation ₱400,000; Loss on sale of building ₱150,000; Decrease in accounts receivable ₱180,000; Decrease in inventory ₱120,000; Increase in accounts payable ₱90,000. Calculate operating cash flow.", "solution": 740000, "explanation": "Net loss: ₱-200,000 + Depreciation: 400,000 + Loss on sale of building: 150,000 + Decrease in accounts receivable: 180,000 + Decrease in inventory: 120,000 + Increase in accounts payable: 90,000 = Net cash provided by operating activities: ₱740,000. By adding back significant noncash charges and favorable working capital liquidations the entity generated a strong positive cash flow despite the accounting loss." } },
  { "FAR-StatementOfCashFlows-023": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity presented: Net income ₱1,850,000; Depreciation ₱420,000; Gain on debt restructuring ₱130,000; Increase in accounts receivable ₱240,000; Decrease in accounts payable ₱160,000; Increase in accrued interest payable ₱70,000. Compute the operating cash flow.", "solution": 1810000, "explanation": "Net income: ₱1,850,000 + Depreciation: 420,000 - Gain on debt restructuring: 130,000 - Increase in accounts receivable: 240,000 - Decrease in accounts payable: 160,000 + Increase in accrued interest payable: 70,000 = Net cash provided by operating activities: ₱1,810,000. The gain on debt restructuring is a noncash gain or financing related gain that must be deducted. The increase in accrued interest payable implies interest expense exceeded cash paid for interest so it is added back." } },
  { "FAR-StatementOfCashFlows-024": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for the period: Net income ₱2,500,000; Depreciation ₱600,000; Amortization of patent ₱80,000; Amortization of bond premium ₱50,000; Decrease in inventory ₱270,000; Decrease in accounts payable ₱190,000; Increase in prepaid rent ₱60,000. Calculate net cash provided by operations.", "solution": 3150000, "explanation": "Net income: ₱2,500,000 + Depreciation: 600,000 + Amortization of patent: 80,000 - Amortization of bond premium: 50,000 + Decrease in inventory: 270,000 - Decrease in accounts payable: 190,000 - Increase in prepaid rent: 60,000 = Net cash provided by operating activities: ₱3,150,000. Bond premium amortization artificially reduces interest expense without transferring cash so it is deducted from net income." } },
  { "FAR-StatementOfCashFlows-025": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company provided this information: Net income ₱3,000,000; Depreciation ₱750,000; Loss on sale of equipment ₱110,000; Gain on sale of land ₱240,000; Increase in accounts receivable ₱320,000; Decrease in inventory ₱180,000; Decrease in accounts payable ₱140,000. What amount should be reported as net cash provided by operating activities?", "solution": 3340000, "explanation": "Net income: ₱3,000,000 + Depreciation: 750,000 + Loss on sale of equipment: 110,000 - Gain on sale of land: 240,000 - Increase in accounts receivable: 320,000 + Decrease in inventory: 180,000 - Decrease in accounts payable: 140,000 = Net cash provided by operating activities: ₱3,340,000. All investing gains and losses must be reversed out of net income to isolate cash flows specifically generated from core operations." } },
  { "FAR-StatementOfCashFlows-026": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported Sales ₱5,000,000; Cost of goods sold ₱2,000,000; Operating expenses ₱1,000,000 including depreciation of ₱200,000. During the year, accounts receivable increased by ₱300,000, inventory increased by ₱150,000, accounts payable increased by ₱100,000, and accrued expenses decreased by ₱50,000. Using the direct method, what is the net cash provided by operating activities?", "solution": 1800000, "explanation": "Sales: ₱5,000,000 - Increase in accounts receivable: 300,000 = Cash received from customers: ₱4,700,000. Cost of goods sold: ₱2,000,000 + Increase in inventory: 150,000 - Increase in accounts payable: 100,000 = Cash paid to suppliers: ₱2,050,000. Operating expenses: ₱1,000,000 - Depreciation: 200,000 + Decrease in accrued expenses: 50,000 = Cash paid for operating expenses: ₱850,000. Cash received from customers: ₱4,700,000 - Cash paid to suppliers: 2,050,000 - Cash paid for operating expenses: 850,000 = Net cash provided by operating activities: ₱1,800,000. An increase in accounts receivable means cash collected was less than sales revenue, requiring a deduction. An increase in inventory means purchases exceeded the cost of goods sold, requiring an addition, while an increase in accounts payable means cash paid was less than purchases, requiring a deduction. Depreciation is a noncash expense and is removed from operating expenses. A decrease in accrued expenses implies cash paid exceeded the recognized expense, requiring an addition." } },
  { "FAR-StatementOfCashFlows-027": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm's records show Sales ₱6,500,000; Cost of goods sold ₱3,500,000; Operating expenses ₱1,200,000 including depreciation ₱250,000 and amortization ₱50,000. Working capital changes include: Decrease in accounts receivable ₱200,000; Decrease in inventory ₱400,000; Decrease in accounts payable ₱150,000; Increase in prepaid expenses ₱100,000. Calculate net cash provided by operating activities using the direct method.", "solution": 2450000, "explanation": "Sales: ₱6,500,000 + Decrease in accounts receivable: 200,000 = Cash received from customers: ₱6,700,000. Cost of goods sold: ₱3,500,000 - Decrease in inventory: 400,000 + Decrease in accounts payable: 150,000 = Cash paid to suppliers: ₱3,250,000. Operating expenses: ₱1,200,000 - Depreciation: 250,000 - Amortization: 50,000 + Increase in prepaid expenses: 100,000 = Cash paid for operating expenses: ₱1,000,000. Cash received from customers: ₱6,700,000 - Cash paid to suppliers: 3,250,000 - Cash paid for operating expenses: 1,000,000 = Net cash provided by operating activities: ₱2,450,000. A decrease in accounts receivable means cash collections exceeded sales revenue. A decrease in inventory implies goods sold were drawn from existing stock, reducing required cash purchases. A decrease in accounts payable means payments to suppliers exceeded new credit purchases. An increase in prepaid expenses means cash was paid for future expenses, increasing operating cash outflows." } },
  { "FAR-StatementOfCashFlows-028": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Company data: Sales ₱4,800,000; Cost of goods sold ₱2,400,000; Operating expenses ₱800,000 excluding depreciation; Interest expense ₱120,000; Income tax expense ₱250,000. Account changes: Increase in accounts receivable ₱100,000; Increase in unearned revenue ₱80,000; Increase in inventory ₱200,000; Increase in accounts payable ₱300,000; Increase in accrued expenses ₱40,000; Decrease in interest payable ₱30,000; Increase in income tax payable ₱50,000. Determine net cash provided by operating activities.", "solution": 1370000, "explanation": "Sales: ₱4,800,000 - Increase in accounts receivable: 100,000 + Increase in unearned revenue: 80,000 = Cash received from customers: ₱4,780,000. Cost of goods sold: ₱2,400,000 + Increase in inventory: 200,000 - Increase in accounts payable: 300,000 = Cash paid to suppliers: ₱2,300,000. Operating expenses: ₱800,000 - Increase in accrued expenses: 40,000 = Cash paid for operating expenses: ₱760,000. Interest expense: ₱120,000 + Decrease in interest payable: 30,000 = Cash paid for interest: ₱150,000. Income tax expense: ₱250,000 - Increase in income tax payable: 50,000 = Cash paid for income taxes: ₱200,000. Cash received from customers: ₱4,780,000 - Cash paid to suppliers: 2,300,000 - Cash paid for operating expenses: 760,000 - Cash paid for interest: 150,000 - Cash paid for income taxes: 200,000 = Net cash provided by operating activities: ₱1,370,000. An increase in unearned revenue is added because cash was collected in advance. A decrease in interest payable means cash paid was greater than the interest expense for the period. An increase in tax payable means tax expense was recognized but not yet paid." } },
  { "FAR-StatementOfCashFlows-029": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Reported figures: Sales ₱7,000,000; Cost of goods sold ₱3,000,000; Operating expenses ₱1,500,000 including depreciation of ₱300,000 and bad debt expense of ₱100,000. Changes: Increase in accounts receivable ₱500,000; Decrease in inventory ₱200,000; Decrease in accounts payable ₱300,000; Increase in prepaid expenses ₱50,000. Calculate operating cash flow under the direct method.", "solution": 2250000, "explanation": "Sales: ₱7,000,000 - Increase in accounts receivable: 500,000 = Cash received from customers: ₱6,500,000. Cost of goods sold: ₱3,000,000 - Decrease in inventory: 200,000 + Decrease in accounts payable: 300,000 = Cash paid to suppliers: ₱3,100,000. Operating expenses: ₱1,500,000 - Depreciation: 300,000 - Bad debt expense: 100,000 + Increase in prepaid expenses: 50,000 = Cash paid for operating expenses: ₱1,150,000. Cash received from customers: ₱6,500,000 - Cash paid to suppliers: 3,100,000 - Cash paid for operating expenses: 1,150,000 = Net cash provided by operating activities: ₱2,250,000. Bad debt expense is a noncash charge included in operating expenses and must be excluded. When adjusting accounts receivable, gross sales and gross receivables are typically used under the direct method to bypass the noncash effect of bad debts." } },
  { "FAR-StatementOfCashFlows-030": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity provides the following: Sales ₱5,500,000; Cost of goods sold ₱2,800,000; Operating expenses ₱1,200,000 including depreciation ₱250,000. Working capital shifts: Decrease in accounts receivable ₱250,000; Increase in inventory ₱150,000; Decrease in accounts payable ₱100,000; Decrease in prepaid expenses ₱40,000; Decrease in accrued expenses ₱70,000. Compute the net cash provided by operations.", "solution": 1720000, "explanation": "Sales: ₱5,500,000 + Decrease in accounts receivable: 250,000 = Cash received from customers: ₱5,750,000. Cost of goods sold: ₱2,800,000 + Increase in inventory: 150,000 + Decrease in accounts payable: 100,000 = Cash paid to suppliers: ₱3,050,000. Operating expenses: ₱1,200,000 - Depreciation: 250,000 - Decrease in prepaid expenses: 40,000 + Decrease in accrued expenses: 70,000 = Cash paid for operating expenses: ₱980,000. Cash received from customers: ₱5,750,000 - Cash paid to suppliers: 3,050,000 - Cash paid for operating expenses: 980,000 = Net cash provided by operating activities: ₱1,720,000. A decrease in prepaid expenses means a past cash outflow is now being expensed, requiring a deduction. A decrease in accrued expenses means a liability was settled, requiring an addition to cash expenses." } },
  { "FAR-StatementOfCashFlows-031": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Income statement data: Sales ₱9,200,000; Cost of goods sold ₱4,500,000; Operating expenses ₱2,000,000 including depreciation ₱500,000; Interest expense ₱300,000 including amortization of bond premium ₱20,000; Income tax expense ₱600,000. Changes: Increase in accounts receivable ₱600,000; Decrease in inventory ₱300,000; Increase in accounts payable ₱400,000; Increase in accrued expenses ₱150,000; Decrease in income tax payable ₱80,000. Calculate operating cash flow using the direct method.", "solution": 2450000, "explanation": "Sales: ₱9,200,000 - Increase in accounts receivable: 600,000 = Cash received from customers: ₱8,600,000. Cost of goods sold: ₱4,500,000 - Decrease in inventory: 300,000 - Increase in accounts payable: 400,000 = Cash paid to suppliers: ₱3,800,000. Operating expenses: ₱2,000,000 - Depreciation: 500,000 - Increase in accrued expenses: 150,000 = Cash paid for operating expenses: ₱1,350,000. Interest expense: ₱300,000 + Amortization of bond premium: 20,000 = Cash paid for interest: ₱320,000. Income tax expense: ₱600,000 + Decrease in income tax payable: 80,000 = Cash paid for income taxes: ₱680,000. Cash received from customers: ₱8,600,000 - Cash paid to suppliers: 3,800,000 - Cash paid for operating expenses: 1,350,000 - Cash paid for interest: 320,000 - Cash paid for income taxes: 680,000 = Net cash provided by operating activities: ₱2,450,000. Amortization of bond premium is a noncash reduction of interest expense, so the actual cash paid to bondholders is higher than the recorded expense and must be added back." } },
  { "FAR-StatementOfCashFlows-032": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Given the following details: Sales ₱3,800,000; Cost of goods sold ₱1,900,000; Operating expenses excluding depreciation ₱700,000. Balances changed as follows: Accounts receivable decreased by ₱150,000; Unearned revenue increased by ₱50,000; Inventory increased by ₱100,000; Accounts payable decreased by ₱80,000; Prepaid expenses decreased by ₱30,000. What is the net cash provided by operations?", "solution": 1250000, "explanation": "Sales: ₱3,800,000 + Decrease in accounts receivable: 150,000 + Increase in unearned revenue: 50,000 = Cash received from customers: ₱4,000,000. Cost of goods sold: ₱1,900,000 + Increase in inventory: 100,000 + Decrease in accounts payable: 80,000 = Cash paid to suppliers: ₱2,080,000. Operating expenses: ₱700,000 - Decrease in prepaid expenses: 30,000 = Cash paid for operating expenses: ₱670,000. Cash received from customers: ₱4,000,000 - Cash paid to suppliers: 2,080,000 - Cash paid for operating expenses: 670,000 = Net cash provided by operating activities: ₱1,250,000. Increases in unearned revenue represent cash collected that has not yet been recognized as sales, requiring an addition to sales to compute total collections." } },
  { "FAR-StatementOfCashFlows-033": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported: Sales ₱4,500,000; Cost of goods sold ₱2,100,000; Operating expenses ₱950,000 including depreciation ₱150,000. Related balance sheet changes: Accounts receivable increased by ₱250,000; Inventory decreased by ₱150,000; Accounts payable increased by ₱100,000; Accrued expenses increased by ₱50,000. Using the direct method, calculate operating cash flow.", "solution": 1650000, "explanation": "Sales: ₱4,500,000 - Increase in accounts receivable: 250,000 = Cash received from customers: ₱4,250,000. Cost of goods sold: ₱2,100,000 - Decrease in inventory: 150,000 - Increase in accounts payable: 100,000 = Cash paid to suppliers: ₱1,850,000. Operating expenses: ₱950,000 - Depreciation: 150,000 - Increase in accrued expenses: 50,000 = Cash paid for operating expenses: ₱750,000. Cash received from customers: ₱4,250,000 - Cash paid to suppliers: 1,850,000 - Cash paid for operating expenses: 750,000 = Net cash provided by operating activities: ₱1,650,000. The direct method cleanly maps each income statement line to its corresponding cash flow by stripping away noncash accruals and related working capital changes." } },
  { "FAR-StatementOfCashFlows-034": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net operating cash flow: Sales ₱6,000,000; Cost of goods sold ₱3,200,000; Operating expenses ₱1,400,000 including depreciation ₱200,000 and bad debts ₱50,000. Accounts receivable decreased by ₱300,000; Unearned revenue increased by ₱100,000; Inventory increased by ₱250,000; Accounts payable decreased by ₱150,000; Prepaid expenses decreased by ₱40,000.", "solution": 1690000, "explanation": "Sales: ₱6,000,000 + Decrease in accounts receivable: 300,000 + Increase in unearned revenue: 100,000 = Cash received from customers: ₱6,400,000. Cost of goods sold: ₱3,200,000 + Increase in inventory: 250,000 + Decrease in accounts payable: 150,000 = Cash paid to suppliers: ₱3,600,000. Operating expenses: ₱1,400,000 - Depreciation: 200,000 - Bad debt expense: 50,000 - Decrease in prepaid expenses: 40,000 = Cash paid for operating expenses: ₱1,110,000. Cash received from customers: ₱6,400,000 - Cash paid to suppliers: 3,600,000 - Cash paid for operating expenses: 1,110,000 = Net cash provided by operating activities: ₱1,690,000. Noncash expenses like depreciation and bad debts are purged from total operating expenses to isolate the exact cash paid." } },
  { "FAR-StatementOfCashFlows-035": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company provided this data: Sales ₱7,500,000; Cost of goods sold ₱4,000,000; Operating expenses ₱1,800,000 including depreciation ₱300,000; Interest expense ₱200,000. The following changes occurred: Accounts receivable increased ₱400,000; Inventory increased ₱300,000; Accounts payable increased ₱250,000; Accrued expenses decreased ₱80,000; Interest payable increased ₱20,000. Calculate net cash from operations.", "solution": 1290000, "explanation": "Sales: ₱7,500,000 - Increase in accounts receivable: 400,000 = Cash received from customers: ₱7,100,000. Cost of goods sold: ₱4,000,000 + Increase in inventory: 300,000 - Increase in accounts payable: 250,000 = Cash paid to suppliers: ₱4,050,000. Operating expenses: ₱1,800,000 - Depreciation: 300,000 + Decrease in accrued expenses: 80,000 = Cash paid for operating expenses: ₱1,580,000. Interest expense: ₱200,000 - Increase in interest payable: 20,000 = Cash paid for interest: ₱180,000. Cash received from customers: ₱7,100,000 - Cash paid to suppliers: 4,050,000 - Cash paid for operating expenses: 1,580,000 - Cash paid for interest: 180,000 = Net cash provided by operating activities: ₱1,290,000. An increase in interest payable means a portion of the interest expense recognized was not paid in cash during the period, requiring a deduction." } },
  { "FAR-StatementOfCashFlows-036": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Financial results show: Sales ₱5,200,000; Cost of goods sold ₱2,600,000; Operating expenses ₱1,100,000 including depreciation ₱180,000; Income tax expense ₱350,000. Account changes: Accounts receivable decreased ₱180,000; Inventory decreased ₱120,000; Accounts payable decreased ₱90,000; Prepaid expenses increased ₱70,000; Income tax payable decreased ₱40,000. What is the net operating cash flow?", "solution": 1430000, "explanation": "Sales: ₱5,200,000 + Decrease in accounts receivable: 180,000 = Cash received from customers: ₱5,380,000. Cost of goods sold: ₱2,600,000 - Decrease in inventory: 120,000 + Decrease in accounts payable: 90,000 = Cash paid to suppliers: ₱2,570,000. Operating expenses: ₱1,100,000 - Depreciation: 180,000 + Increase in prepaid expenses: 70,000 = Cash paid for operating expenses: ₱990,000. Income tax expense: ₱350,000 + Decrease in income tax payable: 40,000 = Cash paid for income taxes: ₱390,000. Cash received from customers: ₱5,380,000 - Cash paid to suppliers: 2,570,000 - Cash paid for operating expenses: 990,000 - Cash paid for income taxes: 390,000 = Net cash provided by operating activities: ₱1,430,000. A decrease in income tax payable indicates that cash payments to tax authorities exceeded the recognized tax expense for the period." } },
  { "FAR-StatementOfCashFlows-037": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "The records present: Sales ₱8,800,000; Cost of goods sold ₱4,800,000; Operating expenses ₱2,200,000 including depreciation ₱400,000 and amortization ₱100,000. Working capital adjustments: Accounts receivable increased ₱500,000; Unearned revenue decreased ₱100,000; Inventory increased ₱400,000; Accounts payable decreased ₱200,000. Compute the direct method operating cash flow.", "solution": 1100000, "explanation": "Sales: ₱8,800,000 - Increase in accounts receivable: 500,000 - Decrease in unearned revenue: 100,000 = Cash received from customers: ₱8,200,000. Cost of goods sold: ₱4,800,000 + Increase in inventory: 400,000 + Decrease in accounts payable: 200,000 = Cash paid to suppliers: ₱5,400,000. Operating expenses: ₱2,200,000 - Depreciation: 400,000 - Amortization: 100,000 = Cash paid for operating expenses: ₱1,700,000. Cash received from customers: ₱8,200,000 - Cash paid to suppliers: 5,400,000 - Cash paid for operating expenses: 1,700,000 = Net cash provided by operating activities: ₱1,100,000. A decrease in unearned revenue signifies that previously collected cash was recognized as revenue in the current period, so it is deducted to prevent overstating current cash inflows." } },
  { "FAR-StatementOfCashFlows-038": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity shows: Sales ₱3,500,000; Cost of goods sold ₱1,700,000; Operating expenses ₱800,000 including depreciation ₱100,000; Interest expense ₱150,000 including bond discount amortization of ₱15,000. Changes: Accounts receivable decreased ₱150,000; Inventory decreased ₱200,000; Accounts payable increased ₱150,000; Accrued expenses increased ₱40,000. Calculate operating cash flow.", "solution": 1505000, "explanation": "Sales: ₱3,500,000 + Decrease in accounts receivable: 150,000 = Cash received from customers: ₱3,650,000. Cost of goods sold: ₱1,700,000 - Decrease in inventory: 200,000 - Increase in accounts payable: 150,000 = Cash paid to suppliers: ₱1,350,000. Operating expenses: ₱800,000 - Depreciation: 100,000 - Increase in accrued expenses: 40,000 = Cash paid for operating expenses: ₱660,000. Interest expense: ₱150,000 - Amortization of bond discount: 15,000 = Cash paid for interest: ₱135,000. Cash received from customers: ₱3,650,000 - Cash paid to suppliers: 1,350,000 - Cash paid for operating expenses: 660,000 - Cash paid for interest: 135,000 = Net cash provided by operating activities: ₱1,505,000. Amortization of a bond discount increases interest expense beyond the actual cash interest payment, necessitating a deduction to pinpoint the true cash outflow." } },
  { "FAR-StatementOfCashFlows-039": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data includes: Sales ₱9,500,000; Cost of goods sold ₱5,000,000; Operating expenses ₱2,400,000 including depreciation ₱350,000 and loss on sale of equipment ₱50,000. Balance sheet items changed: Accounts receivable increased ₱700,000; Inventory increased ₱500,000; Accounts payable increased ₱300,000; Prepaid expenses decreased ₱60,000. What is the net cash from operations?", "solution": 1660000, "explanation": "Sales: ₱9,500,000 - Increase in accounts receivable: 700,000 = Cash received from customers: ₱8,800,000. Cost of goods sold: ₱5,000,000 + Increase in inventory: 500,000 - Increase in accounts payable: 300,000 = Cash paid to suppliers: ₱5,200,000. Operating expenses: ₱2,400,000 - Depreciation: 350,000 - Loss on sale of equipment: 50,000 - Decrease in prepaid expenses: 60,000 = Cash paid for operating expenses: ₱1,940,000. Cash received from customers: ₱8,800,000 - Cash paid to suppliers: 5,200,000 - Cash paid for operating expenses: 1,940,000 = Net cash provided by operating activities: ₱1,660,000. The loss on sale is stripped from operating expenses because the total cash proceeds from the sale are properly reported as a cash inflow from investing activities." } },
  { "FAR-StatementOfCashFlows-040": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported: Sales ₱4,200,000; Cost of goods sold ₱2,000,000; Operating expenses ₱900,000 including depreciation ₱120,000; Income tax expense ₱280,000. Working capital shifts: Accounts receivable decreased ₱220,000; Inventory decreased ₱180,000; Accounts payable decreased ₱120,000; Accrued expenses decreased ₱30,000; Deferred tax liability increased ₱40,000. Compute the operating cash flow.", "solution": 1430000, "explanation": "Sales: ₱4,200,000 + Decrease in accounts receivable: 220,000 = Cash received from customers: ₱4,420,000. Cost of goods sold: ₱2,000,000 - Decrease in inventory: 180,000 + Decrease in accounts payable: 120,000 = Cash paid to suppliers: ₱1,940,000. Operating expenses: ₱900,000 - Depreciation: 120,000 + Decrease in accrued expenses: 30,000 = Cash paid for operating expenses: ₱810,000. Income tax expense: ₱280,000 - Increase in deferred tax liability: 40,000 = Cash paid for income taxes: ₱240,000. Cash received from customers: ₱4,420,000 - Cash paid to suppliers: 1,940,000 - Cash paid for operating expenses: 810,000 - Cash paid for income taxes: 240,000 = Net cash provided by operating activities: ₱1,430,000. An increase in a deferred tax liability denotes that a portion of the current tax expense will be settled in future periods, meaning it did not require a current cash outlay." } },
  { "FAR-StatementOfCashFlows-041": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Financial results present: Sales ₱7,800,000; Cost of goods sold ₱3,900,000; Operating expenses ₱1,600,000 including depreciation ₱280,000. The following changed: Accounts receivable increased ₱350,000; Unearned revenue increased ₱150,000; Inventory increased ₱300,000; Accounts payable decreased ₱200,000; Prepaid expenses increased ₱90,000. Calculate operating cash flow using the direct method.", "solution": 1790000, "explanation": "Sales: ₱7,800,000 - Increase in accounts receivable: 350,000 + Increase in unearned revenue: 150,000 = Cash received from customers: ₱7,600,000. Cost of goods sold: ₱3,900,000 + Increase in inventory: 300,000 + Decrease in accounts payable: 200,000 = Cash paid to suppliers: ₱4,400,000. Operating expenses: ₱1,600,000 - Depreciation: 280,000 + Increase in prepaid expenses: 90,000 = Cash paid for operating expenses: ₱1,410,000. Cash received from customers: ₱7,600,000 - Cash paid to suppliers: 4,400,000 - Cash paid for operating expenses: 1,410,000 = Net cash provided by operating activities: ₱1,790,000. A decrease in accounts payable means that besides paying for current purchases, the company also utilized cash to pay down its existing debt to suppliers." } },
  { "FAR-StatementOfCashFlows-042": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Income statement metrics: Sales ₱6,400,000; Cost of goods sold ₱3,100,000; Operating expenses ₱1,300,000 including depreciation ₱220,000 and bad debt expense ₱60,000. The balances changed by: Accounts receivable decreased ₱280,000; Inventory decreased ₱240,000; Accounts payable increased ₱180,000; Accrued expenses increased ₱70,000. Determine the net operating cash flow.", "solution": 3050000, "explanation": "Sales: ₱6,400,000 + Decrease in accounts receivable: 280,000 = Cash received from customers: ₱6,680,000. Cost of goods sold: ₱3,100,000 - Decrease in inventory: 240,000 - Increase in accounts payable: 180,000 = Cash paid to suppliers: ₱2,680,000. Operating expenses: ₱1,300,000 - Depreciation: 220,000 - Bad debt expense: 60,000 - Increase in accrued expenses: 70,000 = Cash paid for operating expenses: ₱950,000. Cash received from customers: ₱6,680,000 - Cash paid to suppliers: 2,680,000 - Cash paid for operating expenses: 950,000 = Net cash provided by operating activities: ₱3,050,000. Both depreciation and bad debt expense are noncash components that must be strictly stripped out to compute the true cash disbursements for operations." } },
  { "FAR-StatementOfCashFlows-043": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm provides the following: Sales ₱5,600,000; Cost of goods sold ₱2,900,000; Operating expenses ₱1,050,000 including depreciation ₱190,000; Interest expense ₱180,000 including bond premium amortization ₱25,000. Account shifts: Accounts receivable increased ₱420,000; Inventory increased ₱160,000; Accounts payable decreased ₱140,000; Prepaid expenses decreased ₱50,000. What is the net cash provided by operations?", "solution": 965000, "explanation": "Sales: ₱5,600,000 - Increase in accounts receivable: 420,000 = Cash received from customers: ₱5,180,000. Cost of goods sold: ₱2,900,000 + Increase in inventory: 160,000 + Decrease in accounts payable: 140,000 = Cash paid to suppliers: ₱3,200,000. Operating expenses: ₱1,050,000 - Depreciation: 190,000 - Decrease in prepaid expenses: 50,000 = Cash paid for operating expenses: ₱810,000. Interest expense: ₱180,000 + Amortization of bond premium: 25,000 = Cash paid for interest: ₱205,000. Cash received from customers: ₱5,180,000 - Cash paid to suppliers: 3,200,000 - Cash paid for operating expenses: 810,000 - Cash paid for interest: 205,000 = Net cash provided by operating activities: ₱965,000. The amortization of a bond premium reduces the recognized interest expense, meaning the actual cash disbursed to bondholders is higher than the expense reported." } },
  { "FAR-StatementOfCashFlows-044": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity revealed: Sales ₱8,500,000; Cost of goods sold ₱4,200,000; Operating expenses ₱1,900,000 including depreciation ₱360,000. Balance adjustments: Accounts receivable decreased ₱340,000; Unearned revenue decreased ₱120,000; Inventory decreased ₱350,000; Accounts payable increased ₱280,000; Accrued expenses decreased ₱90,000. Calculate operating cash flow via the direct method.", "solution": 3520000, "explanation": "Sales: ₱8,500,000 + Decrease in accounts receivable: 340,000 - Decrease in unearned revenue: 120,000 = Cash received from customers: ₱8,720,000. Cost of goods sold: ₱4,200,000 - Decrease in inventory: 350,000 - Increase in accounts payable: 280,000 = Cash paid to suppliers: ₱3,570,000. Operating expenses: ₱1,900,000 - Depreciation: 360,000 + Decrease in accrued expenses: 90,000 = Cash paid for operating expenses: ₱1,630,000. Cash received from customers: ₱8,720,000 - Cash paid to suppliers: 3,570,000 - Cash paid for operating expenses: 1,630,000 = Net cash provided by operating activities: ₱3,520,000. A decrease in unearned revenue means that services were performed for cash collected in a prior period, thus the revenue recognized does not equate to a current cash inflow and must be deducted." } },
  { "FAR-StatementOfCashFlows-045": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Company records show: Sales ₱3,900,000; Cost of goods sold ₱1,850,000; Operating expenses ₱850,000 including depreciation ₱140,000 and patent amortization ₱40,000; Income tax expense ₱320,000. Adjustments are: Accounts receivable increased ₱180,000; Inventory increased ₱220,000; Accounts payable increased ₱140,000; Prepaid expenses increased ₱60,000; Income tax payable increased ₱50,000. Determine net cash flow from operations.", "solution": 790000, "explanation": "Sales: ₱3,900,000 - Increase in accounts receivable: 180,000 = Cash received from customers: ₱3,720,000. Cost of goods sold: ₱1,850,000 + Increase in inventory: 220,000 - Increase in accounts payable: 140,000 = Cash paid to suppliers: ₱1,930,000. Operating expenses: ₱850,000 - Depreciation: 140,000 - Amortization: 40,000 + Increase in prepaid expenses: 60,000 = Cash paid for operating expenses: ₱730,000. Income tax expense: ₱320,000 - Increase in income tax payable: 50,000 = Cash paid for income taxes: ₱270,000. Cash received from customers: ₱3,720,000 - Cash paid to suppliers: 1,930,000 - Cash paid for operating expenses: 730,000 - Cash paid for income taxes: 270,000 = Net cash provided by operating activities: ₱790,000. Patent amortization is excluded exactly like depreciation because it is a systematic noncash allocation of an intangible asset cost." } },
  { "FAR-StatementOfCashFlows-046": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "The income statement contains: Sales ₱7,200,000; Cost of goods sold ₱3,600,000; Operating expenses ₱1,500,000 including depreciation ₱270,000. Working capital changes: Accounts receivable decreased ₱450,000; Inventory decreased ₱280,000; Accounts payable decreased ₱210,000; Accrued expenses increased ₱110,000. Compute the operating cash flow.", "solution": 3000000, "explanation": "Sales: ₱7,200,000 + Decrease in accounts receivable: 450,000 = Cash received from customers: ₱7,650,000. Cost of goods sold: ₱3,600,000 - Decrease in inventory: 280,000 + Decrease in accounts payable: 210,000 = Cash paid to suppliers: ₱3,530,000. Operating expenses: ₱1,500,000 - Depreciation: 270,000 - Increase in accrued expenses: 110,000 = Cash paid for operating expenses: ₱1,120,000. Cash received from customers: ₱7,650,000 - Cash paid to suppliers: 3,530,000 - Cash paid for operating expenses: 1,120,000 = Net cash provided by operating activities: ₱3,000,000. Under the direct method, each element of working capital modifies its related income statement account to convert the accrual figure strictly into its pure cash equivalent." } },
  { "FAR-StatementOfCashFlows-047": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data includes: Sales ₱5,800,000; Cost of goods sold ₱2,750,000; Operating expenses ₱1,150,000 including depreciation ₱210,000 and loss on sale of land ₱40,000. Change in balances: Accounts receivable increased ₱320,000; Unearned revenue increased ₱90,000; Inventory increased ₱190,000; Accounts payable decreased ₱130,000; Prepaid expenses decreased ₱30,000. What is the net cash from operations?", "solution": 1630000, "explanation": "Sales: ₱5,800,000 - Increase in accounts receivable: 320,000 + Increase in unearned revenue: 90,000 = Cash received from customers: ₱5,570,000. Cost of goods sold: ₱2,750,000 + Increase in inventory: 190,000 + Decrease in accounts payable: 130,000 = Cash paid to suppliers: ₱3,070,000. Operating expenses: ₱1,150,000 - Depreciation: 210,000 - Loss on sale of land: 40,000 - Decrease in prepaid expenses: 30,000 = Cash paid for operating expenses: ₱870,000. Cash received from customers: ₱5,570,000 - Cash paid to suppliers: 3,070,000 - Cash paid for operating expenses: 870,000 = Net cash provided by operating activities: ₱1,630,000. The loss on sale of land is completely stripped from operating expenses because property sales generate cash flows properly classified within investing activities." } },
  { "FAR-StatementOfCashFlows-048": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported: Sales ₱9,000,000; Cost of goods sold ₱4,600,000; Operating expenses ₱2,100,000 including depreciation ₱380,000 and bad debt expense ₱70,000; Interest expense ₱250,000. Working capital shifts: Accounts receivable decreased ₱550,000; Inventory decreased ₱420,000; Accounts payable increased ₱340,000; Accrued expenses decreased ₱120,000; Interest payable decreased ₱40,000. Compute the operating cash flow.", "solution": 3650000, "explanation": "Sales: ₱9,000,000 + Decrease in accounts receivable: 550,000 = Cash received from customers: ₱9,550,000. Cost of goods sold: ₱4,600,000 - Decrease in inventory: 420,000 - Increase in accounts payable: 340,000 = Cash paid to suppliers: ₱3,840,000. Operating expenses: ₱2,100,000 - Depreciation: 380,000 - Bad debt expense: 70,000 + Decrease in accrued expenses: 120,000 = Cash paid for operating expenses: ₱1,770,000. Interest expense: ₱250,000 + Decrease in interest payable: 40,000 = Cash paid for interest: ₱290,000. Cash received from customers: ₱9,550,000 - Cash paid to suppliers: 3,840,000 - Cash paid for operating expenses: 1,770,000 - Cash paid for interest: 290,000 = Net cash provided by operating activities: ₱3,650,000. The decrease in interest payable means the company disbursed cash to settle previously accrued interest, demanding an addition to the current period interest expense." } },
  { "FAR-StatementOfCashFlows-049": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm provides the following: Sales ₱4,700,000; Cost of goods sold ₱2,300,000; Operating expenses ₱980,000 including depreciation ₱160,000; Income tax expense ₱310,000. Balance adjustments: Accounts receivable increased ₱210,000; Inventory increased ₱170,000; Accounts payable increased ₱160,000; Prepaid expenses increased ₱80,000; Deferred tax liability decreased ₱30,000. Calculate net cash provided by operations.", "solution": 940000, "explanation": "Sales: ₱4,700,000 - Increase in accounts receivable: 210,000 = Cash received from customers: ₱4,490,000. Cost of goods sold: ₱2,300,000 + Increase in inventory: 170,000 - Increase in accounts payable: 160,000 = Cash paid to suppliers: ₱2,310,000. Operating expenses: ₱980,000 - Depreciation: 160,000 + Increase in prepaid expenses: 80,000 = Cash paid for operating expenses: ₱900,000. Income tax expense: ₱310,000 + Decrease in deferred tax liability: 30,000 = Cash paid for income taxes: ₱340,000. Cash received from customers: ₱4,490,000 - Cash paid to suppliers: 2,310,000 - Cash paid for operating expenses: 900,000 - Cash paid for income taxes: 340,000 = Net cash provided by operating activities: ₱940,000. A decrease in a deferred tax liability denotes that previously deferred taxes were actively settled with cash during the year, requiring an addition to the current income tax expense." } },
  { "FAR-StatementOfCashFlows-050": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Company records reveal: Sales ₱8,200,000; Cost of goods sold ₱4,100,000; Operating expenses ₱1,750,000 including depreciation ₱310,000 and software amortization ₱60,000. Working capital changes: Accounts receivable decreased ₱380,000; Unearned revenue decreased ₱140,000; Inventory decreased ₱310,000; Accounts payable decreased ₱220,000; Accrued expenses increased ₱100,000. What is the operating cash flow using the direct method?", "solution": 3150000, "explanation": "Sales: ₱8,200,000 + Decrease in accounts receivable: 380,000 - Decrease in unearned revenue: 140,000 = Cash received from customers: ₱8,440,000. Cost of goods sold: ₱4,100,000 - Decrease in inventory: 310,000 + Decrease in accounts payable: 220,000 = Cash paid to suppliers: ₱4,010,000. Operating expenses: ₱1,750,000 - Depreciation: 310,000 - Amortization: 60,000 - Increase in accrued expenses: 100,000 = Cash paid for operating expenses: ₱1,280,000. Cash received from customers: ₱8,440,000 - Cash paid to suppliers: 4,010,000 - Cash paid for operating expenses: 1,280,000 = Net cash provided by operating activities: ₱3,150,000. Direct mapping requires careful tracking: decreasing receivables inflate cash collections; decreasing unearned revenue deflates collections; decreasing inventory reduces supplier payments; and decreasing payables inflates supplier payments." } },
  { "FAR-StatementOfCashFlows-051": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported the following transactions: Purchase of equipment for cash ₱1,200,000; Purchase of land by paying ₱500,000 cash and issuing a ₱1,000,000 note payable; Sale of equipment with a carrying amount of ₱400,000 at a loss of ₱50,000; Purchase of trading securities ₱200,000; Purchase of FVOCI equity securities ₱600,000. What amount should be reported as net cash used in investing activities?", "solution": 1950000, "explanation": "Cash paid for equipment: ₱1,200,000 + Cash paid for land: 500,000 + Cash paid for FVOCI securities: 600,000 - Cash proceeds from sale of equipment: 350,000 = Net cash used in investing activities: ₱1,950,000. The purchase of equipment, the cash down payment for land, and the purchase of non-trading securities are investing outflows. The noncash note issued for the land is excluded. Proceeds from the equipment sale computed as carrying amount minus loss is an investing inflow. The purchase of trading securities is an operating activity." } },
  { "FAR-StatementOfCashFlows-052": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "During the year, a company paid ₱2,500,000 to construct a new building, which included ₱100,000 of capitalized interest. The company also paid ₱300,000 for a new patent. An old building costing ₱2,000,000 with accumulated depreciation of ₱1,500,000 was sold at a gain of ₱200,000. The company collected ₱400,000 principal on a loan granted to an affiliate. Calculate the net cash used in investing activities.", "solution": 1700000, "explanation": "Cash paid for self-constructed building: ₱2,500,000 + Cash paid for patent: 300,000 - Cash proceeds from sale of building: 700,000 - Collection of loan principal: 400,000 = Net cash used in investing activities: ₱1,700,000. Capitalized interest forms part of the asset cost and is classified as an investing outflow. Proceeds from the old building computed as its book value plus the recognized gain is an investing inflow. The collection of loan principal is an investing inflow." } },
  { "FAR-StatementOfCashFlows-053": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm had these cash flows: Cash proceeds from sale of land ₱1,800,000; Purchase of equipment with a total cost of ₱3,000,000 where twenty percent was paid in cash and the balance on mortgage; Purchase of inventory ₱500,000; Loans granted to associates ₱1,200,000; Sale of investment in associate having a carrying amount of ₱1,500,000 sold at a loss of ₱300,000. What is the net cash provided by investing activities?", "solution": 1200000, "explanation": "Cash proceeds from sale of land: ₱1,800,000 + Cash proceeds from sale of investment: 1,200,000 - Cash paid for equipment: 600,000 - Loans granted to associates: 1,200,000 = Net cash provided by investing activities: ₱1,200,000. Only the cash down payment for the equipment is an investing outflow. The purchase of inventory is operating. Loans granted to other entities are investing outflows. Proceeds from the investment sale are computed as carrying amount minus the loss." } },
  { "FAR-StatementOfCashFlows-054": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A corporation acquired a subsidiary by paying ₱5,000,000 cash. The subsidiary had a cash balance of ₱800,000 at acquisition. The corporation also purchased machinery for ₱900,000 cash, paid ₱200,000 for a major capitalizable overhaul of the machinery, and received ₱1,500,000 in insurance proceeds from a warehouse destroyed by fire. Calculate the net cash used in investing activities.", "solution": 3800000, "explanation": "Cash paid for subsidiary net of cash acquired: ₱4,200,000 + Cash paid for machinery: 900,000 + Cash paid for major overhaul: 200,000 - Insurance proceeds from destroyed warehouse: 1,500,000 = Net cash used in investing activities: ₱3,800,000. Business acquisitions are reported net of the cash acquired as an investing outflow. The major overhaul extends the asset life and is capitalized as an investing outflow. Insurance compensation for damaged property is an investing inflow." } },
  { "FAR-StatementOfCashFlows-055": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net cash used in investing activities: Sale of equipment with a book value of ₱300,000 sold at twenty percent above book value; Acquisition of a franchise for ₱500,000 cash; Payment of principal on a bank loan ₱1,000,000; Payment for development costs capitalized as an intangible asset ₱400,000; Collection of advance to an affiliate ₱250,000.", "solution": 290000, "explanation": "Cash paid for franchise: ₱500,000 + Cash paid for capitalized development costs: 400,000 - Cash proceeds from sale of equipment: 360,000 - Collection of advance to affiliate: 250,000 = Net cash used in investing activities: ₱290,000. Franchise acquisitions and capitalized development expenditures are investing outflows. Proceeds from the equipment sale computed as book value multiplied by one point two is an investing inflow. Payment of a bank loan is a financing activity." } },
  { "FAR-StatementOfCashFlows-056": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity purchased land for ₱4,000,000 by issuing ₱3,000,000 in ordinary shares and paying ₱1,000,000 cash. It sold a patent with a carrying amount of ₱600,000 for a gain of ₱150,000. It also paid ₱1,200,000 to acquire bonds intended to be held to maturity. Dividends paid to shareholders were ₱800,000. What is the net cash used in investing activities?", "solution": 1450000, "explanation": "Cash paid for land: ₱1,000,000 + Cash paid for amortized cost bonds: 1,200,000 - Cash proceeds from sale of patent: 750,000 = Net cash used in investing activities: ₱1,450,000. Only the cash portion of the land acquisition is recorded as an investing outflow. The acquisition of held to maturity bonds is an investing outflow. Proceeds from the patent computed as carrying amount plus gain is an investing inflow. Dividends paid are financing." } },
  { "FAR-StatementOfCashFlows-057": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company acquired new machinery with a list price of ₱3,300,000 by trading in old machinery and paying ₱2,800,000 cash. It purchased investment property for ₱1,500,000. It received ₱900,000 from the sale of FVOCI equity securities and paid ₱400,000 to purchase treasury shares. Calculate the net cash used in investing activities.", "solution": 3400000, "explanation": "Cash paid for new machinery: ₱2,800,000 + Cash paid for investment property: 1,500,000 - Cash proceeds from sale of non trading securities: 900,000 = Net cash used in investing activities: ₱3,400,000. In a trade-in transaction lacking full cash settlement, only the actual cash paid is an investing outflow. Purchasing investment property is an investing outflow. Selling FVOCI securities is an investing inflow. Treasury share purchases are financing activities." } },
  { "FAR-StatementOfCashFlows-058": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net cash provided by investing activities from the following: Proceeds from sale of building ₱3,500,000; Payment for construction in progress ₱1,800,000; Payment of interest on construction loan capitalized to the asset ₱200,000; Purchase of copyright ₱350,000; Purchase of trading securities ₱600,000; Sale of equipment with a carrying amount of ₱900,000 sold at a loss of ₱150,000.", "solution": 1900000, "explanation": "Cash proceeds from sale of building: ₱3,500,000 + Cash proceeds from sale of equipment: 750,000 - Cash paid for construction in progress: 1,800,000 - Capitalized interest paid: 200,000 - Cash paid for copyright: 350,000 = Net cash provided by investing activities: ₱1,900,000. Capitalized interest is treated as an investing outflow because it forms part of the qualifying asset cost. The purchase of trading securities is an operating activity. Proceeds from equipment is carrying amount minus loss." } },
  { "FAR-StatementOfCashFlows-059": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm paid ₱4,000,000 to acquire a thirty percent interest in an associate. It received ₱2,500,000 from the disposal of a subsidiary, which held a cash balance of ₱300,000 at the time of sale. The firm also purchased delivery trucks for ₱1,200,000 cash and paid ₱400,000 on its lease liability principal. What is the net cash used in investing activities?", "solution": 3000000, "explanation": "Cash paid for investment in associate: ₱4,000,000 + Cash paid for delivery trucks: 1,200,000 - Cash proceeds from disposal of subsidiary net of cash disposed: 2,200,000 = Net cash used in investing activities: ₱3,000,000. Investments in associates and physical assets are investing outflows. Proceeds from disposing a subsidiary must be reported net of the subsidiary cash balance surrendered. Payment of lease liability principal is a financing activity." } },
  { "FAR-StatementOfCashFlows-060": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Calculate the net cash used in investing activities: Purchase of land ₱5,000,000; Payment for demolition of an old building on the land to prepare for new construction ₱300,000; Proceeds from salvage of demolished building materials ₱50,000; Sale of a different parcel of land costing ₱2,000,000 for a gain of ₱800,000; Payment of accounts payable ₱1,500,000.", "solution": 2450000, "explanation": "Cash paid for land: ₱5,000,000 + Cash paid for demolition: 300,000 - Cash proceeds from salvage: 50,000 - Cash proceeds from sale of land: 2,800,000 = Net cash used in investing activities: ₱2,450,000. Demolition costs and salvage proceeds related to site preparation are investing cash flows because they are capitalized as part of the readiness of property plant and equipment. Accounts payable payments are operating activities." } },
  { "FAR-StatementOfCashFlows-061": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported: Loans granted to other entities ₱2,500,000; Collections of principal on loans to other entities ₱800,000; Purchase of FVPL securities ₱900,000; Purchase of software ₱400,000; Sale of machinery with a carrying amount of ₱1,200,000 sold for ₱1,000,000. What is the net cash used in investing activities?", "solution": 1100000, "explanation": "Cash paid for loans to other entities: ₱2,500,000 + Cash paid for software: 400,000 - Cash collected from loans: 800,000 - Cash proceeds from sale of machinery: 1,000,000 = Net cash used in investing activities: ₱1,100,000. Making loans and collecting the principal on those loans to outside parties are investing activities. Software is an intangible asset requiring an investing outflow. The purchase of FVPL securities is an operating activity because they are held for short-term trading." } },
  { "FAR-StatementOfCashFlows-062": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net cash used in investing activities: Cash paid for equipment ₱3,200,000; Installation costs paid for equipment ₱150,000; Cash received from a government grant specifically for the equipment ₱500,000; Sale of a patent with a book value of ₱800,000 sold at a loss of ₱200,000.", "solution": 2250000, "explanation": "Cash paid for equipment: ₱3,200,000 + Cash paid for installation: 150,000 - Cash received from government grant: 500,000 - Cash proceeds from sale of patent: 600,000 = Net cash used in investing activities: ₱2,250,000. Installation costs are capitalized and form part of the investing outflow. Government grants related to assets are treated as investing inflows. Proceeds from the patent sale computed as book value minus the loss is an investing inflow." } },
  { "FAR-StatementOfCashFlows-063": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm paid ₱6,000,000 cash to acquire the net assets of a competitor. It also paid ₱400,000 for directly attributable costs to acquire a parcel of land. It sold a long-term investment costing ₱2,000,000 for ₱3,500,000. Dividends paid to its own shareholders were ₱1,000,000. Calculate the net cash used in investing activities.", "solution": 2900000, "explanation": "Cash paid for competitor net assets: ₱6,000,000 + Cash paid for direct land acquisition costs: 400,000 - Cash proceeds from sale of long term investment: 3,500,000 = Net cash used in investing activities: ₱2,900,000. The acquisition of the net assets of a business is an investing outflow. Directly attributable costs to acquire property are capitalized as investing outflows. The sale of long-term investments is an investing inflow. Dividends paid are financing outflows." } },
  { "FAR-StatementOfCashFlows-064": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Company records show: Sale of equipment with an original cost of ₱4,000,000 and accumulated depreciation of ₱1,500,000 sold for ₱3,000,000 cash; Purchase of bonds to be held at amortized cost ₱2,000,000; Amortization of bond discount ₱50,000; Payment for major leasehold improvements ₱800,000; Repayment of bank loan ₱1,500,000. What is the net cash provided by investing activities?", "solution": 200000, "explanation": "Cash proceeds from sale of equipment: ₱3,000,000 - Cash paid for amortized cost bonds: 2,000,000 - Cash paid for leasehold improvements: 800,000 = Net cash provided by investing activities: ₱200,000. Sale of equipment provides cash based exactly on actual proceeds regardless of book value. Bond purchases and leasehold improvements are investing outflows. Bond discount amortization is noncash. Loan repayment is a financing activity." } },
  { "FAR-StatementOfCashFlows-065": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity purchased machinery for ₱2,500,000 by paying ₱1,000,000 cash and issuing a ₱1,500,000 note. It paid ₱200,000 cash for freight and insurance on the new machinery. It sold a piece of land for ₱1,800,000 by receiving ₱800,000 cash and a ₱1,000,000 note receivable. It also purchased inventory for ₱600,000 cash. Compute the net cash used in investing activities.", "solution": 400000, "explanation": "Cash paid for machinery downpayment: ₱1,000,000 + Cash paid for machinery freight and insurance: 200,000 - Cash collected from sale of land: 800,000 = Net cash used in investing activities: ₱400,000. Only the actual cash components of asset acquisitions and sales are recorded. Noncash notes issued or received are strictly excluded. Freight and insurance to bring the asset to its intended use are capitalized and form part of the investing outflows." } },
  { "FAR-StatementOfCashFlows-066": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net cash used in investing activities: Insurance proceeds from machinery destroyed by earthquake ₱1,200,000; Purchase of replacement machinery ₱1,500,000; Sale of FVOCI investment with a fair value of ₱700,000 sold for ₱700,000 cash; Purchase of treasury bonds of the company's own debt ₱400,000; Purchase of associate entity's bonds ₱500,000.", "solution": 100000, "explanation": "Cash paid for replacement machinery: ₱1,500,000 + Cash paid for associate bonds: 500,000 - Insurance proceeds from destroyed machinery: 1,200,000 - Cash proceeds from sale of non trading investments: 700,000 = Net cash used in investing activities: ₱100,000. Insurance proceeds from property damage are investing inflows. Purchasing another entity's debt is an investing outflow but retiring the company's own debt is a financing outflow." } },
  { "FAR-StatementOfCashFlows-067": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm paid ₱450,000 cash for a trademark and ₱3,000,000 cash to acquire forty percent of an entity. It received ₱150,000 proceeds from the sale of obsolete equipment. Advances to officers and employees were ₱100,000. A long-term loan granted to a supplier amounted to ₱600,000. What is the net cash used in investing activities?", "solution": 3900000, "explanation": "Cash paid for trademark: ₱450,000 + Cash paid for investment in associate: 3,000,000 + Cash paid for long term loan granted: 600,000 - Cash proceeds from sale of equipment: 150,000 = Net cash used in investing activities: ₱3,900,000. Intangibles, investments in associates, and long term loans granted to others are investing outflows. Advances to officers and employees are generally considered operating activities under standard accounting conventions." } },
  { "FAR-StatementOfCashFlows-068": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Calculate the net cash used in investing activities: Purchase of equipment ₱2,200,000 cash; Sale of land costing ₱1,500,000 sold at a loss of ₱200,000; Purchase of ninety-day treasury bills ₱500,000; Collection of principal on long-term note receivable ₱700,000; Collection of interest on long-term note ₱70,000.", "solution": 200000, "explanation": "Cash paid for equipment: ₱2,200,000 - Cash proceeds from sale of land: 1,300,000 - Collection of principal on note receivable: 700,000 = Net cash used in investing activities: ₱200,000. The purchase of ninety day treasury bills represents a movement strictly within cash and cash equivalents and does not affect the cash flows. Interest collected is an operating inflow." } },
  { "FAR-StatementOfCashFlows-069": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported: Acquisition of patent ₱800,000 cash; Development costs capitalized ₱600,000; Research costs expensed ₱300,000; Sale of equipment with a book value of ₱1,000,000 sold for ₱1,400,000 cash; Purchase of investment in joint venture ₱2,000,000. Determine the net cash used in investing activities.", "solution": 2000000, "explanation": "Cash paid for patent: ₱800,000 + Cash paid for capitalized development costs: 600,000 + Cash paid for investment in joint venture: 2,000,000 - Cash proceeds from sale of equipment: 1,400,000 = Net cash used in investing activities: ₱2,000,000. Capitalized development costs are investing outflows because they result in an intangible asset, while research costs are immediately expensed as operating outflows. Joint ventures are investing activities." } },
  { "FAR-StatementOfCashFlows-070": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "During the year, a company paid ₱4,500,000 to construct a new warehouse and paid ₱300,000 for architect fees related to it. It received ₱2,000,000 from issuing ordinary shares. It sold an old warehouse for ₱1,800,000 cash. It also purchased held-for-trading securities for ₱500,000. What is the net cash used in investing activities?", "solution": 3000000, "explanation": "Cash paid for warehouse construction: ₱4,500,000 + Cash paid for architect fees: 300,000 - Cash proceeds from sale of old warehouse: 1,800,000 = Net cash used in investing activities: ₱3,000,000. Architect fees are directly attributable to the construction and are properly capitalized as part of the investing outflow. Trading securities purchases are operating activities, while issuing shares is a financing activity." } },
  { "FAR-StatementOfCashFlows-071": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net cash used in investing activities: Proceeds from sale of FVOCI securities ₱1,600,000; Purchase of equipment ₱2,100,000; Received government grant for environmental equipment ₱800,000; Paid environmental fines ₱100,000; Paid for a major overhaul of equipment extending its life ₱400,000.", "solution": 100000, "explanation": "Cash paid for equipment: ₱2,100,000 + Cash paid for major equipment overhaul: 400,000 - Cash proceeds from sale of FVOCI securities: 1,600,000 - Cash received from government grant: 800,000 = Net cash used in investing activities: ₱100,000. Overhauls that extend the useful life of an asset are capitalized and treated as investing outflows. Government grants specifically related to acquiring assets are treated as investing inflows. Fines are operating expenses." } },
  { "FAR-StatementOfCashFlows-072": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm reported: Sale of subsidiary net of cash disposed ₱3,500,000; Purchase of associate ₱1,800,000; Cash paid to acquire patent ₱700,000; Payment of lease liability ₱500,000; Cash received from short-term borrowing ₱1,000,000. Calculate the net cash provided by investing activities.", "solution": 1000000, "explanation": "Cash proceeds from sale of subsidiary: ₱3,500,000 - Cash paid for investment in associate: 1,800,000 - Cash paid for patent: 700,000 = Net cash provided by investing activities: ₱1,000,000. Transactions involving subsidiaries, associates, and intangibles are investing activities. Lease payments and short term borrowings are financing activities." } },
  { "FAR-StatementOfCashFlows-073": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Calculate the net cash used in investing activities: Cash paid for land ₱2,000,000; Cash paid for building construction ₱5,000,000; Capitalized borrowing costs paid ₱300,000; Proceeds from sale of equipment ₱1,500,000; Purchased bonds to be held at amortized cost ₱1,200,000.", "solution": 7000000, "explanation": "Cash paid for land: ₱2,000,000 + Cash paid for building construction: 5,000,000 + Cash paid for capitalized borrowing costs: 300,000 + Cash paid for amortized cost bonds: 1,200,000 - Cash proceeds from sale of equipment: 1,500,000 = Net cash used in investing activities: ₱7,000,000. Borrowing costs actually paid and properly capitalized into a qualifying asset become part of the investing cash outflows for that specific asset." } },
  { "FAR-StatementOfCashFlows-074": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity paid ₱8,000,000 cash to acquire a subsidiary. The subsidiary's cash balance acquired was ₱1,500,000. The entity sold equipment with a carrying amount of ₱2,000,000 for a gain of ₱400,000. Dividends received from an associate were ₱200,000. Loans granted to third parties were ₱1,000,000. What is the net cash used in investing activities?", "solution": 5100000, "explanation": "Cash paid for subsidiary net of cash acquired: ₱6,500,000 + Loans granted to third parties: 1,000,000 - Cash proceeds from sale of equipment: 2,400,000 = Net cash used in investing activities: ₱5,100,000. Acquisitions of businesses are presented net of the cash acquired. Equipment proceeds are carrying amount plus the gain. Dividends received are classified as operating inflows under benchmark standards." } },
  { "FAR-StatementOfCashFlows-075": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net cash used in investing activities: Sale of land ₱4,500,000 cash; Purchased machinery for ₱3,000,000; Paid ₱200,000 for installation of machinery; Paid ₱100,000 for staff training on the new machinery; Purchased FVOCI securities ₱1,500,000.", "solution": 200000, "explanation": "Cash paid for machinery: ₱3,000,000 + Cash paid for machinery installation: 200,000 + Cash paid for FVOCI securities: 1,500,000 - Cash proceeds from sale of land: 4,500,000 = Net cash used in investing activities: ₱200,000. Installation costs are capitalized investing outflows. Staff training costs cannot be capitalized and must be expensed immediately as operating outflows." } },
  { "FAR-StatementOfCashFlows-076": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company reported the following transactions: Purchased machinery with a list price of ₱4,000,000 by paying ₱1,500,000 in cash and signing a three year note for the balance; Paid ₱200,000 cash for installation and testing of the machinery; Received a government grant of ₱800,000 specifically to subsidize the machinery purchase; Paid interest of ₱100,000 on the note payable. What amount should be reported as net cash used in investing activities?", "solution": 900000, "explanation": "Cash down payment for machinery: ₱1,500,000 + Cash paid for installation and testing: 200,000 - Cash received from government grant: 800,000 = Net cash used in investing activities: ₱900,000. The noncash portion of the machinery purchase financed by the note is excluded from the cash flow statement. Installation and testing costs are strictly capitalized as part of the asset cost and represent an investing outflow. The government grant related to the asset is treated as an investing inflow. Interest paid is classified as an operating or financing activity, never investing." } },
  { "FAR-StatementOfCashFlows-077": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity engaged in the following: Sold equipment with a carrying amount of ₱1,200,000 at a loss of ₱300,000; Acquired a subsidiary for a total consideration of ₱5,000,000, paying ₱3,000,000 in cash and issuing equity shares for the remainder. The subsidiary had a cash balance of ₱400,000 on the acquisition date. The entity also advanced ₱100,000 to a primary supplier. Calculate the net cash used in investing activities.", "solution": 1700000, "explanation": "Cash paid for subsidiary acquisition: ₱3,000,000 - Cash acquired from subsidiary: 400,000 - Cash proceeds from sale of equipment: 900,000 = Net cash used in investing activities: ₱1,700,000. The acquisition of a business is reported net of the cash acquired as an investing outflow. The issuance of equity shares is a noncash financing transaction. Cash proceeds from the equipment sale are calculated as the carrying amount less the recognized loss. Advances to suppliers are classified as operating activities." } },
  { "FAR-StatementOfCashFlows-078": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "During the current year, a firm paid ₱2,500,000 for materials and ₱1,000,000 for direct labor to construct a new corporate headquarters. It paid ₱300,000 in interest on a specific construction loan, which qualifies for capitalization. It purchased trading securities for ₱400,000 and equity securities designated at fair value through other comprehensive income for ₱700,000. What is the net cash used in investing activities?", "solution": 4500000, "explanation": "Cash paid for construction materials: ₱2,500,000 + Cash paid for construction labor: 1,000,000 + Cash paid for capitalized interest: 300,000 + Cash paid for non trading securities: 700,000 = Net cash used in investing activities: ₱4,500,000. Material, labor, and capitalized interest directly attributable to a self constructed property form part of the asset cost and are investing outflows. Non trading securities designated at fair value through other comprehensive income are investing outflows. Trading securities are operating activities." } },
  { "FAR-StatementOfCashFlows-079": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A technology company had the following expenditures and receipts: Research costs paid ₱500,000; Development costs capitalized as an intangible asset ₱800,000; Purchase of a trademark ₱350,000; Sale of a patent with a carrying amount of ₱600,000 resulting in a gain of ₱250,000. Compute the net cash used in investing activities.", "solution": 300000, "explanation": "Cash paid for capitalized development costs: ₱800,000 + Cash paid for trademark: 350,000 - Cash proceeds from sale of patent: 850,000 = Net cash used in investing activities: ₱300,000. Research costs are strictly expensed when incurred and represent an operating outflow. Capitalized development costs and acquired trademarks are intangible assets that trigger investing outflows. Proceeds from the patent sale are computed as the carrying amount plus the recognized gain." } },
  { "FAR-StatementOfCashFlows-080": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity experienced a fire that destroyed its warehouse. It received insurance proceeds of ₱2,200,000 for the destroyed property. It paid ₱150,000 cash to clear the fire debris to prepare the site for a new building. It subsequently paid ₱3,000,000 to construct a replacement warehouse. What is the net cash used in investing activities?", "solution": 950000, "explanation": "Cash paid for new warehouse construction: ₱3,000,000 + Cash paid for site preparation: 150,000 - Insurance proceeds from destroyed warehouse: 2,200,000 = Net cash used in investing activities: ₱950,000. Insurance compensation for damaged or destroyed property plant and equipment is classified as an investing inflow. Site preparation costs such as clearing debris to build a new asset are capitalized as part of the new asset cost, creating an investing outflow." } },
  { "FAR-StatementOfCashFlows-081": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A corporation paid ₱4,500,000 cash for a fifty percent interest in a joint venture. During the year, it received ₱600,000 in cash dividends from this joint venture. It also collected ₱1,200,000 principal on a long term loan granted to an unaffiliated entity. Calculate the net cash used in investing activities.", "solution": 3300000, "explanation": "Cash paid for investment in joint venture: ₱4,500,000 - Cash collected from loan principal: 1,200,000 = Net cash used in investing activities: ₱3,300,000. Acquiring an interest in a joint venture is an investing outflow. Collecting the principal of a loan granted to another entity is an investing inflow. Under standard benchmark accounting, dividends received from investments are classified as operating inflows." } },
  { "FAR-StatementOfCashFlows-082": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company traded in old equipment with a carrying amount of ₱800,000 and a fair value of ₱1,000,000 for new equipment with a list price of ₱3,500,000. The company paid a cash boot of ₱2,300,000. It also paid ₱100,000 freight to transport the new equipment. Finally, it sold an idle parcel of land for ₱1,500,000 cash. What is the net cash used in investing activities?", "solution": 90000, "explanation": "Cash paid for equipment boot: ₱2,300,000 + Cash paid for equipment freight: 100,000 - Cash proceeds from sale of land: 1,500,000 = Net cash used in investing activities: ₱900,000. In a nonmonetary exchange involving a cash boot, only the actual cash paid is reported as an investing outflow. Freight costs are capitalized into the equipment cost. The sale of idle land provides an investing inflow." } },
  { "FAR-StatementOfCashFlows-083": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Evaluate the following cash flows: Purchased a ninety day treasury bill for ₱500,000; Purchased a one hundred twenty day treasury bill for ₱400,000; Purchased shares of an associate intended for long term hold ₱900,000; Sold trading equity securities for ₱350,000. Compute the net cash used in investing activities.", "solution": 1300000, "explanation": "Cash paid for one hundred twenty day treasury bill: ₱400,000 + Cash paid for investment in associate: 900,000 = Net cash used in investing activities: ₱1,300,000. The ninety day treasury bill qualifies as a cash equivalent, so its purchase is merely a movement of cash and is not an investing outflow. The one hundred twenty day bill is a short term investment and constitutes an investing outflow. Trading securities transactions are operating activities." } },
  { "FAR-StatementOfCashFlows-084": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity acquired a building valued at ₱6,000,000 by paying ₱1,500,000 in cash and assuming a pre-existing ₱4,500,000 mortgage. It later paid ₱300,000 for major renovations that extended the building useful life, and ₱100,000 for routine building maintenance. It received ₱800,000 from the sale of long term bonds. Calculate the net cash used in investing activities.", "solution": 1000000, "explanation": "Cash paid for building down payment: ₱1,500,000 + Cash paid for major renovations: 300,000 - Cash proceeds from sale of long term bonds: 800,000 = Net cash used in investing activities: ₱1,000,000. The assumption of a mortgage is a noncash investing and financing activity that is excluded from the cash flow statement. Major renovations are capitalized as investing outflows. Routine maintenance is expensed as an operating outflow." } },
  { "FAR-StatementOfCashFlows-085": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A real estate firm paid ₱4,000,000 cash for land to be held for long term capital appreciation. It paid ₱150,000 in non-refundable broker fees to acquire this land. It collected ₱400,000 in rent from temporary tenants on the land. It also sold a different investment property for ₱3,200,000. What is the net cash used in investing activities?", "solution": 950000, "explanation": "Cash paid for investment property land: ₱4,000,000 + Cash paid for broker fees: 150,000 - Cash proceeds from sale of investment property: 3,200,000 = Net cash used in investing activities: ₱950,000. Land held for capital appreciation is an investment property. Direct acquisition costs like broker fees are capitalized. Rent collected from tenants is an operating cash inflow. The sale of investment property provides an investing inflow." } },
  { "FAR-StatementOfCashFlows-086": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A parent company paid ₱5,500,000 cash for one hundred percent of a subsidiary. The subsidiary balance sheet showed ₱1,200,000 in cash. The parent paid ₱250,000 for direct acquisition costs such as legal and advisory fees. The parent also purchased equipment for ₱1,400,000. Calculate the net cash used in investing activities.", "solution": 5700000, "explanation": "Cash paid for subsidiary net of cash acquired: ₱4,300,000 + Cash paid for equipment: 1,400,000 = Net cash used in investing activities: ₱5,700,000. Acquisitions are reported net of cash acquired. Under PFRS 3, direct acquisition costs like legal and advisory fees are immediately expensed and classify as operating outflows rather than capitalized investing outflows." } },
  { "FAR-StatementOfCashFlows-087": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity purchased a tract of land containing an old unusable building for ₱5,000,000 cash. It paid ₱400,000 to demolish the building. It sold the salvaged materials from the demolition for ₱80,000. Finally, it paid ₱1,200,000 to construct a new parking lot on the site. What is the net cash used in investing activities?", "solution": 6520000, "explanation": "Cash paid for land: ₱5,000,000 + Cash paid for demolition: 400,000 - Cash proceeds from salvaged materials: 80,000 + Cash paid for parking lot construction: 1,200,000 = Net cash used in investing activities: ₱6,520,000. Demolition costs and salvage proceeds related to preparing the site for its intended use are capitalized into the cost of the land or new building, making them investing cash flows. Land improvements like parking lots are also investing outflows." } },
  { "FAR-StatementOfCashFlows-088": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm paid ₱700,000 to acquire a new enterprise software system. It paid ₱150,000 for staff training on the software and ₱50,000 for data conversion. It sold old server equipment that had an original cost of ₱1,000,000 and accumulated depreciation of ₱800,000 for ₱150,000 cash. Compute the net cash used in investing activities.", "solution": 550000, "explanation": "Cash paid for software system: ₱700,000 - Cash proceeds from sale of server equipment: 150,000 = Net cash used in investing activities: ₱550,000. The cost to acquire the software is an investing outflow. Staff training and data conversion costs cannot be capitalized as part of the intangible asset under PAS 38 and must be expensed as operating outflows. Proceeds from the asset sale are strictly the cash received." } },
  { "FAR-StatementOfCashFlows-089": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net cash used in investing activities: Cash paid to acquire a thirty percent interest in an associate ₱3,500,000; Cash received from the sale of a joint venture ₱2,100,000; Cash dividends received from the associate ₱400,000; Cash loan granted to the associate ₱1,500,000.", "solution": 2900000, "explanation": "Cash paid for investment in associate: ₱3,500,000 + Cash paid for loan granted to associate: 1,500,000 - Cash proceeds from sale of joint venture: 2,100,000 = Net cash used in investing activities: ₱2,900,000. Investments in associates and loans granted to other entities are investing outflows. Proceeds from selling a joint venture are investing inflows. Cash dividends received are generally classified as operating inflows under the primary PAS 7 benchmark." } },
  { "FAR-StatementOfCashFlows-090": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An agricultural company paid ₱1,200,000 to plant rubber trees. It paid ₱300,000 for fertilizers specifically used during the multi year growth period of the trees. It paid ₱400,000 to harvest rubber latex from mature trees. It also purchased a new tractor for ₱800,000. Calculate the net cash used in investing activities.", "solution": 2300000, "explanation": "Cash paid to plant rubber trees: ₱1,200,000 + Cash paid for growth period fertilizers: 300,000 + Cash paid for tractor: 800,000 = Net cash used in investing activities: ₱2,300,000. Rubber trees are bearer plants treated as property plant and equipment, making planting and growth stage costs capitalized investing outflows. Harvesting the latex relates to agricultural produce inventory and is an operating activity. The tractor is an investing outflow." } },
  { "FAR-StatementOfCashFlows-091": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A mining entity paid ₱2,000,000 for a mining license. It paid ₱300,000 for general prospecting costs prior to acquiring the license. Under the successful efforts method, it paid ₱800,000 for exploratory drilling which was capitalized. It sold old mining equipment for ₱500,000. What is the net cash used in investing activities?", "solution": 2300000, "explanation": "Cash paid for mining license: ₱2,000,000 + Cash paid for capitalized exploratory drilling: 800,000 - Cash proceeds from sale of mining equipment: 500,000 = Net cash used in investing activities: ₱2,300,000. Exploration and evaluation assets like licenses and capitalized drilling are investing outflows. Pre exploration prospecting costs incurred before securing legal rights must be expensed as operating outflows." } },
  { "FAR-StatementOfCashFlows-092": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity sold a building for ₱4,000,000 cash and immediately leased it back in a transaction that qualifies as a sale under PFRS 15. The entity purchased new factory machinery for ₱1,500,000. It paid the principal portion of its lease liability amounting to ₱400,000. Compute the net cash provided by investing activities.", "solution": 2500000, "explanation": "Cash proceeds from sale of building: ₱4,000,000 - Cash paid for factory machinery: 1,500,000 = Net cash provided by investing activities: ₱2,500,000. The cash proceeds from a valid sale and leaseback transaction are treated as an investing inflow from the disposal of property. Purchasing machinery is an investing outflow. The payment of the principal portion of a lease liability is strictly a financing outflow." } },
  { "FAR-StatementOfCashFlows-093": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm paid ₱5,000,000 for a new factory building. It received a government grant of ₱1,500,000 to help finance this specific building. It acquired equipment by donating a parcel of land with a carrying amount of ₱800,000 and a fair value of ₱1,200,000. It sold delivery vehicles for ₱450,000 cash. What is the net cash used in investing activities?", "solution": 3050000, "explanation": "Cash paid for factory building: ₱5,000,000 - Cash received from government grant: 1,500,000 - Cash proceeds from sale of vehicles: 450,000 = Net cash used in investing activities: ₱3,050,000. Government grants related to assets are classified as investing inflows. The acquisition of equipment via the donation of land is a noncash investing transaction that must be excluded from the cash flow statement entirely." } },
  { "FAR-StatementOfCashFlows-094": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net cash used in investing activities: Purchased bonds classified at fair value through other comprehensive income for ₱1,800,000; Sold bonds classified at amortized cost for ₱1,100,000; Purchased treasury shares for ₱500,000; Granted a cash advance to a joint venture for ₱900,000.", "solution": 1600000, "explanation": "Cash paid for FVOCI bonds: ₱1,800,000 + Cash paid for advance to joint venture: 900,000 - Cash proceeds from sale of amortized cost bonds: 1,100,000 = Net cash used in investing activities: ₱1,600,000. Purchasing non trading debt securities and advancing cash to joint ventures are investing outflows. Selling debt investments generates an investing inflow. Purchasing treasury shares represents a return of capital to owners and is a financing outflow." } },
  { "FAR-StatementOfCashFlows-095": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity collected ₱600,000 on a long term note receivable consisting of ₱500,000 principal and ₱100,000 interest. It granted a ₱2,000,000 cash loan to an affiliate. It purchased office equipment for ₱300,000 cash. What is the net cash used in investing activities?", "solution": 1800000, "explanation": "Cash paid for loan to affiliate: ₱2,000,000 + Cash paid for office equipment: 300,000 - Cash collected from note principal: 500,000 = Net cash used in investing activities: ₱1,800,000. Only the principal portion of the note collection is an investing inflow. The interest collected is classified as an operating cash flow under standard accounting rules. Loans granted and equipment purchases are investing outflows." } },
  { "FAR-StatementOfCashFlows-096": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company paid ₱1,500,000 to acquire a customer list from a competitor. It paid ₱400,000 to internally generate and design a new brand name. It purchased a patent for ₱600,000 cash. It sold a copyright for ₱250,000 cash. Compute the net cash used in investing activities.", "solution": 1850000, "explanation": "Cash paid for customer list: ₱1,500,000 + Cash paid for patent: 600,000 - Cash proceeds from sale of copyright: 250,000 = Net cash used in investing activities: ₱1,850,000. Acquired intangible assets like customer lists and patents are investing outflows. Internally generated brands cannot be capitalized under PAS 38 and must be expensed immediately as an operating outflow. The sale of an intangible provides an investing inflow." } },
  { "FAR-StatementOfCashFlows-097": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A machine with an original cost of ₱3,000,000 and accumulated depreciation of ₱1,800,000 was sold. The buyer paid ₱500,000 cash and legally assumed a ₱600,000 liability attached to the machine. The entity purchased a new machine for ₱2,400,000 cash. It also paid ₱150,000 cash to dismantle the old machine. Calculate the net cash used in investing activities.", "solution": 2050000, "explanation": "Cash paid for new machine: ₱2,400,000 + Cash paid to dismantle old machine: 150,000 - Cash proceeds from sale of old machine: 500,000 = Net cash used in investing activities: ₱2,050,000. Only the actual cash received from the buyer constitutes the investing inflow; the assumption of the liability is a noncash transaction. Dismantling costs directly associated with asset disposal or replacement reduce the net investing inflows or increase outflows." } },
  { "FAR-StatementOfCashFlows-098": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm purchased a commercial building for rental purposes for ₱8,000,000 by paying ₱5,000,000 cash and securing a mortgage for the remainder. It paid ₱400,000 in annual property taxes on the building. It sold a separate tract of land held for capital appreciation for ₱2,500,000 cash. What is the net cash used in investing activities?", "solution": 2500000, "explanation": "Cash paid for commercial building down payment: ₱5,000,000 - Cash proceeds from sale of land: 2,500,000 = Net cash used in investing activities: ₱2,500,000. Commercial buildings rented out and land held for appreciation are investment properties triggering investing cash flows. The noncash mortgage is excluded. Property taxes are regular operating expenses and are classified as operating outflows." } },
  { "FAR-StatementOfCashFlows-099": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity received ₱3,200,000 from the liquidation of a sixty percent owned subsidiary. It paid ₱1,800,000 to acquire a twenty percent stake in another company. It paid ₱500,000 in broker fees for this new acquisition. It also paid ₱200,000 in stock issuance costs. Calculate the net cash provided by investing activities.", "solution": 900000, "explanation": "Cash proceeds from liquidation of subsidiary: ₱3,200,000 - Cash paid for investment in associate: 1,800,000 - Cash paid for acquisition broker fees: 500,000 = Net cash provided by investing activities: ₱900,000. Proceeds from liquidating an investment are investing inflows. Direct broker fees for acquiring an investment are capitalized into the investment cost as an investing outflow. Stock issuance costs are financing outflows deducted from equity." } },
  { "FAR-StatementOfCashFlows-100": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Investing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net cash used in investing activities: Cash paid for property plant and equipment ₱4,200,000; Cash paid for capitalized interest ₱350,000; Cash received from sale of FVOCI securities ₱1,400,000; Cash paid to acquire a subsidiary net of ₱300,000 cash acquired ₱2,700,000; Cash collected from a one hundred twenty day treasury bill maturity ₱600,000.", "solution": 5250000, "explanation": "Cash paid for property plant and equipment: ₱4,200,000 + Cash paid for capitalized interest: 350,000 + Cash paid for subsidiary net of cash acquired: 2,700,000 - Cash proceeds from sale of FVOCI securities: 1,400,000 - Cash collected from short term treasury bill: 600,000 = Net cash used in investing activities: ₱5,250,000. Capitalized interest and net cash outflows for subsidiaries are investing activities. A one hundred twenty day treasury bill fails the cash equivalent test, so its collection is a cash inflow from investing activities." } },
  { "FAR-StatementOfCashFlows-101": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported the following: Proceeds from issuance of ordinary shares ₱4,000,000; Payment for stock issuance costs ₱200,000; Dividends declared ₱1,500,000; Increase in dividends payable ₱300,000; Proceeds from bank loan ₱2,000,000; Principal payment on lease liability ₱500,000; Interest paid on lease liability ₱100,000; Acquisition of equipment by issuing bonds ₱3,000,000. What amount should be reported as net cash provided by financing activities?", "solution": 4100000, "explanation": "Proceeds from issuance of ordinary shares: ₱4,000,000 - Payment for stock issuance costs: 200,000 - Payment of cash dividends: 1,200,000 + Proceeds from bank loan: 2,000,000 - Principal payment on lease liability: 500,000 = Net cash provided by financing activities: ₱4,100,000. Stock issuance costs are deducted directly from the share proceeds. Cash dividends paid are computed as dividends declared minus the increase in dividends payable. The principal payment on a lease liability is a financing outflow, but interest paid is typically classified as an operating outflow. Acquiring equipment by issuing bonds is a noncash transaction and is completely excluded from the cash flow statement." } },
  { "FAR-StatementOfCashFlows-102": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A corporation had the following transactions: Issuance of bonds with a face amount of ₱5,000,000 at one hundred five percent; Payment of bond issue costs ₱150,000; Retirement of bonds with a face amount of ₱2,000,000 at ninety eight percent; Payment of cash dividends ₱800,000; Distribution of a ten percent stock dividend valued at ₱500,000; Purchase of treasury shares ₱600,000. Calculate the net cash provided by financing activities.", "solution": 3740000, "explanation": "Proceeds from issuance of bonds: ₱5,250,000 - Payment of bond issue costs: 150,000 - Payment for retirement of bonds: 1,960,000 - Payment of cash dividends: 800,000 - Purchase of treasury shares: 600,000 = Net cash provided by financing activities: ₱3,740,000. The bonds were issued at a premium, so cash received is the face amount multiplied by the issuance percentage. Retirement cash paid is the face amount multiplied by the retirement percentage. Stock dividends are noncash transactions and are excluded. Purchasing treasury shares represents a return of capital to shareholders and is a financing outflow." } },
  { "FAR-StatementOfCashFlows-103": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net cash used in financing activities: Repayment of a long term bank loan ₱3,500,000; Payment of interest on the bank loan ₱250,000; Proceeds from reissuance of treasury shares ₱900,000; Payment to acquire ordinary shares for the treasury ₱1,200,000; Payment of accounts payable to merchandise suppliers ₱800,000; Dividends paid to preference shareholders ₱400,000.", "solution": 4200000, "explanation": "Repayment of long term bank loan: ₱3,500,000 - Proceeds from reissuance of treasury shares: 900,000 + Payment to acquire treasury shares: 1,200,000 + Dividends paid to preference shareholders: 400,000 = Net cash used in financing activities: ₱4,200,000. Repaying bank loans, acquiring treasury shares, and paying dividends are financing outflows. Reissuing treasury shares provides a financing inflow. Interest paid and payments to merchandise suppliers are classified as operating activities." } },
  { "FAR-StatementOfCashFlows-104": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "The financial records show: Issuance of preference shares ₱2,500,000; Conversion of bonds payable into ordinary shares ₱1,500,000; Payment of principal on finance lease ₱700,000; Payment of lease interest ₱120,000; Cash dividends declared ₱1,000,000 with a decrease in dividends payable of ₱200,000; Short term non trade bank loan received ₱1,800,000. Compute the net cash provided by financing activities.", "solution": 2400000, "explanation": "Proceeds from issuance of preference shares: ₱2,500,000 - Principal payment on finance lease: 700,000 - Payment of cash dividends: 1,200,000 + Proceeds from short term bank loan: 1,800,000 = Net cash provided by financing activities: ₱2,400,000. Conversion of bonds into shares is a significant noncash financing activity that must be disclosed elsewhere but excluded from cash flows. Cash dividends paid equal dividends declared plus the decrease in dividends payable. Short term non trade loans are financing inflows." } },
  { "FAR-StatementOfCashFlows-105": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity engaged in these transactions: Proceeds from issuing bonds ₱6,000,000; Payment of bond interest ₱500,000; Amortization of bond discount ₱50,000; Dividends paid to minority interest ₱300,000; Cash paid to acquire a subsidiary ₱2,000,000; Cash received from issuing ordinary shares ₱1,500,000; Payment of share issue costs ₱100,000. What is the net cash provided by financing activities?", "solution": 7100000, "explanation": "Proceeds from issuing bonds: ₱6,000,000 - Dividends paid to minority interest: 300,000 + Proceeds from issuing ordinary shares: 1,500,000 - Payment of share issue costs: 100,000 = Net cash provided by financing activities: ₱7,100,000. Dividends paid to non controlling or minority interests are financing outflows. Bond interest paid is an operating outflow, and amortization is a noncash operating adjustment. Acquiring a subsidiary is an investing outflow." } },
  { "FAR-StatementOfCashFlows-106": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Company data: Bonds payable January one ₱4,000,000; Bonds payable December thirty one ₱7,000,000; Unamortized premium on bonds January one ₱200,000; Unamortized premium on bonds December thirty one ₱450,000; Premium amortized during the year ₱50,000. No bonds were retired during the year. What is the cash inflow from the issuance of bonds?", "solution": 3300000, "explanation": "Increase in bonds payable face amount: ₱3,000,000 + Increase in unamortized premium: 250,000 + Premium amortized during the year: 50,000 = Cash proceeds from issuance of bonds: ₱3,300,000. The cash received equals the face amount of the new bonds issued plus the new premium attached to those bonds. The new premium is the net change in the premium account plus the amount that was amortized during the period." } },
  { "FAR-StatementOfCashFlows-107": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Calculate the net cash used in financing activities: Repayment of mortgage principal ₱2,000,000; Prepayment penalty on mortgage ₱100,000; Payment of property taxes ₱300,000; Cash dividends paid ₱800,000; Property dividends distributed ₱500,000; Proceeds from reissuing treasury shares at cost ₱400,000.", "solution": 2500000, "explanation": "Repayment of mortgage principal: ₱2,000,000 + Prepayment penalty on mortgage: 100,000 + Payment of cash dividends: 800,000 - Proceeds from reissuing treasury shares: 400,000 = Net cash used in financing activities: ₱2,500,000. The prepayment penalty is directly tied to the extinguishment of debt and is considered a financing outflow. Property dividends are noncash distributions and are excluded. Property taxes are operating expenses." } },
  { "FAR-StatementOfCashFlows-108": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm reported: Issuance of shares for a parcel of land valued at ₱3,000,000; Issuance of ordinary shares for cash ₱2,200,000; Payment of dividends ₱900,000; Payment of notes payable to suppliers ₱1,100,000; Payment of long term notes payable to bank ₱1,500,000. Determine the net cash used in financing activities.", "solution": 200000, "explanation": "Payment of cash dividends: ₱900,000 + Payment of long term notes payable to bank: 1,500,000 - Proceeds from issuance of ordinary shares: 2,200,000 = Net cash used in financing activities: ₱200,000. Issuing shares for land is a noncash transaction. Notes payable to suppliers are trade payables, so their settlement is an operating cash outflow. Only non trade debt repayments are financing outflows." } },
  { "FAR-StatementOfCashFlows-109": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Information for the year: Retained earnings January one ₱5,000,000; Retained earnings December thirty one ₱6,500,000; Net income ₱2,500,000; Stock dividends declared and issued ₱400,000. There were no prior period adjustments and dividends payable remained zero. Calculate the cash dividends paid.", "solution": 600000, "explanation": "Beginning retained earnings: ₱5,000,000 + Net income: 2,500,000 - Ending retained earnings: 6,500,000 - Stock dividends: 400,000 = Cash dividends paid: ₱600,000. To find cash dividends paid, analyze the retained earnings account. The total decrease in retained earnings not attributed to net income is one million, of which four hundred thousand is noncash stock dividends, leaving the remainder as cash dividends." } },
  { "FAR-StatementOfCashFlows-110": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Compute net cash provided by financing activities: Received ₱5,000,000 from issuing ten percent bonds at par; Paid ₱200,000 for direct bond issue costs; Paid ₱1,200,000 to retire ordinary shares; Received ₱300,000 from a government grant; Paid ₱800,000 in dividends; Paid ₱400,000 in interest.", "solution": 2800000, "explanation": "Proceeds from issuing bonds: ₱5,000,000 - Payment for bond issue costs: 200,000 - Payment to retire ordinary shares: 1,200,000 - Payment of cash dividends: 800,000 = Net cash provided by financing activities: ₱2,800,000. Government grants are typically classified as operating or investing depending on the nature of the grant. Interest paid is classified as operating under the benchmark treatment. Retiring shares is a financing outflow." } },
  { "FAR-StatementOfCashFlows-111": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity had the following: Treasury shares January one ₱1,000,000; Treasury shares December thirty one ₱1,800,000. During the year, the entity acquired treasury shares for ₱1,500,000. It also declared dividends of ₱700,000 while dividends payable decreased by ₱100,000. Calculate the net cash used in financing activities assuming no other transactions occurred.", "solution": 1600000, "explanation": "Payment to acquire treasury shares: ₱1,500,000 - Proceeds from reissuing treasury shares: 700,000 + Payment of cash dividends: 800,000 = Net cash used in financing activities: ₱1,600,000. Since treasury shares increased by eight hundred thousand but purchases were one point five million, the entity must have reissued treasury shares costing seven hundred thousand. Dividends paid equals dividends declared plus the decrease in dividends payable." } },
  { "FAR-StatementOfCashFlows-112": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm reported: Sale of investment in associate ₱2,000,000; Issuance of ordinary shares ₱4,500,000; Redemption of preference shares ₱1,800,000; Payment of short term bank loan ₱1,000,000; Payment of trade notes payable ₱600,000; Cash dividends paid ₱900,000. What is the net cash provided by financing activities?", "solution": 800000, "explanation": "Proceeds from issuance of ordinary shares: ₱4,500,000 - Payment to redeem preference shares: 1,800,000 - Payment of short term bank loan: 1,000,000 - Payment of cash dividends: 900,000 = Net cash provided by financing activities: ₱800,000. Redeeming shares and paying non trade short term loans are financing activities. Trade notes payable relate to suppliers and represent operating outflows. Sale of an investment is an investing inflow." } },
  { "FAR-StatementOfCashFlows-113": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net cash used in financing activities: Cash paid to retire bonds with a face value of ₱3,000,000 at one hundred four percent; Cash paid for bond interest ₱300,000; Cash received from a mortgage loan ₱1,500,000; Cash paid to acquire treasury shares ₱600,000; Cash paid for lease principal ₱450,000.", "solution": 1670000, "explanation": "Payment to retire bonds: ₱3,120,000 - Proceeds from mortgage loan: 1,500,000 + Payment to acquire treasury shares: 600,000 + Principal payment on lease liability: 450,000 = Net cash used in financing activities: ₱1,670,000. The cash paid to retire bonds is the face value multiplied by the retirement percentage. Mortgage loans are financing inflows. Lease principal payments are financing outflows. Bond interest is an operating outflow." } },
  { "FAR-StatementOfCashFlows-114": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company provided this data: Share capital January one ₱10,000,000; Share capital December thirty one ₱14,000,000; Share premium January one ₱2,000,000; Share premium December thirty one ₱3,500,000. During the year, a ten percent stock dividend was declared and issued when the market value of shares was ₱1,200,000. Determine the cash proceeds from issuing shares.", "solution": 4300000, "explanation": "Increase in share capital: ₱4,000,000 + Increase in share premium: 1,500,000 - Stock dividend capitalization: 1,200,000 = Cash proceeds from issuing shares: ₱4,300,000. The total increase in equity accounts is five point five million. Subtracting the one point two million noncash increase caused by the stock dividend leaves the amount of equity increase generated from actual cash issuances." } },
  { "FAR-StatementOfCashFlows-115": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported the following: Issued ₱5,000,000 face value bonds at ninety six percent; Paid bond issue costs of ₱100,000; Paid ₱2,000,000 to settle a long term note; Paid ₱300,000 penalty for early settlement of the note; Distributed property dividends with a carrying amount of ₱400,000; Paid cash dividends of ₱700,000. Calculate net cash provided by financing activities.", "solution": 1700000, "explanation": "Proceeds from issuing bonds: ₱4,800,000 - Payment of bond issue costs: 100,000 - Repayment of long term note: 2,000,000 - Payment of early settlement penalty: 300,000 - Payment of cash dividends: 700,000 = Net cash provided by financing activities: ₱1,700,000. Bonds issued at a discount provide cash equal to face value multiplied by the percentage. Penalties for early debt settlement are treated as part of the financing outflow to extinguish debt. Property dividends are noncash." } },
  { "FAR-StatementOfCashFlows-116": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net cash used in financing activities: Cash paid for dividends ₱1,100,000; Cash paid to acquire treasury shares ₱800,000; Cash received from issuing ordinary shares ₱1,500,000; Refinanced a ₱2,000,000 short term loan into a long term loan without cash transfer; Paid principal on finance lease ₱350,000.", "solution": 750000, "explanation": "Payment of cash dividends: ₱1,100,000 + Payment to acquire treasury shares: 800,000 - Proceeds from issuing ordinary shares: 1,500,000 + Principal payment on finance lease: 350,000 = Net cash used in financing activities: ₱750,000. Refinancing debt without any actual cash changing hands is a significant noncash financing activity and is entirely excluded from the statement of cash flows." } },
  { "FAR-StatementOfCashFlows-117": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm's ledger shows: Dividends payable January one ₱400,000; Dividends payable December thirty one ₱600,000; Retained earnings decreased by ₱1,500,000 during the year; Net income was ₱500,000. There were no stock dividends or prior period adjustments. Calculate the cash paid for dividends.", "solution": 1800000, "explanation": "Decrease in retained earnings: ₱1,500,000 + Net income: 500,000 = Dividends declared: ₱2,000,000. Dividends declared: ₱2,000,000 + Beginning dividends payable: 400,000 - Ending dividends payable: 600,000 = Cash paid for dividends: ₱1,800,000. A decrease in retained earnings despite positive net income means dividends declared must equal the decrease plus the net income. Adjusting this declared amount by the change in the payable account yields the actual cash paid." } },
  { "FAR-StatementOfCashFlows-118": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity engaged in these transactions: Issued preference shares for ₱3,500,000; Paid ₱250,000 for share registration and listing fees; Paid ₱1,500,000 to redeem maturing bonds; Paid ₱120,000 for bank overdrafts that are not part of cash equivalents; Collected ₱600,000 from a loan granted to an associate. Compute net cash provided by financing activities.", "solution": 1630000, "explanation": "Proceeds from issuing preference shares: ₱3,500,000 - Payment of share registration fees: 250,000 - Payment to redeem bonds: 1,500,000 - Payment of bank overdrafts: 120,000 = Net cash provided by financing activities: ₱1,630,000. Share registration fees are direct issuance costs deducted from financing inflows. Bank overdrafts not included in cash equivalents are treated as short term financing. Collecting a loan granted to an associate is an investing inflow." } },
  { "FAR-StatementOfCashFlows-119": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Calculate the net cash used in financing activities: Payment of cash dividends ₱1,300,000; Distribution of scrip dividends ₱200,000; Payment to retire ordinary shares ₱900,000; Proceeds from short term non trade loan ₱1,400,000; Cash paid for treasury shares ₱600,000; Payment of income taxes ₱300,000.", "solution": 1400000, "explanation": "Payment of cash dividends: ₱1,300,000 + Payment to retire ordinary shares: 900,000 - Proceeds from short term non trade loan: 1,400,000 + Payment to acquire treasury shares: 600,000 = Net cash used in financing activities: ₱1,400,000. Scrip dividends are promises to pay in the future and are noncash when distributed. Income taxes paid are operating outflows. Retiring shares and buying treasury shares are distinct financing outflows." } },
  { "FAR-StatementOfCashFlows-120": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company provided the following: Notes payable January one ₱5,000,000; Notes payable December thirty one ₱7,500,000. During the year, the company borrowed ₱4,000,000 cash from the bank. It also issued a ₱1,000,000 note payable to acquire a piece of land. Calculate the cash paid to settle notes payable.", "solution": 2500000, "explanation": "Beginning notes payable: ₱5,000,000 + Cash borrowed: 4,000,000 + Note issued for land: 1,000,000 - Ending notes payable: 7,500,000 = Cash paid to settle notes payable: ₱2,500,000. The total additions to the notes payable account include both cash borrowings and noncash issuances for assets. Subtracting the ending balance from the total accumulated balance reveals the cash disbursed for settlements." } },
  { "FAR-StatementOfCashFlows-121": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net cash provided by financing activities: Issued ordinary shares for ₱5,000,000; Paid stock issue costs of ₱300,000; Paid cash dividends of ₱1,200,000; Declared but unpaid cash dividends ₱400,000; Received ₱2,000,000 from issuing bonds; Converted ₱1,000,000 of preference shares into ordinary shares.", "solution": 5500000, "explanation": "Proceeds from issuing ordinary shares: ₱5,000,000 - Payment of stock issue costs: 300,000 - Payment of cash dividends: 1,200,000 + Proceeds from issuing bonds: 2,000,000 = Net cash provided by financing activities: ₱5,500,000. Declared but unpaid dividends do not involve a cash outflow. The conversion of preference shares into ordinary shares is a major noncash equity transaction that must be excluded from the cash flow computations." } },
  { "FAR-StatementOfCashFlows-122": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported: Cash paid to acquire treasury shares ₱1,500,000; Cash proceeds from selling treasury shares ₱800,000; Cash paid to settle a mortgage ₱2,500,000; Cash received from a government grant ₱1,000,000; Cash paid for dividends ₱700,000. What is the net cash used in financing activities?", "solution": 3900000, "explanation": "Payment to acquire treasury shares: ₱1,500,000 - Proceeds from selling treasury shares: 800,000 + Payment to settle mortgage: 2,500,000 + Payment of cash dividends: 700,000 = Net cash used in financing activities: ₱3,900,000. Selling treasury shares generates a financing inflow while acquiring them uses cash. Settling a mortgage is a debt repayment. Government grants are generally classified as operating or investing depending on the underlying condition." } },
  { "FAR-StatementOfCashFlows-123": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm's balances changed as follows: Bonds payable decreased by ₱2,000,000; Discount on bonds payable decreased by ₱150,000. The firm retired bonds with a face value of ₱2,000,000 and an unamortized discount of ₱100,000 by paying ₱1,950,000 cash. It also issued new ordinary shares for ₱3,000,000. Calculate the net cash provided by financing activities.", "solution": 1050000, "explanation": "Proceeds from issuing ordinary shares: ₱3,000,000 - Payment to retire bonds: 1,950,000 = Net cash provided by financing activities: ₱1,050,000. The actual cash disbursed to retire the bonds is explicitly given and is the amount utilized as the financing outflow regardless of the face value or the unamortized discount balances." } },
  { "FAR-StatementOfCashFlows-124": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the net cash used in financing activities: Cash paid for principal of lease liability ₱600,000; Cash paid for interest on lease liability ₱150,000; Cash paid for dividends ₱900,000; Cash proceeds from bank loan ₱1,200,000; Cash paid to settle trade notes payable ₱400,000.", "solution": 300000, "explanation": "Principal payment on lease liability: ₱600,000 + Payment of cash dividends: 900,000 - Proceeds from bank loan: 1,200,000 = Net cash used in financing activities: ₱300,000. Only the principal portion of lease payments is a financing outflow. Trade notes payable arise from operating activities and their settlement is an operating outflow. Interest paid is typically an operating outflow." } },
  { "FAR-StatementOfCashFlows-125": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company provided this data: Share capital increased by ₱3,000,000; Share premium increased by ₱1,200,000. The company issued shares for ₱2,500,000 cash and issued the remaining shares to settle a ₱1,700,000 long term bank loan. The company also paid ₱800,000 in cash dividends. Calculate the net cash provided by financing activities.", "solution": 1700000, "explanation": "Proceeds from issuing shares for cash: ₱2,500,000 - Payment of cash dividends: 800,000 = Net cash provided by financing activities: ₱1,700,000. Issuing shares directly to settle a debt is a noncash financing transaction that does not affect the cash flow statement. Only the portion of shares explicitly issued for cash generates a financing inflow." } },
  { "FAR-StatementOfCashFlows-126": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Retained earnings January one ₱8,000,000; Retained earnings December thirty one ₱10,500,000; Net income ₱4,000,000; Stock dividends declared ₱500,000. Dividends payable January one ₱300,000; Dividends payable December thirty one ₱700,000. Treasury shares purchased ₱900,000. Treasury shares reissued ₱1,200,000. What is the net cash used in financing activities?", "solution": 300000, "explanation": "First determine the cash dividends paid by analyzing retained earnings and dividends payable. Beginning retained earnings: ₱8,000,000 + Net income: 4,000,000 - Ending retained earnings: 10,500,000 - Stock dividends declared: 500,000 = Cash dividends declared: ₱1,000,000. Cash dividends declared: ₱1,000,000 + Beginning dividends payable: 300,000 - Ending dividends payable: 700,000 = Cash paid for dividends: ₱600,000. Next compute the total financing cash flows. Payment to acquire treasury shares: ₱900,000 + Cash paid for dividends: 600,000 - Proceeds from reissuing treasury shares: 1,200,000 = Net cash used in financing activities: ₱300,000. Stock dividends are noncash and excluded, while treasury share transactions and cash dividend payments are financing activities." } },
  { "FAR-StatementOfCashFlows-127": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Bonds payable January one ₱5,000,000; Bonds payable December thirty one ₱8,000,000. Discount on bonds January one ₱300,000; Discount on bonds December thirty one ₱400,000. Discount amortized during the year ₱50,000. Bonds with a face value of ₱1,000,000 and unamortized discount of ₱60,000 were retired at 102. Calculate the net cash provided by financing activities.", "solution": 2770000, "explanation": "To find the cash received from issuing new bonds, reconstruct the bonds payable and discount accounts. Increase in bonds payable face amount: ₱3,000,000 + Face amount of bonds retired: 1,000,000 = Face amount of new bonds issued: ₱4,000,000. Increase in unamortized discount: ₱100,000 + Discount amortized during the year: 50,000 + Unamortized discount of retired bonds: 60,000 = Discount on new bonds issued: ₱210,000. Face amount of new bonds issued: ₱4,000,000 - Discount on new bonds issued: 210,000 = Proceeds from issuing bonds: ₱3,790,000. Face amount of bonds retired: ₱1,000,000 * Retirement premium of one point zero two: 1.02 = Cash paid to retire bonds: ₱1,020,000. Proceeds from issuing bonds: ₱3,790,000 - Cash paid to retire bonds: 1,020,000 = Net cash provided by financing activities: ₱2,770,000." } },
  { "FAR-StatementOfCashFlows-128": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Share capital January one ₱4,000,000; Share capital December thirty one ₱5,500,000. Share premium January one ₱1,000,000; Share premium December thirty one ₱2,500,000. During the year, the company issued shares with a par value of ₱500,000 and fair value of ₱1,200,000 in exchange for a parcel of land. The remaining shares were issued for cash. The company also made lease payments totaling ₱1,500,000, of which ₱400,000 represented interest. What is the net cash provided by financing activities?", "solution": 700000, "explanation": "Increase in share capital: ₱1,500,000 + Increase in share premium: 1,500,000 - Fair value of shares issued for land: 1,200,000 = Proceeds from issuing shares for cash: ₱1,800,000. Total lease payments: ₱1,500,000 - Lease interest paid: 400,000 = Principal payment on lease liability: ₱1,100,000. Proceeds from issuing shares for cash: ₱1,800,000 - Principal payment on lease liability: 1,100,000 = Net cash provided by financing activities: ₱700,000. Issuing shares for land is a noncash transaction and must be deducted from the total equity increase to isolate cash proceeds. Only the principal portion of a lease payment is a financing outflow." } },
  { "FAR-StatementOfCashFlows-129": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company declared the following dividends: Cash dividends ₱1,500,000; Property dividends ₱800,000; Scrip dividends ₱500,000; Stock dividends ₱600,000. By year end, ₱300,000 of the cash dividends remained unpaid, and all scrip dividends were unpaid. The company also borrowed ₱4,000,000 from a bank and repaid ₱2,500,000 of existing bank loans. What is the net cash provided by financing activities?", "solution": 300000, "explanation": "Proceeds from bank loan: ₱4,000,000 - Repayment of bank loans: 2,500,000 - Cash dividends declared: 1,500,000 + Unpaid cash dividends: 300,000 = Net cash provided by financing activities: ₱300,000. Property, scrip, and stock dividends do not involve current cash outflows and are completely excluded. The unpaid portion of the cash dividends is added back to the declared amount to compute the actual cash paid." } },
  { "FAR-StatementOfCashFlows-130": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Bonds payable with a face value of ₱5,000,000 were settled. Half of the bonds were converted into ordinary shares with a fair value of ₱2,800,000. The other half was retired by paying ₱2,600,000 cash which includes the retirement penalty. The company also paid ₱150,000 for share issuance costs. Calculate the net cash used in financing activities.", "solution": 2750000, "explanation": "Cash paid to retire bonds: ₱2,600,000 + Payment of share issue costs: 150,000 = Net cash used in financing activities: ₱2,750,000. The conversion of bonds into ordinary shares is a major noncash financing activity that must be excluded from the cash flow statement. Share issue costs and cash paid to retire bonds are direct financing outflows." } },
  { "FAR-StatementOfCashFlows-131": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Notes payable January one ₱3,500,000; Notes payable December thirty one ₱6,000,000. During the year, the company issued a ₱2,000,000 note to purchase machinery. It also borrowed cash from a bank by issuing a new note. The company repaid ₱1,200,000 of existing notes in cash. Determine the cash proceeds from issuing notes payable.", "solution": 1700000, "explanation": "Ending notes payable: ₱6,000,000 - Beginning notes payable: 3,500,000 - Note issued for machinery: 2,000,000 + Repayment of notes payable: 1,200,000 = Proceeds from issuing notes payable: ₱1,700,000. The total increase in the notes payable account must be adjusted by removing the noncash issuance for machinery and adding back the cash repayments to determine the pure cash borrowed." } },
  { "FAR-StatementOfCashFlows-132": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Calculate the net cash provided by financing activities: Proceeds from issuing bonds ₱8,000,000; Payment of bond interest ₱600,000; Payment of cash dividends ₱1,400,000; Purchase of treasury shares ₱900,000; Proceeds from selling treasury shares ₱1,100,000; Payment of lease principal ₱500,000; Payment of lease interest ₱150,000; Cash paid to acquire a subsidiary ₱3,000,000.", "solution": 6300000, "explanation": "Proceeds from issuing bonds: ₱8,000,000 + Proceeds from selling treasury shares: 1,100,000 - Payment of cash dividends: 1,400,000 - Purchase of treasury shares: 900,000 - Payment of lease principal: 500,000 = Net cash provided by financing activities: ₱6,300,000. Bond and lease interest payments are classified as operating outflows under standard PAS 7 rules. Acquiring a subsidiary is an investing outflow." } },
  { "FAR-StatementOfCashFlows-133": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company issued shares upon the exercise of stock options, receiving ₱2,500,000 in cash. The options had a recognized fair value of ₱800,000 which was transferred from share premium options to share premium issuance. The company also granted restricted stock units and recognized ₱400,000 in compensation expense. It paid ₱1,500,000 to redeem preference shares. What is the net cash provided by financing activities?", "solution": 1000000, "explanation": "Proceeds from exercise of stock options: ₱2,500,000 - Payment to redeem preference shares: 1,500,000 = Net cash provided by financing activities: ₱1,000,000. The transfer of the option fair value between equity accounts is a noncash reclassification. The recognition of compensation expense for restricted stock units is a noncash operating adjustment." } },
  { "FAR-StatementOfCashFlows-134": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm had a ₱4,000,000 short term loan due. It paid ₱1,000,000 in cash and refinanced the remaining ₱3,000,000 into a long term loan by signing a new agreement with the bank. The firm also issued ordinary shares for ₱5,000,000 cash and paid ₱1,200,000 in cash dividends. Calculate the net cash provided by financing activities.", "solution": 2800000, "explanation": "Proceeds from issuing ordinary shares: ₱5,000,000 - Repayment of short term loan: 1,000,000 - Payment of cash dividends: 1,200,000 = Net cash provided by financing activities: ₱2,800,000. The refinancing of the three million peso balance into a long term loan involves no cash transfer and is treated as a significant noncash financing activity to be disclosed in the notes." } },
  { "FAR-StatementOfCashFlows-135": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Share capital increased by ₱2,000,000 and share premium increased by ₱1,800,000. A shareholder donated a parcel of land with a fair value of ₱1,500,000 which was credited to donated capital forming part of share premium. All other share issuances were for cash. Bonds payable decreased by ₱1,000,000 due to cash retirement. What is the net cash provided by financing activities?", "solution": 1300000, "explanation": "Increase in share capital: ₱2,000,000 + Increase in share premium: 1,800,000 - Fair value of donated land: 1,500,000 = Proceeds from issuing shares for cash: ₱2,300,000. Proceeds from issuing shares for cash: ₱2,300,000 - Payment to retire bonds: 1,000,000 = Net cash provided by financing activities: ₱1,300,000. Donated capital from shareholders increases equity but provides no cash, so its fair value must be deducted from the total equity increase to find the actual cash proceeds." } },
  { "FAR-StatementOfCashFlows-136": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "To acquire a subsidiary, a parent company paid ₱3,000,000 in cash, issued its own shares valued at ₱5,000,000, and borrowed ₱4,000,000 from a bank specifically for this acquisition. The parent also paid ₱500,000 in dividends to its own shareholders. Determine the net cash provided by financing activities.", "solution": 3500000, "explanation": "Proceeds from bank loan: ₱4,000,000 - Payment of cash dividends: 500,000 = Net cash provided by financing activities: ₱3,500,000. The issuance of shares to acquire the subsidiary is a noncash transaction. The cash paid to acquire the subsidiary is an investing outflow, while the cash borrowed from the bank to fund it is a financing inflow." } },
  { "FAR-StatementOfCashFlows-137": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Retained earnings January one ₱12,000,000; Retained earnings December thirty one ₱15,000,000. Net income for the year was ₱5,500,000. A prior period error understating depreciation by ₱800,000 was corrected directly against retained earnings. The only other change in retained earnings was the declaration of cash dividends. Dividends payable decreased by ₱200,000. Calculate the cash paid for dividends.", "solution": 1900000, "explanation": "Beginning retained earnings: ₱12,000,000 - Prior period error correction: 800,000 + Net income: 5,500,000 - Ending retained earnings: 15,000,000 = Cash dividends declared: ₱1,700,000. Cash dividends declared: ₱1,700,000 + Decrease in dividends payable: 200,000 = Cash paid for dividends: ₱1,900,000. The prior period error reduces the beginning retained earnings balance before current year income and dividends are factored in." } },
  { "FAR-StatementOfCashFlows-138": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity issued zero coupon bonds with a face value of ₱10,000,000 for ₱6,200,000 cash. It recognized ₱400,000 in interest expense during the year as discount amortization. It also retired an older batch of zero coupon bonds with a face value of ₱5,000,000 and unamortized discount of ₱1,000,000 by paying ₱4,200,000 cash. What is the net cash provided by financing activities?", "solution": 2000000, "explanation": "Proceeds from issuing zero coupon bonds: ₱6,200,000 - Payment to retire old bonds: 4,200,000 = Net cash provided by financing activities: ₱2,000,000. The cash inflow from a zero coupon bond is the actual deeply discounted cash received at issuance. The interest expense recognized through amortization is noncash. The retirement uses the actual cash paid to extinguish the debt." } },
  { "FAR-StatementOfCashFlows-139": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company sold a building for ₱10,000,000 cash and immediately leased it back. The transaction qualified as a sale. The present value of the lease payments was ₱6,000,000, which was recorded as a lease liability. During the year, the company paid ₱1,200,000 on the lease, of which ₱500,000 was interest. Calculate the net cash used in financing activities.", "solution": 700000, "explanation": "Total lease payments: ₱1,200,000 - Lease interest paid: 500,000 = Net cash used in financing activities: ₱700,000. The ten million proceeds from the sale of the building constitute an investing inflow, not financing. The establishment of the six million lease liability is a noncash financing activity. Only the principal reduction of the lease liability is a cash financing outflow." } },
  { "FAR-StatementOfCashFlows-140": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm executed a rights issue, allowing existing shareholders to purchase one hundred thousand new shares at ₱30 each. All rights were exercised for cash. The firm also redeemed fifty thousand preference shares at ₱110 each. It paid a ₱200,000 underwriting fee for the rights issue. What is the net cash used in financing activities?", "solution": 2700000, "explanation": "Proceeds from rights issue: ₱3,000,000 - Payment of underwriting fees: 200,000 - Payment to redeem preference shares: 5,500,000 = Net cash used in financing activities: ₱2,700,000. A rights issue generates a financing cash inflow when the rights are exercised. Underwriting fees are direct issuance costs deducted from the proceeds. Redeeming preference shares uses cash to buy back equity." } },
  { "FAR-StatementOfCashFlows-141": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company owed a bank ₱4,000,000 in principal and ₱400,000 in accrued interest. Under a debt restructuring agreement, the company issued shares with a fair value of ₱3,500,000 to fully settle the principal. The company paid the ₱400,000 accrued interest in cash along with a ₱100,000 restructuring penalty. Assume interest paid is classified as an operating cash flow. Determine the net cash used in financing activities.", "solution": 100000, "explanation": "Payment of restructuring penalty: ₱100,000 = Net cash used in financing activities: ₱100,000. The settlement of principal using shares is a noncash financing transaction. The payment of accrued interest is classified as an operating outflow as specified. The penalty incurred to extinguish the debt is a direct financing outflow." } },
  { "FAR-StatementOfCashFlows-142": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Share capital par 100 January one ₱5,000,000; December thirty one ₱7,000,000. Share premium January one ₱1,500,000; December thirty one ₱2,800,000. The company declared a ten thousand share stock dividend when the market price was ₱130 per share. The remaining increase in shares was due to a cash issuance. Calculate the cash proceeds from the share issuance.", "solution": 2000000, "explanation": "Increase in share capital: ₱2,000,000 + Increase in share premium: 1,300,000 - Total value of stock dividend: 1,300,000 = Cash proceeds from issuing shares: ₱2,000,000. The stock dividend capitalized one point three million of retained earnings into share capital and share premium without generating cash. Deducting this noncash value from the total increase in equity accounts yields the exact cash proceeds." } },
  { "FAR-StatementOfCashFlows-143": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity issued ₱5,000,000 face value convertible bonds for ₱5,400,000. The fair value of the bonds without the conversion option was ₱4,900,000, with the ₱500,000 residual assigned to the equity conversion privilege. During the year, ₱2,000,000 of these bonds were converted into ordinary shares. Calculate the net cash provided by financing activities.", "solution": 5400000, "explanation": "Proceeds from issuing convertible bonds: ₱5,400,000 = Net cash provided by financing activities: ₱5,400,000. The entire cash amount received upon issuing the compound financial instrument is a financing inflow, regardless of how it is split between liability and equity in the accounting records. The subsequent conversion of bonds into shares is a noncash transaction." } },
  { "FAR-StatementOfCashFlows-144": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm paid the following dividends during the year: Cash dividends ₱2,500,000; Liquidating dividends ₱800,000; Property dividends consisting of investments with a carrying amount of ₱1,200,000. It also paid ₱400,000 to acquire treasury shares. What is the net cash used in financing activities?", "solution": 3700000, "explanation": "Payment of cash dividends: ₱2,500,000 + Payment of liquidating dividends: 800,000 + Payment to acquire treasury shares: 400,000 = Net cash used in financing activities: ₱3,700,000. Liquidating dividends represent a return of capital and are paid in cash, making them financing outflows. Property dividends represent a distribution of noncash assets and are excluded from the cash flow statement." } },
  { "FAR-StatementOfCashFlows-145": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company borrowed ₱10,000,000 from a bank to construct a factory. It paid ₱800,000 in interest on this loan, all of which was capitalized as part of the factory cost. It repaid ₱2,000,000 of the loan principal. It also paid ₱300,000 in dividends. Calculate the net cash provided by financing activities.", "solution": 7700000, "explanation": "Proceeds from bank loan: ₱10,000,000 - Repayment of loan principal: 2,000,000 - Payment of cash dividends: 300,000 = Net cash provided by financing activities: ₱7,700,000. Capitalized interest is classified as an investing outflow because it forms part of the cost of the constructed asset, so it is excluded from financing activities." } },
  { "FAR-StatementOfCashFlows-146": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported: Proceeds from long term note ₱6,000,000; Repayment of short term trade notes ₱1,500,000; Increase in bank overdrafts forming part of cash management ₱800,000; Decrease in separate non trade bank overdrafts ₱400,000. Compute the net cash provided by financing activities.", "solution": 5600000, "explanation": "Proceeds from long term note: ₱6,000,000 - Decrease in non trade bank overdrafts: 400,000 = Net cash provided by financing activities: ₱5,600,000. Trade notes payable are operating liabilities. Overdrafts that form an integral part of cash management are grouped with cash and cash equivalents, not financing. Separate non trade overdrafts are short term borrowing, so their decrease is a financing outflow." } },
  { "FAR-StatementOfCashFlows-147": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm purchased treasury shares for ₱1,500,000. Later, it sold half of these shares for ₱900,000, crediting the ₱150,000 excess over cost to share premium treasury. It sold the remaining half for ₱600,000, debiting the ₱150,000 deficit against share premium and retained earnings. What is the net cash used in financing activities?", "solution": 0, "explanation": "Payment to acquire treasury shares: ₱1,500,000 - Proceeds from first sale of treasury shares: 900,000 - Proceeds from second sale of treasury shares: 600,000 = Net cash used in financing activities: ₱0. The accounting mechanics of gains and losses on treasury shares hitting share premium and retained earnings are irrelevant for cash flows. Only the raw cash paid to acquire them and the raw cash received from reissuing them are considered." } },
  { "FAR-StatementOfCashFlows-148": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company transferred ₱2,000,000 cash into a bond sinking fund. Using the sinking fund, it retired bonds with a face value of ₱1,800,000 by paying exactly ₱1,800,000. It also issued new ordinary shares for ₱4,000,000 cash. What is the net cash provided by financing activities?", "solution": 2200000, "explanation": "Proceeds from issuing ordinary shares: ₱4,000,000 - Payment to retire bonds: 1,800,000 = Net cash provided by financing activities: ₱2,200,000. The transfer of cash into a sinking fund is an investing outflow. The actual retirement of the bonds using those funds represents the financing outflow. The source of the cash does not change the financing nature of the bond retirement." } },
  { "FAR-StatementOfCashFlows-149": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Retained earnings increased by ₱4,500,000. Net income was ₱6,000,000. Dividends payable were ₱500,000 at the beginning and ₱800,000 at the end of the year. The company issued ₱3,000,000 in bonds and paid ₱1,200,000 to purchase treasury shares. Calculate the net cash provided by financing activities.", "solution": 600000, "explanation": "Net income: ₱6,000,000 - Increase in retained earnings: 4,500,000 = Cash dividends declared: ₱1,500,000. Cash dividends declared: ₱1,500,000 + Beginning dividends payable: 500,000 - Ending dividends payable: 800,000 = Cash paid for dividends: ₱1,200,000. Proceeds from issuing bonds: ₱3,000,000 - Cash paid for dividends: 1,200,000 - Payment to acquire treasury shares: 1,200,000 = Net cash provided by financing activities: ₱600,000." } },
  { "FAR-StatementOfCashFlows-150": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Financing Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported: Cash received from issuing ordinary shares ₱6,500,000; Cash paid for share issue costs ₱400,000; Cash paid to retire preference shares ₱2,800,000; Cash proceeds from bank loan ₱5,000,000; Cash paid to settle mortgage ₱3,500,000; Cash paid for finance lease principal ₱900,000; Cash dividends paid ₱1,600,000; Cash paid for interest ₱700,000. Compute net cash provided by financing activities.", "solution": 2300000, "explanation": "Proceeds from issuing ordinary shares: ₱6,500,000 + Proceeds from bank loan: 5,000,000 - Payment of share issue costs: 400,000 - Payment to retire preference shares: 2,800,000 - Payment to settle mortgage: 3,500,000 - Principal payment on finance lease: 900,000 - Payment of cash dividends: 1,600,000 = Net cash provided by financing activities: ₱2,300,000. All these are direct financing flows except interest paid, which is classified as an operating outflow under the standard benchmark." } },
{ "FAR-StatementOfCashFlows-151": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity provided the following data for 20xA and 20xB respectively: Trade accounts receivable net ₱1,200,000 and ₱1,500,000; Inventory ₱2,000,000 and ₱2,300,000; Accounts payable ₱1,500,000 and ₱1,700,000; Unearned revenue ₱400,000 and ₱600,000. Total sales were ₱15,000,000 for 20xB. Cash sales were thirty percent of total sales. Cost of goods sold was ₱9,000,000 for 20xB. Bad debt estimate for 20xB was ₱100,000 and writeoffs totaled ₱80,000. What is the amount collected from customers during 20xB?", "solution": 1480000, "explanation": "To determine the cash collected, adjust the total sales for changes in related operating assets and liabilities. Total sales: ₱15,000,000 - Increase in net accounts receivable: 300,000 + Increase in unearned revenue: 200,000 - Bad debt expense: 100,000 = Total cash collected from customers: ₱14,800,000. An increase in net accounts receivable indicates that revenue recognized exceeded cash collected, requiring a deduction. An increase in unearned revenue represents cash received in advance of revenue recognition, requiring an addition. Bad debt expense reduces net accounts receivable without a corresponding cash inflow, so it must be deducted to correct the net receivable change. The provided inventory, accounts payable, and cost of goods sold are distractors for computing customer collections." } },
  { "FAR-StatementOfCashFlows-152": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for 20xA and 20xB respectively: Gross trade accounts receivable ₱2,000,000 and ₱1,800,000; Allowance for bad debts ₱150,000 and ₱200,000; Inventory ₱3,500,000 and ₱3,200,000. Total sales for 20xB were ₱10,000,000. Recoveries of written off accounts were ₱20,000. Writeoffs during 20xB were ₱100,000. Sales discounts taken by customers were ₱50,000. What is the amount collected from customers during 20xB?", "solution": 10070000, "explanation": "Analyze the gross accounts receivable to compute collections. Gross accounts receivable beginning: ₱2,000,000 + Total sales: 10,000,000 + Recoveries of written off accounts: 20,000 - Writeoffs: 100,000 - Sales discounts: 50,000 - Gross accounts receivable ending: 1,800,000 = Cash collected from customers: ₱10,070,000. Recoveries temporarily increase the receivable balance before the cash is collected. Writeoffs and sales discounts reduce the gross receivable balance without generating cash, so they must be deducted to isolate the actual cash collections." } },
  { "FAR-StatementOfCashFlows-153": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for 20xA and 20xB respectively: Net trade accounts receivable ₱3,500,000 and ₱4,100,000; Unearned revenue ₱800,000 and ₱500,000; Accounts payable ₱2,100,000 and ₱1,900,000. Gross sales for 20xB were ₱26,000,000. Sales returns and allowances credited to receivables were ₱1,000,000. Bad debt expense for 20xB was ₱200,000. What is the amount collected from customers during 20xB?", "solution": 23900000, "explanation": "Adjust gross sales for noncash reductions and working capital changes. Gross sales: ₱26,000,000 - Sales returns and allowances: 1,000,000 - Increase in net accounts receivable: 600,000 - Decrease in unearned revenue: 300,000 - Bad debt expense: 200,000 = Total cash collected from customers: ₱23,900,000. A decrease in unearned revenue indicates that previously collected cash was recognized as revenue in the current period, so it is deducted to prevent overstating current cash inflows." } },
  { "FAR-StatementOfCashFlows-154": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for 20xA and 20xB respectively: Trade accounts receivable ₱2,500,000 and ₱3,000,000; Trade notes receivable ₱1,000,000 and ₱800,000; Prepaid expenses ₱300,000 and ₱450,000. Total sales for 20xB were ₱18,000,000. Sales returns for which cash refunds were given amounted to ₱150,000. Accounts written off during 20xB were ₱120,000. No allowance for bad debts is maintained. What is the net amount collected from customers during 20xB?", "solution": 17430000, "explanation": "First, compute the gross collections from the change in total trade receivables. Total trade receivables beginning: ₱3,500,000 + Total sales: 18,000,000 - Writeoffs: 120,000 - Total trade receivables ending: 3,800,000 = Gross collections from customers: ₱17,580,000. Next, deduct cash refunds to find the net cash collected. Gross collections from customers: ₱17,580,000 - Cash refunds for sales returns: 150,000 = Net amount collected from customers: ₱17,430,000. Trade notes receivable function exactly like accounts receivable for collections. Cash refunds for returns directly reduce the net cash collected during the period." } },
  { "FAR-StatementOfCashFlows-155": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for 20xA and 20xB respectively: Net accounts receivable ₱4,000,000 and ₱3,200,000; Advances from customers ₱600,000 and ₱1,100,000; Inventory ₱5,000,000 and ₱4,500,000. Total sales for 20xB were ₱22,000,000. Bad debt expense recognized for 20xB was ₱350,000. What is the amount collected from customers during 20xB?", "solution": 22950000, "explanation": "Adjust sales using the net accounts receivable and advances accounts. Total sales: ₱22,000,000 + Decrease in net accounts receivable: 800,000 + Increase in advances from customers: 500,000 - Bad debt expense: 350,000 = Total cash collected from customers: ₱22,950,000. An increase in customer advances means the company collected more cash than it recognized as revenue. The bad debt expense must be deducted because it reduced the net accounts receivable without generating any cash." } },
  { "FAR-StatementOfCashFlows-156": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for 20xA and 20xB respectively: Gross accounts receivable ₱5,000,000 and ₱6,500,000; Allowance for bad debts ₱400,000 and ₱600,000; Accounts payable ₱3,000,000 and ₱3,600,000. Total sales for 20xB were ₱30,000,000. Bad debt expense for the year was ₱500,000. What is the amount collected from customers during 20xB?", "solution": 28200000, "explanation": "First, reconstruct the allowance account to determine writeoffs. Allowance for bad debts beginning: ₱400,000 + Bad debt expense: 500,000 - Allowance for bad debts ending: 600,000 = Writeoffs: ₱300,000. Next, reconstruct the gross accounts receivable to find collections. Gross accounts receivable beginning: ₱5,000,000 + Total sales: 30,000,000 - Writeoffs: 300,000 - Gross accounts receivable ending: 6,500,000 = Cash collected from customers: ₱28,200,000. The writeoffs determined from the allowance account are deducted from the gross receivables because they reduce the balance without providing cash." } },
  { "FAR-StatementOfCashFlows-157": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for 20xA and 20xB respectively: Gross accounts receivable ₱3,000,000 and ₱2,200,000; Inventory ₱1,800,000 and ₱2,100,000. Cash sales for 20xB were ₱5,000,000 and credit sales were ₱25,000,000. Sales discounts taken by credit customers totaled ₱200,000. Accounts written off during the year were ₱150,000. What is the total cash collected from customers during 20xB?", "solution": 30450000, "explanation": "First, calculate collections from credit customers. Gross accounts receivable beginning: ₱3,000,000 + Credit sales: 25,000,000 - Sales discounts: 200,000 - Writeoffs: 150,000 - Gross accounts receivable ending: 2,200,000 = Collections from credit customers: ₱25,450,000. Next, add cash sales for total collections. Collections from credit customers: ₱25,450,000 + Cash sales: 5,000,000 = Total cash collected from customers: ₱30,450,000. Sales discounts and writeoffs reduce the receivable balance without cash inflows, requiring deduction when isolating credit collections." } },
  { "FAR-StatementOfCashFlows-158": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for 20xA and 20xB respectively: Net accounts receivable ₱6,000,000 and ₱7,500,000; Net trade notes receivable ₱2,000,000 and ₱1,000,000. Total sales for 20xB were ₱40,000,000. Bad debt expense for 20xB was ₱800,000. Operating expenses for 20xB were ₱12,000,000. What is the amount collected from customers during 20xB?", "solution": 38700000, "explanation": "Adjust net sales for changes in all trade receivables and noncash expenses. Net sales: ₱40,000,000 - Increase in net accounts receivable: 1,500,000 + Decrease in net trade notes receivable: 1,000,000 - Bad debt expense: 800,000 = Total cash collected from customers: ₱38,700,000. Both accounts receivable and trade notes receivable must be analyzed to capture all customer related cash flows. Bad debt expense reduces the net receivable balances but provides no cash, requiring a deduction." } },
  { "FAR-StatementOfCashFlows-159": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for 20xA and 20xB respectively: Gross accounts receivable ₱8,000,000 and ₱9,500,000; Accounts payable ₱4,000,000 and ₱3,500,000. Gross sales for 20xB were ₱50,000,000. Sales returns credited to customer accounts were ₱1,200,000. Sales returns for which cash refunds were given amounted to ₱400,000. Accounts written off were ₱500,000. What is the net cash collected from customers during 20xB?", "solution": 46400000, "explanation": "First, compute the gross collections from accounts receivable. Gross accounts receivable beginning: ₱8,000,000 + Gross sales: 50,000,000 - Sales returns credited to accounts: 1,200,000 - Writeoffs: 500,000 - Gross accounts receivable ending: 9,500,000 = Gross collections from customers: ₱46,800,000. Next, deduct cash refunds to find the net cash collected. Gross collections from customers: ₱46,800,000 - Cash refunds for sales returns: 400,000 = Net cash collected from customers: ₱46,400,000. Returns credited to accounts reduce the receivable balance directly, whereas cash refunds reduce the final cash collected." } },
  { "FAR-StatementOfCashFlows-160": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for 20xA and 20xB respectively: Gross accounts receivable ₱10,000,000 and ₱8,500,000; Unearned revenue ₱2,000,000 and ₱3,500,000. Total sales for 20xB were ₱60,000,000. Recoveries of previously written off accounts were ₱150,000. Accounts written off during the year were ₱900,000. What is the amount collected from customers during 20xB?", "solution": 62250000, "explanation": "Adjust total sales for changes in gross receivables, unearned revenue, and noncash items. Total sales: ₱60,000,000 + Decrease in gross accounts receivable: 1,500,000 + Recoveries of written off accounts: 150,000 - Writeoffs: 900,000 + Increase in unearned revenue: 1,500,000 = Total cash collected from customers: ₱62,250,000. Recoveries temporarily increase the receivable balance before the cash is received. The increase in unearned revenue is added because the company received cash in advance of earning the revenue." } },  
{ "FAR-StatementOfCashFlows-161": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity provided the following data for 20xA and 20xB respectively: Inventory ₱2,800,000 and ₱3,400,000; Accounts payable ₱1,900,000 and ₱1,500,000; Advances to suppliers ₱200,000 and ₱550,000. Total sales for 20xB were ₱24,000,000. The company consistently maintains a gross profit rate of forty percent based on sales. What is the amount disbursed for purchases during 20xB?", "solution": 15750000, "explanation": "Cost of goods sold: ₱14,400,000 + Increase in inventory: 600,000 + Decrease in accounts payable: 400,000 + Increase in advances to suppliers: 350,000 = Cash disbursed for purchases: ₱15,750,000. Cost of goods sold is derived by multiplying sales by sixty percent. An increase in inventory indicates purchases exceeded cost of goods sold. A decrease in accounts payable means cash payments exceeded new credit purchases. An increase in advances to suppliers represents additional cash outflows sent to vendors before goods were received." } },
  { "FAR-StatementOfCashFlows-162": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Financial records for 20xA and 20xB show: Inventory ₱4,000,000 and ₱3,500,000; Accounts payable ₱2,400,000 and ₱3,100,000. The cost of goods available for sale during 20xB was ₱18,000,000. Cost of goods sold for 20xB amounted to ₱14,500,000. Determine the total amount disbursed for purchases during 20xB.", "solution": 13300000, "explanation": "Gross purchases: ₱14,000,000 - Increase in accounts payable: 700,000 = Cash disbursed for purchases: ₱13,300,000. Gross purchases are derived by deducting the beginning inventory from the cost of goods available for sale. The increase in accounts payable is then deducted from gross purchases because it represents the portion of current year purchases that have not yet been paid in cash. The cost of goods sold and ending inventory are distractors when the cost of goods available for sale is already provided." } },
  { "FAR-StatementOfCashFlows-163": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for 20xA and 20xB respectively: Inventory ₱1,800,000 and ₱1,600,000; Total current liabilities ₱4,000,000 and ₱4,500,000. Included in current liabilities are Accrued operating expenses of ₱1,200,000 and ₱1,500,000, and Bank notes payable of ₱1,000,000 and ₱1,000,000. The remainder of current liabilities consists solely of trade accounts payable. Cost of goods sold for 20xB was ₱9,600,000. What is the amount disbursed for purchases during 20xB?", "solution": 9200000, "explanation": "Cost of goods sold: ₱9,600,000 - Decrease in inventory: 200,000 - Increase in trade accounts payable: 200,000 = Cash disbursed for purchases: ₱9,200,000. First isolate trade accounts payable by deducting accrued expenses and bank notes from total current liabilities, yielding beginning payables of one point eight million and ending payables of two million. A decrease in inventory implies goods sold were pulled from existing stock rather than new purchases. An increase in trade accounts payable means some purchases were financed via credit rather than cash." } },
  { "FAR-StatementOfCashFlows-164": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "For 20xA and 20xB respectively: Inventory ₱2,200,000 and ₱2,700,000; Accounts payable ₱1,600,000 and ₱1,400,000. Cost of goods sold for 20xB was ₱11,000,000. During 20xB, the company conducted a physical count and discovered an abnormal inventory shortage of ₱250,000 which was written off directly to a loss account. Calculate the cash disbursed for purchases during 20xB.", "solution": 11950000, "explanation": "Cost of goods sold: ₱11,000,000 + Inventory shortage written off: 250,000 + Increase in inventory: 500,000 + Decrease in accounts payable: 200,000 = Cash disbursed for purchases: ₱11,950,000. The abnormal inventory shortage removed goods from the warehouse without flowing through cost of goods sold, so it must be added alongside cost of goods sold to capture the total inventory credits for the year before adjusting for the change in inventory balances and accounts payable." } },
  { "FAR-StatementOfCashFlows-165": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for 20xA and 20xB respectively: Accounts payable ₱2,800,000 and ₱3,500,000. For 20xB, the company reported Net purchases of ₱15,000,000. Additional information for 20xB includes: Freight in paid in cash ₱400,000; Purchase returns credited against accounts payable ₱600,000. What is the total amount disbursed for purchases including freight during 20xB?", "solution": 14700000, "explanation": "Net purchases: ₱15,000,000 - Increase in accounts payable: 700,000 = Cash disbursed for purchases: ₱14,300,000. Cash disbursed for purchases: ₱14,300,000 + Freight in paid in cash: 400,000 = Total amount disbursed: ₱14,700,000. Adjusting net purchases directly for the change in accounts payable bypasses the need to manually add back purchase returns, as returns already reduced both net purchases and accounts payable equally. Freight in paid in cash is an additional operating cash outflow directly tied to inventory acquisition." } },
  { "FAR-StatementOfCashFlows-166": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for 20xA and 20xB respectively: Inventory ₱3,600,000 and ₱3,100,000; Accounts payable ₱2,500,000 and ₱2,100,000; Notes payable to trade suppliers ₱800,000 and ₱1,200,000. Cost of goods sold for 20xB was ₱16,500,000. Compute the amount disbursed for purchases during 20xB.", "solution": 16000000, "explanation": "Cost of goods sold: ₱16,500,000 - Decrease in inventory: 500,000 = Cash disbursed for purchases: ₱16,000,000. Both accounts payable and notes payable to trade suppliers constitute the total trade liabilities. The decrease in accounts payable of four hundred thousand is exactly offset by the increase in trade notes payable of four hundred thousand, resulting in zero net change in trade liabilities. Therefore, cash payments equal the purchases for the year." } },
  { "FAR-StatementOfCashFlows-167": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "For 20xA and 20xB respectively: Inventory ₱5,000,000 and ₱6,500,000; Accounts payable ₱3,200,000 and ₱4,800,000. Cost of goods sold for 20xB was ₱21,000,000. During 20xB, the company made strictly cash purchases amounting to ₱2,000,000. The rest of the purchases were on account. What is the total amount disbursed for all purchases during 20xB?", "solution": 20900000, "explanation": "Cost of goods sold: ₱21,000,000 + Increase in inventory: 1,500,000 - Increase in accounts payable: 1,600,000 = Cash disbursed for purchases: ₱20,900,000. The standard direct method adjustment formula inherently captures all cash paid to suppliers, encompassing both direct cash purchases and payments made to settle credit purchases. Segregating cash purchases from credit purchases is a distractor as the overall net change accurately reflects total cash outflows." } },
  { "FAR-StatementOfCashFlows-168": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for 20xA and 20xB respectively: Inventory ₱4,500,000 and ₱3,800,000; Accounts payable ₱2,700,000 and ₱2,100,000; Advances to suppliers ₱500,000 and ₱300,000. Sales for 20xB were ₱30,000,000, and the company reported a gross margin equal to thirty percent of sales. Determine the amount disbursed for purchases during 20xB.", "solution": 20700000, "explanation": "Cost of goods sold: ₱21,000,000 - Decrease in inventory: 700,000 + Decrease in accounts payable: 600,000 - Decrease in advances to suppliers: 200,000 = Cash disbursed for purchases: ₱20,700,000. Cost of goods sold is seventy percent of sales. A decrease in advances to suppliers means the company received inventory for which it had already paid cash in a prior period, thus reducing the current period cash requirement." } },
  { "FAR-StatementOfCashFlows-169": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "For 20xA and 20xB respectively: Inventory ₱3,100,000 and ₱3,500,000; Accounts payable recorded net of discount ₱1,960,000 and ₱2,450,000. Cost of goods sold for 20xB was ₱18,200,000. The company records purchases strictly net of a two percent cash discount. During 20xB, the company failed to take discounts on some invoices, resulting in purchase discounts lost of ₱120,000 which were paid in cash. What is the total cash disbursed for purchases during 20xB?", "solution": 18230000, "explanation": "Cost of goods sold: ₱18,200,000 + Increase in inventory: 400,000 - Increase in net accounts payable: 490,000 + Purchase discounts lost paid in cash: 120,000 = Cash disbursed for purchases: ₱18,230,000. The base adjustment using net accounts payable captures the cash flows as if all discounts were perfectly taken. Because the company missed some discounts and had to pay extra cash penalties, this specific discounts lost amount must be added to the total cash disbursements." } },
  { "FAR-StatementOfCashFlows-170": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for 20xA and 20xB respectively: Inventory ₱6,000,000 and ₱5,200,000; Accounts payable ₱4,100,000 and ₱3,600,000. Cost of goods sold for 20xB was ₱25,000,000. To settle an overdue balance with a major supplier during 20xB, the company issued ordinary shares with a fair value of ₱1,000,000 directly to the supplier. Calculate the cash disbursed for purchases during 20xB.", "solution": 23700000, "explanation": "Cost of goods sold: ₱25,000,000 - Decrease in inventory: 800,000 + Decrease in accounts payable: 500,000 - Noncash settlement of accounts payable: 1,000,000 = Cash disbursed for purchases: ₱23,700,000. Issuance of shares to settle accounts payable is a noncash transaction that artificially reduces the payable balance without utilizing cash, so it must be deducted from the standard computation to isolate the actual cash paid." } },
{ "FAR-StatementOfCashFlows-171": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company provided the following data: Total sales were ₱25,000,000 for 20xB and ₱20,000,000 for 20xA. Variable general and administrative expenses for 20xB were ₱2,500,000. These variable expenses have varied in proportion to sales. Sixty percent of variable expenses are paid in the year incurred and forty percent the following year. Fixed general and administrative expenses totaled ₱3,000,000 each year. These fixed expenses include depreciation of ₱600,000, amortization of ₱200,000, and bad debt expense of ₱100,000. Seventy percent of fixed expenses involving cash were paid in the year incurred and thirty percent the following year. In addition to the above, the company paid ₱150,000 for a one year insurance policy on December 31, 20xB, charged entirely to prepaid general and administrative expenses. Unpaid expenses are not included in accounts payable. What amount should be reported as cash disbursed for general and administrative expenses during 20xB?", "solution": 4550000, "explanation": "First determine the variable expenses for the prior year based on the proportion of sales. The variable expenses for 20xA are computed by dividing the 20xB variable expenses of two million five hundred thousand by the 20xB sales and multiplying by the 20xA sales to get two million. Next calculate the cash disbursed for variable expenses. Variable expenses paid from 20xB: ₱1,500,000 + Variable expenses paid from 20xA: 800,000 = Cash disbursed for variable expenses: ₱2,300,000. Then calculate the cash disbursed for fixed expenses by removing noncash items. Total fixed expenses: ₱3,000,000 - Depreciation: 600,000 - Amortization: 200,000 - Bad debt expense: 100,000 = Cash basis fixed expenses: ₱2,100,000. Fixed expenses paid from 20xB: ₱1,470,000 + Fixed expenses paid from 20xA: 630,000 = Cash disbursed for fixed expenses: ₱2,100,000. Finally aggregate all cash disbursements. Cash disbursed for variable expenses: ₱2,300,000 + Cash disbursed for fixed expenses: 2,100,000 + Prepaid insurance paid: 150,000 = Total cash disbursed for general and administrative expenses: ₱4,550,000." } },
  { "FAR-StatementOfCashFlows-172": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Total sales were ₱18,000,000 for 20xB and ₱15,000,000 for 20xA. Variable general and administrative expenses for 20xB were ₱3,600,000. They varied in strict proportion to sales. Forty percent of variable expenses are paid in the year incurred and sixty percent the following year. Fixed general and administrative expenses totaled ₱4,000,000 each year. These fixed expenses include depreciation of ₱800,000, amortization of ₱300,000, bad debt expense of ₱100,000, and share based compensation expense of ₱200,000. Ninety percent of fixed expenses involving cash were paid in the year incurred and ten percent the following year. Additionally, a separate general and administrative legal penalty of ₱300,000 was incurred and paid in full during 20xB. What is the total cash disbursed for general and administrative expenses during 20xB?", "solution": 6140000, "explanation": "Determine the variable expenses for 20xA based on the sales ratio. The 20xA variable expenses are three million, calculated by scaling the 20xB expenses by the ratio of 20xA sales to 20xB sales. Variable expenses paid from 20xB: ₱1,440,000 + Variable expenses paid from 20xA: 1,800,000 = Cash disbursed for variable expenses: ₱3,240,000. Next strip out all noncash items from the fixed expenses. Total fixed expenses: ₱4,000,000 - Depreciation: 800,000 - Amortization: 300,000 - Bad debt expense: 100,000 - Share based compensation: 200,000 = Cash basis fixed expenses: ₱2,600,000. Since the cash basis fixed expenses are identical each year, the total cash paid equals one full year of cash basis fixed expenses. Fixed expenses paid from 20xB: ₱2,340,000 + Fixed expenses paid from 20xA: 260,000 = Cash disbursed for fixed expenses: ₱2,600,000. Combine all payments. Cash disbursed for variable expenses: ₱3,240,000 + Cash disbursed for fixed expenses: 2,600,000 + Legal penalty paid: 300,000 = Total cash disbursed for general and administrative expenses: ₱6,140,000." } },
  { "FAR-StatementOfCashFlows-173": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Total sales were ₱24,000,000 for 20xB and ₱30,000,000 for 20xA. Variable general and administrative expenses for 20xB were ₱4,800,000 and varied directly with sales. Seventy five percent of variable expenses are paid in the year incurred and twenty five percent the following year. Fixed general and administrative expenses totaled ₱5,000,000 in 20xA and ₱5,500,000 in 20xB. Noncash items included in fixed expenses were depreciation of ₱1,000,000 and bad debt expense of ₱200,000 in 20xA, and depreciation of ₱1,200,000 and bad debt expense of ₱300,000 in 20xB. Eighty percent of fixed expenses involving cash were paid in the year incurred and twenty percent the following year. What amount was disbursed for general and administrative expenses during 20xB?", "solution": 9060000, "explanation": "Calculate the 20xA variable expenses by dividing the 20xB variable expenses by 20xB sales and multiplying by 20xA sales, resulting in six million. Variable expenses paid from 20xB: ₱3,600,000 + Variable expenses paid from 20xA: 1,500,000 = Cash disbursed for variable expenses: ₱5,100,000. Next determine the cash basis fixed expenses for each year. 20xA total fixed expenses: ₱5,000,000 - 20xA noncash expenses: 1,200,000 = 20xA cash basis fixed expenses: ₱3,800,000. 20xB total fixed expenses: ₱5,500,000 - 20xB noncash expenses: 1,500,000 = 20xB cash basis fixed expenses: ₱4,000,000. Fixed expenses paid from 20xB: ₱3,200,000 + Fixed expenses paid from 20xA: 760,000 = Cash disbursed for fixed expenses: ₱3,960,000. Sum the disbursements. Cash disbursed for variable expenses: ₱5,100,000 + Cash disbursed for fixed expenses: 3,960,000 = Total cash disbursed for general and administrative expenses: ₱9,060,000." } },
  { "FAR-StatementOfCashFlows-174": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Total sales were ₱15,000,000 for 20xB and ₱10,000,000 for 20xA. Variable general and administrative expenses for 20xB were ₱1,800,000 and varied proportionately with sales. Fifty percent of variable expenses are paid in the year incurred and fifty percent the following year. Fixed general and administrative expenses totaled ₱2,000,000 each year, including depreciation of ₱500,000 and amortization of ₱100,000. Sixty percent of fixed expenses involving cash were paid in the year incurred and forty percent the following year. The balance sheet showed prepaid general and administrative expenses of ₱200,000 at the end of 20xA and ₱500,000 at the end of 20xB. What is the total cash disbursed for general and administrative expenses during 20xB?", "solution": 3200000, "explanation": "The variable expenses for 20xA are one million two hundred thousand based on the proportion of sales. Variable expenses paid from 20xB: ₱900,000 + Variable expenses paid from 20xA: 600,000 = Cash disbursed for variable expenses: ₱1,500,000. For fixed expenses deduct the noncash items to find the cash basis expense. Total fixed expenses: ₱2,000,000 - Depreciation: 500,000 - Amortization: 100,000 = Cash basis fixed expenses: ₱1,400,000. Fixed expenses paid from 20xB: ₱840,000 + Fixed expenses paid from 20xA: 560,000 = Cash disbursed for fixed expenses: ₱1,400,000. An increase in prepaid expenses means cash was paid for future periods. Increase in prepaid expenses: ₱500,000 - Beginning prepaid expenses: 200,000 = Additional cash disbursed: ₱300,000. Cash disbursed for variable expenses: ₱1,500,000 + Cash disbursed for fixed expenses: 1,400,000 + Additional cash disbursed for prepaids: 300,000 = Total cash disbursed for general and administrative expenses: ₱3,200,000." } },
  { "FAR-StatementOfCashFlows-175": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Total sales were ₱50,000,000 for 20xB and ₱40,000,000 for 20xA. Variable general and administrative expenses for 20xB were ₱5,000,000, varying directly with sales. Eighty percent of variable expenses are paid in the year incurred and twenty percent the following year. Fixed general and administrative expenses totaled ₱6,000,000 in 20xA and ₱7,000,000 in 20xB. Noncash items included in fixed expenses were ₱2,000,000 in 20xA and ₱2,500,000 in 20xB. Seventy percent of fixed expenses involving cash were paid in the year incurred and thirty percent the following year. In addition, an advance payment of ₱400,000 was made in cash to a supplier for general and administrative services to be rendered in 20xC. What amount was disbursed for general and administrative expenses during 20xB?", "solution": 9550000, "explanation": "Based on the sales ratio, the variable expenses for 20xA are four million. Variable expenses paid from 20xB: ₱4,000,000 + Variable expenses paid from 20xA: 800,000 = Cash disbursed for variable expenses: ₱4,800,000. Next find the cash basis fixed expenses for each year. 20xA total fixed expenses: ₱6,000,000 - 20xA noncash expenses: 2,000,000 = 20xA cash basis fixed expenses: ₱4,000,000. 20xB total fixed expenses: ₱7,000,000 - 20xB noncash expenses: 2,500,000 = 20xB cash basis fixed expenses: ₱4,500,000. Fixed expenses paid from 20xB: ₱3,150,000 + Fixed expenses paid from 20xA: 1,200,000 = Cash disbursed for fixed expenses: ₱4,350,000. Sum the cash outflows. Cash disbursed for variable expenses: ₱4,800,000 + Cash disbursed for fixed expenses: 4,350,000 + Advance payment to supplier: 400,000 = Total cash disbursed for general and administrative expenses: ₱9,550,000." } },
  { "FAR-StatementOfCashFlows-176": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Total sales were ₱12,000,000 for 20xB and ₱8,000,000 for 20xA. Variable general and administrative expenses for 20xB were ₱2,400,000 and varied in proportion to sales. Sixty five percent of variable expenses are paid in the year incurred and thirty five percent the following year. Fixed general and administrative expenses totaled ₱3,000,000 in 20xA and ₱3,500,000 in 20xB. Noncash items included in fixed expenses were depreciation of ₱800,000 in 20xA, and depreciation of ₱900,000 plus an impairment loss of ₱200,000 in 20xB. Except for general and administrative salaries, fixed expenses involving cash were paid one hundred percent in the current year. General and administrative salaries expense included in fixed expenses was ₱1,000,000 for 20xB. Accrued general and administrative salaries decreased by ₱200,000 during 20xB. What is the total cash disbursed for general and administrative expenses during 20xB?", "solution": 4720000, "explanation": "Determine the 20xA variable expenses which amount to one million six hundred thousand due to the sales proportion. Variable expenses paid from 20xB: ₱1,560,000 + Variable expenses paid from 20xA: 560,000 = Cash disbursed for variable expenses: ₱2,120,000. The cash basis fixed expenses for 20xB are calculated by removing noncash items. 20xB total fixed expenses: ₱3,500,000 - Depreciation: 900,000 - Impairment loss: 200,000 = 20xB cash basis fixed expenses: ₱2,400,000. Since fixed expenses are paid one hundred percent in the current year except for the change in accrued salaries, start with the cash basis fixed expenses. 20xB cash basis fixed expenses: ₱2,400,000 + Decrease in accrued salaries: 200,000 = Cash disbursed for fixed expenses: ₱2,600,000. Cash disbursed for variable expenses: ₱2,120,000 + Cash disbursed for fixed expenses: 2,600,000 = Total cash disbursed for general and administrative expenses: ₱4,720,000. A decrease in accrued salaries signifies that cash payments exceeded the recognized expense." } },
  { "FAR-StatementOfCashFlows-177": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Total sales were ₱40,000,000 for 20xB and ₱50,000,000 for 20xA. Variable general and administrative expenses for 20xB were ₱8,000,000 and varied directly with sales. Fifty five percent of variable expenses are paid in the year incurred and forty five percent the following year. Fixed general and administrative expenses totaled ₱9,000,000 each year. These fixed expenses include noncash items totaling ₱3,000,000 each year. Eighty five percent of fixed expenses involving cash were paid in the year incurred and fifteen percent the following year. During 20xB, a supplier issued a cash refund of ₱200,000 for overbilled fixed general and administrative expenses from 20xA. What amount should be reported as net cash disbursed for general and administrative expenses during 20xB?", "solution": 14700000, "explanation": "The variable expenses for 20xA are ten million based on the proportionate drop in sales. Variable expenses paid from 20xB: ₱4,400,000 + Variable expenses paid from 20xA: 4,500,000 = Cash disbursed for variable expenses: ₱8,900,000. The cash basis fixed expenses are identical each year. Total fixed expenses: ₱9,000,000 - Noncash items: 3,000,000 = Cash basis fixed expenses: ₱6,000,000. Fixed expenses paid from 20xB: ₱5,100,000 + Fixed expenses paid from 20xA: 900,000 = Gross cash disbursed for fixed expenses: ₱6,000,000. Deduct the refund to get the net cash outflow. Gross cash disbursed for fixed expenses: ₱6,000,000 - Cash refund received: 200,000 = Net cash disbursed for fixed expenses: ₱5,800,000. Cash disbursed for variable expenses: ₱8,900,000 + Net cash disbursed for fixed expenses: 5,800,000 = Total cash disbursed for general and administrative expenses: ₱14,700,000." } },
  { "FAR-StatementOfCashFlows-178": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Total sales were ₱18,000,000 for 20xB and ₱12,000,000 for 20xA. Variable general and administrative expenses for 20xB were ₱2,700,000 and varied proportionately with sales. Seventy percent of variable expenses are paid in the year incurred and thirty percent the following year. Fixed general and administrative expenses totaled ₱2,500,000 in 20xA and ₱3,200,000 in 20xB. Noncash items included in fixed expenses were ₱1,000,000 in 20xA and ₱1,400,000 in 20xB. Fifty percent of fixed expenses involving cash were paid in the year incurred and fifty percent the following year. What is the total cash disbursed for general and administrative expenses during 20xB?", "solution": 4080000, "explanation": "The 20xA variable expenses compute to one million eight hundred thousand based on the sales proportion. Variable expenses paid from 20xB: ₱1,890,000 + Variable expenses paid from 20xA: 540,000 = Cash disbursed for variable expenses: ₱2,430,000. Determine the cash basis fixed expenses for both years. 20xA total fixed expenses: ₱2,500,000 - 20xA noncash items: 1,000,000 = 20xA cash basis fixed expenses: ₱1,500,000. 20xB total fixed expenses: ₱3,200,000 - 20xB noncash items: 1,400,000 = 20xB cash basis fixed expenses: ₱1,800,000. Fixed expenses paid from 20xB: ₱900,000 + Fixed expenses paid from 20xA: 750,000 = Cash disbursed for fixed expenses: ₱1,650,000. Cash disbursed for variable expenses: ₱2,430,000 + Cash disbursed for fixed expenses: 1,650,000 = Total cash disbursed for general and administrative expenses: ₱4,080,000." } },
  { "FAR-StatementOfCashFlows-179": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Total sales were ₱20,000,000 for 20xB and ₱16,000,000 for 20xA. Variable general and administrative expenses for 20xB were ₱4,000,000. These varied in proportion to sales. Ninety percent of variable expenses are paid in the year incurred and ten percent the following year. Fixed general and administrative expenses totaled ₱5,000,000 each year, including noncash items of ₱2,000,000. Sixty percent of fixed expenses involving cash were paid in the year incurred and forty percent the following year. Furthermore, the company paid ₱500,000 in cash during 20xB for late fees regarding general and administrative taxes. What is the total amount disbursed for general and administrative expenses during 20xB?", "solution": 7420000, "explanation": "Compute the variable expenses for 20xA which are three million two hundred thousand. Variable expenses paid from 20xB: ₱3,600,000 + Variable expenses paid from 20xA: 320,000 = Cash disbursed for variable expenses: ₱3,920,000. Find the cash basis fixed expenses by stripping out the noncash elements. Total fixed expenses: ₱5,000,000 - Noncash items: 2,000,000 = Cash basis fixed expenses: ₱3,000,000. Fixed expenses paid from 20xB: ₱1,800,000 + Fixed expenses paid from 20xA: 1,200,000 = Cash disbursed for fixed expenses: ₱3,000,000. Combine the cash outflows. Cash disbursed for variable expenses: ₱3,920,000 + Cash disbursed for fixed expenses: 3,000,000 + Late fees paid: 500,000 = Total cash disbursed for general and administrative expenses: ₱7,420,000." } },
{ "FAR-StatementOfCashFlows-180": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Total sales were ₱20,000,000 for 20xB and ₱25,000,000 for 20xA. Variable general and administrative expenses for 20xB were ₱3,000,000, varying proportionately with sales. Eighty percent of variable expenses are paid in the year incurred and twenty percent the following year. Fixed general and administrative expenses totaled ₱4,500,000 in 20xA and ₱4,800,000 in 20xB. Noncash items included in fixed expenses were ₱1,500,000 in 20xA and ₱1,800,000 in 20xB. Seventy five percent of fixed expenses involving cash were paid in the year incurred and twenty five percent the following year. In addition, the company paid a ₱400,000 refundable security deposit in cash for a new administrative office lease during 20xB. What is the amount disbursed for general and administrative expenses during 20xB?", "solution": 6150000, "explanation": "The variable expenses for 20xA calculate to three million seven hundred fifty thousand based on the sales proportion. Variable expenses paid from 20xB: ₱2,400,000 + Variable expenses paid from 20xA: 750,000 = Cash disbursed for variable expenses: ₱3,150,000. Determine the cash basis fixed expenses. 20xA total fixed expenses: ₱4,500,000 - 20xA noncash items: 1,500,000 = 20xA cash basis fixed expenses: ₱3,000,000. 20xB total fixed expenses: ₱4,800,000 - 20xB noncash items: 1,800,000 = 20xB cash basis fixed expenses: ₱3,000,000. Fixed expenses paid from 20xB: ₱2,250,000 + Fixed expenses paid from 20xA: 750,000 = Cash disbursed for fixed expenses: ₱3,000,000. The refundable security deposit is a non expense receivable asset and is strictly excluded from expense disbursements. Cash disbursed for variable expenses: ₱3,150,000 + Cash disbursed for fixed expenses: 3,000,000 = Total cash disbursed for general and administrative expenses: ₱6,150,000." } },
  { "FAR-StatementOfCashFlows-181": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "The financial records disclosed the following: Total sales ₱40,000,000; Gross accounts receivable increased by ₱3,000,000; Unearned revenue increased by ₱500,000; Accounts written off ₱200,000. Calculate the amount collected from customers.", "solution": 37300000, "explanation": "Total sales: ₱40,000,000 + Increase in unearned revenue: 500,000 - Increase in gross accounts receivable: 3,000,000 - Accounts written off: 200,000 = Total cash collected from customers: ₱37,300,000. An increase in unearned revenue represents cash received in advance of revenue recognition. An increase in gross accounts receivable means credit sales exceeded collections. Accounts written off reduce the gross receivable balance without generating cash, necessitating a deduction." } },
  { "FAR-StatementOfCashFlows-182": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity provided the following for the year: Gross sales ₱35,000,000; Net accounts receivable increased by ₱2,500,000; Bad debt expense ₱400,000; Sales discounts taken by customers ₱150,000. What is the amount collected from customers?", "solution": 31950000, "explanation": "Gross sales: ₱35,000,000 - Increase in net accounts receivable: 2,500,000 - Bad debt expense: 400,000 - Sales discounts: 150,000 = Total cash collected from customers: ₱31,950,000. An increase in net accounts receivable implies uncollected sales, so it is deducted. Bad debt expense reduces the net accounts receivable balance without a cash inflow. Sales discounts reduce the amount owed by customers but do not result in cash collections, requiring a deduction from gross sales." } },
  { "FAR-StatementOfCashFlows-183": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Information for the year includes: Total sales ₱50,000,000, which includes cash sales of ₱10,000,000; Gross accounts receivable beginning balance ₱4,000,000; Gross accounts receivable ending balance ₱5,500,000; Accounts written off ₱300,000; Recoveries of previously written off accounts ₱100,000. Compute the total cash collected from customers.", "solution": 48300000, "explanation": "Total sales: ₱50,000,000 + Beginning gross accounts receivable: 4,000,000 - Ending gross accounts receivable: 5,500,000 + Recoveries of written off accounts: 100,000 - Accounts written off: 300,000 = Total cash collected from customers: ₱48,300,000. The change in gross accounts receivable is applied to total sales. Recoveries increase the receivable balance temporarily before cash is collected, so they are added to the potential collections. Writeoffs reduce the receivable balance without yielding cash, so they are deducted." } },
  { "FAR-StatementOfCashFlows-184": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for the current year: Sales ₱28,000,000; Trade accounts receivable decreased by ₱1,200,000; Trade notes receivable increased by ₱800,000; Unearned revenue decreased by ₱600,000. Calculate the total amount collected from customers.", "solution": 27800000, "explanation": "Sales: ₱28,000,000 + Decrease in trade accounts receivable: 1,200,000 - Increase in trade notes receivable: 800,000 - Decrease in unearned revenue: 600,000 = Total cash collected from customers: ₱27,800,000. A decrease in trade accounts receivable indicates collections exceeded sales. An increase in trade notes receivable means some sales were uncollected. A decrease in unearned revenue signifies that previously collected cash was recognized as revenue during the current period, so it is deducted." } },
  { "FAR-StatementOfCashFlows-185": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "The following changes and amounts were reported: Sales ₱45,000,000; Gross accounts receivable increased by ₱4,000,000; Allowance for doubtful accounts increased by ₱500,000; Accounts written off during the year ₱250,000. Determine the amount collected from customers.", "solution": 40750000, "explanation": "Sales: ₱45,000,000 - Increase in gross accounts receivable: 4,000,000 - Accounts written off: 250,000 = Total cash collected from customers: ₱40,750,000. The increase in gross accounts receivable is deducted from sales because it represents uncollected revenue. Accounts written off are deducted because they reduce the gross accounts receivable without providing any cash. The change in the allowance for doubtful accounts is irrelevant when analyzing gross accounts receivable." } },
  { "FAR-StatementOfCashFlows-186": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company reported: Gross sales ₱32,000,000; Net accounts receivable decreased by ₱1,500,000; Bad debt expense ₱400,000; Sales returns credited to customer accounts ₱800,000; Sales returns refunded in cash ₱300,000. What is the net cash collected from customers?", "solution": 32000000, "explanation": "Gross sales: ₱32,000,000 + Decrease in net accounts receivable: 1,500,000 - Bad debt expense: 400,000 - Sales returns credited to accounts: 800,000 - Cash refunds for sales returns: 300,000 = Net cash collected from customers: ₱32,000,000. A decrease in net accounts receivable adds to collections. Bad debt expense and sales returns credited to accounts reduce the receivable balance without cash inflows, requiring deductions. Cash refunds directly reduce the final net cash collected." } },
  { "FAR-StatementOfCashFlows-187": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Given the following information: Sales ₱55,000,000; Advances from customers increased by ₱1,200,000; Gross accounts receivable decreased by ₱2,000,000; Accounts written off ₱600,000. Compute the total amount collected from customers.", "solution": 57600000, "explanation": "Sales: ₱55,000,000 + Increase in advances from customers: 1,200,000 + Decrease in gross accounts receivable: 2,000,000 - Accounts written off: 600,000 = Total cash collected from customers: ₱57,600,000. An increase in advances from customers means cash was collected ahead of revenue recognition. A decrease in gross accounts receivable indicates past sales were collected. Writeoffs reduce the receivable balance but do not represent cash collections, necessitating a deduction." } },
  { "FAR-StatementOfCashFlows-188": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported: Total sales ₱60,000,000; Net accounts receivable increased by ₱3,500,000; Bad debt expense ₱900,000; Recoveries of previously written off accounts ₱150,000; Accounts written off ₱400,000. Calculate the amount collected from customers.", "solution": 55600000, "explanation": "Total sales: ₱60,000,000 - Increase in net accounts receivable: 3,500,000 - Bad debt expense: 900,000 = Total cash collected from customers: ₱55,600,000. When analyzing net accounts receivable, recoveries and writeoffs are neutral events that do not alter the net balance. Only the net increase in receivables and the bad debt expense need to be deducted from sales to arrive at the actual cash collections." } },
  { "FAR-StatementOfCashFlows-189": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A company provided these details: Sales ₱42,000,000; Accounts receivable increased by ₱2,200,000; Notes receivable decreased by ₱1,500,000; Accounts written off ₱300,000; Sales discounts ₱100,000. Determine the total cash collected from customers.", "solution": 40900000, "explanation": "Sales: ₱42,000,000 - Increase in accounts receivable: 2,200,000 + Decrease in notes receivable: 1,500,000 - Accounts written off: 300,000 - Sales discounts: 100,000 = Total cash collected from customers: ₱40,900,000. The decrease in notes receivable adds to collections just like accounts receivable. Writeoffs and sales discounts reduce the receivable balances without providing cash, so they are deducted from sales to find the actual cash received." } },
  { "FAR-StatementOfCashFlows-190": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Financial data shows: Gross sales ₱38,000,000; Gross accounts receivable decreased by ₱1,800,000; Sales discounts taken ₱400,000; Accounts written off ₱250,000. What is the net amount collected from customers?", "solution": 39150000, "explanation": "Gross sales: ₱38,000,000 + Decrease in gross accounts receivable: 1,800,000 - Sales discounts: 400,000 - Accounts written off: 250,000 = Net cash collected from customers: ₱39,150,000. A decrease in gross accounts receivable is added to sales because it implies prior period credit sales were collected. Sales discounts and writeoffs decrease the receivable balance but do not represent cash receipts, meaning they must be subtracted." } },
{ "FAR-StatementOfCashFlows-191": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported cost of goods sold of ₱25,000,000 for the current year. During the year, inventory increased by ₱2,000,000, accounts payable decreased by ₱1,500,000, and advances to suppliers increased by ₱1,000,000. Additionally, an abnormal inventory shortage of ₱500,000 was discovered and written off directly to a separate loss account. What is the total amount disbursed to suppliers during the year?", "solution": 30000000, "explanation": "Cost of goods sold: ₱25,000,000 + Abnormal inventory shortage: 500,000 + Increase in inventory: 2,000,000 + Decrease in accounts payable: 1,500,000 + Increase in advances to suppliers: 1,000,000 = Cash disbursed to suppliers: ₱30,000,000. The abnormal shortage represents inventory credits not included in cost of goods sold, so it must be added to determine total purchases. An increase in inventory means purchases exceeded cost of goods sold. A decrease in accounts payable indicates payments exceeded new credit purchases. An increase in advances to suppliers represents cash paid out ahead of receiving goods." } },
  { "FAR-StatementOfCashFlows-192": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm reported cost of goods sold of ₱30,000,000. During the year, inventory decreased by ₱1,500,000. Total current liabilities increased by ₱4,000,000, which includes a ₱1,000,000 increase in accrued interest and a ₱500,000 increase in dividends payable. The remainder of the increase relates to trade accounts payable, which are recorded strictly net of discounts. Purchase discounts lost due to late payments were ₱200,000 and were paid in cash. Calculate the amount disbursed for purchases.", "solution": 26200000, "explanation": "Cost of goods sold: ₱30,000,000 - Decrease in inventory: 1,500,000 - Increase in trade accounts payable: 2,500,000 + Purchase discounts lost paid in cash: 200,000 = Cash disbursed for purchases: ₱26,200,000. First isolate the increase in trade accounts payable by deducting the non trade liability increases from the total increase in current liabilities. A decrease in inventory is deducted because goods were sourced from existing stock. The increase in trade accounts payable is deducted because purchases were financed by credit. Purchase discounts lost paid in cash are an additional cash outflow directly related to paying suppliers." } },
  { "FAR-StatementOfCashFlows-193": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "The income statement shows cost of goods sold of ₱18,000,000. Working capital changes include an increase in inventory of ₱3,000,000 and a decrease in accounts payable of ₱2,000,000. The company settled ₱1,000,000 of its accounts payable by issuing ordinary shares to the supplier. Furthermore, the company paid ₱500,000 in cash for freight in, which was not routed through accounts payable. What is the total cash disbursed for purchases?", "solution": 22500000, "explanation": "Cost of goods sold: ₱18,000,000 + Increase in inventory: 3,000,000 + Decrease in accounts payable: 2,000,000 - Noncash settlement of accounts payable: 1,000,000 + Freight in paid in cash: 500,000 = Cash disbursed for purchases: ₱22,500,000. Issuing shares to settle accounts payable reduces the liability without a cash outflow, so it must be subtracted to correct the cash payment calculation. Cash paid for freight in is a direct inventory acquisition cost and is added to the total payments." } },
  { "FAR-StatementOfCashFlows-194": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Company records reveal cost of goods sold of ₱40,000,000. Inventory decreased by ₱2,000,000 and accounts payable increased by ₱3,500,000 during the year. The company received ₱400,000 in cash refunds from suppliers for purchase returns instead of crediting accounts payable. Determine the net cash disbursed to suppliers.", "solution": 34100000, "explanation": "Cost of goods sold: ₱40,000,000 - Decrease in inventory: 2,000,000 - Increase in accounts payable: 3,500,000 - Cash refunds received for purchase returns: 400,000 = Net cash disbursed for purchases: ₱34,100,000. Receiving a cash refund for a purchase return acts as a cash inflow from suppliers, thereby reducing the net overall cash disbursed to them during the year." } },
  { "FAR-StatementOfCashFlows-195": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported cost of goods sold of ₱22,000,000. Inventory increased by ₱4,000,000 and accounts payable decreased by ₱1,000,000. The company also finances some purchases using trade notes payable, which increased by ₱2,500,000 during the year. What is the amount disbursed for purchases?", "solution": 24500000, "explanation": "Cost of goods sold: ₱22,000,000 + Increase in inventory: 4,000,000 + Decrease in accounts payable: 1,000,000 - Increase in trade notes payable: 2,500,000 = Cash disbursed for purchases: ₱24,500,000. Trade notes payable must be grouped with accounts payable as they both represent credit financing from suppliers. The increase in trade notes payable means cash was conserved, requiring a deduction." } },
  { "FAR-StatementOfCashFlows-196": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Data for the current year includes cost of goods sold of ₱15,000,000. Inventory increased by ₱1,200,000. Accounts payable decreased by ₱800,000. Advances to suppliers decreased by ₱500,000, while advances from customers increased by ₱1,000,000. Compute the amount disbursed to suppliers.", "solution": 16500000, "explanation": "Cost of goods sold: ₱15,000,000 + Increase in inventory: 1,200,000 + Decrease in accounts payable: 800,000 - Decrease in advances to suppliers: 500,000 = Cash disbursed to suppliers: ₱16,500,000. A decrease in advances to suppliers implies that the company received inventory it had already paid for in a prior period, reducing current cash outflows. Advances from customers relate to cash received from sales, not payments to suppliers, and is a distractor here." } },
  { "FAR-StatementOfCashFlows-197": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "A firm reported cost of goods sold of ₱50,000,000. Inventory decreased by ₱4,000,000. Accounts payable decreased by ₱5,000,000. The change in accounts payable includes an unrealized foreign exchange gain of ₱1,000,000 because many suppliers are billed in foreign currency. What is the amount disbursed for purchases?", "solution": 50000000, "explanation": "Cost of goods sold: ₱50,000,000 - Decrease in inventory: 4,000,000 + Decrease in accounts payable: 5,000,000 - Unrealized foreign exchange gain on accounts payable: 1,000,000 = Cash disbursed for purchases: ₱50,000,000. An unrealized foreign exchange gain on accounts payable causes the liability to decrease without any cash payment being made. Therefore, this noncash reduction must be stripped out of the accounts payable decrease to reflect the true cash settlement." } },
  { "FAR-StatementOfCashFlows-198": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "An entity reported cost of goods sold of ₱35,000,000, which includes ₱5,000,000 of factory depreciation capitalized into inventory and subsequently sold. During the year, inventory increased by ₱2,000,000 and accounts payable decreased by ₱3,000,000. Determine the cash disbursed for purchases.", "solution": 35000000, "explanation": "Cost of goods sold: ₱35,000,000 - Factory depreciation included in cost of goods sold: 5,000,000 + Increase in inventory: 2,000,000 + Decrease in accounts payable: 3,000,000 = Cash disbursed for purchases: ₱35,000,000. Factory depreciation is a noncash cost that artificially inflates the cost of goods sold figure without representing purchases from suppliers. Deducting the depreciation corrects the baseline before applying working capital adjustments." } },
  { "FAR-StatementOfCashFlows-199": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "The income statement shows cost of goods sold of ₱28,000,000. Inventory increased by ₱3,500,000, and accounts payable increased by ₱1,500,000. The company records its accounts payable at the gross amount. During the year, the company took cash discounts on purchases amounting to ₱800,000. What is the net cash disbursed for purchases?", "solution": 30000000, "explanation": "Net purchases: ₱31,500,000 - Increase in accounts payable: 1,500,000 = Cash disbursed for purchases: ₱30,000,000. First, find net purchases by adding the inventory increase of three million five hundred thousand to cost of goods sold, totaling thirty one million five hundred thousand. Because accounts payable is maintained at gross, adjusting net purchases directly by the gross change in accounts payable automatically yields the exact net cash disbursed, bypassing the need to manually subtract the discounts taken." } },
  { "FAR-StatementOfCashFlows-200": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Operating Activities", "type": "Problem Solving", "competency": "Analyze", "question": "Cost of goods sold was ₱60,000,000, which includes ₱4,000,000 of factory depreciation. An abnormal inventory shortage of ₱1,000,000 was discovered and written off to a separate loss account. During the year, inventory decreased by ₱5,000,000 and accounts payable decreased by ₱2,000,000. To extend payment terms, the company settled ₱3,000,000 of its accounts payable by issuing formal notes payable to suppliers. Calculate the cash disbursed for purchases.", "solution": 51000000, "explanation": "Cost of goods sold: ₱60,000,000 - Factory depreciation: 4,000,000 + Abnormal inventory shortage written off to loss: 1,000,000 - Decrease in inventory: 5,000,000 + Decrease in accounts payable: 2,000,000 - Accounts payable settled by issuing notes: 3,000,000 = Cash disbursed for purchases: ₱51,000,000. Factory depreciation is removed to find the true inventory credits related to supplier purchases. The abnormal shortage is added back because it represents inventory consumed outside of the cost of goods sold. The settlement of accounts payable via note issuance is a noncash transaction that artificially lowers accounts payable without a cash outflow, requiring deduction." } },
{ "FAR-StatementOfCashFlows-201": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Comprehensive Cash Balance", "type": "Problem Solving", "competency": "Analyze", "question": "At the beginning of the current year, an entity reported a cash balance of ₱10,000,000. During the year, the entity reported Total sales of ₱40,000,000, Cost of goods sold of ₱25,000,000, and Operating expenses of ₱8,000,000 which included depreciation of ₱2,000,000. The following account changes occurred: Accounts receivable increased by ₱3,000,000, Inventory decreased by ₱2,000,000, and Accounts payable decreased by ₱4,000,000. Additionally, the entity purchased equipment for ₱3,000,000 in cash. What is the cash balance at year-end?", "solution": 11000000, "explanation": "First, compute cash collected from customers. Sales: ₱40,000,000 - Increase in accounts receivable: 3,000,000 = Cash collected: ₱37,000,000. Next, compute cash paid to suppliers. Cost of goods sold: ₱25,000,000 - Decrease in inventory: 2,000,000 + Decrease in accounts payable: 4,000,000 = Cash paid to suppliers: ₱27,000,000. Next, compute cash paid for operating expenses. Operating expenses: ₱8,000,000 - Depreciation: 2,000,000 = Cash paid for operating expenses: ₱6,000,000. Finally, combine all cash flows with the beginning balance. Beginning cash balance: ₱10,000,000 + Cash collected: 37,000,000 - Cash paid to suppliers: 27,000,000 - Cash paid for operating expenses: 6,000,000 - Cash paid for equipment: 3,000,000 = Ending cash balance: ₱11,000,000. Depreciation is a noncash expense and is deducted from operating expenses. Purchasing equipment is an investing cash outflow." } },
  { "FAR-StatementOfCashFlows-202": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Comprehensive Cash Balance", "type": "Problem Solving", "competency": "Analyze", "question": "A company had a beginning cash balance of ₱5,000,000. Operations for the year showed Sales of ₱50,000,000, Cost of goods sold of ₱30,000,000, and Operating expenses of ₱10,000,000 including ₱3,000,000 in depreciation. Changes in working capital were: Accounts receivable decreased by ₱2,000,000, Inventory increased by ₱4,000,000, Accounts payable increased by ₱1,500,000, and Accrued operating expenses increased by ₱500,000. The company also paid cash dividends of ₱2,000,000. Calculate the cash balance at year-end.", "solution": 16000000, "explanation": "Sales: ₱50,000,000 + Decrease in accounts receivable: 2,000,000 = Cash collected: ₱52,000,000. Cost of goods sold: ₱30,000,000 + Increase in inventory: 4,000,000 - Increase in accounts payable: 1,500,000 = Cash paid to suppliers: ₱32,500,000. Operating expenses: ₱10,000,000 - Depreciation: 3,000,000 - Increase in accrued operating expenses: 500,000 = Cash paid for operating expenses: ₱6,500,000. Beginning cash balance: ₱5,000,000 + Cash collected: 52,000,000 - Cash paid to suppliers: 32,500,000 - Cash paid for operating expenses: 6,500,000 - Cash paid for dividends: 2,000,000 = Ending cash balance: ₱16,000,000. An increase in accrued expenses implies that some expenses were recognized but not yet paid, requiring a deduction from total expenses." } },
  { "FAR-StatementOfCashFlows-203": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Comprehensive Cash Balance", "type": "Problem Solving", "competency": "Analyze", "question": "The beginning cash balance was ₱12,000,000. For the year, Sales were ₱60,000,000, Cost of goods sold ₱35,000,000, and Operating expenses excluding depreciation were ₱12,000,000. Account changes included: Accounts receivable increased by ₱4,000,000, Unearned revenue increased by ₱1,000,000, Inventory decreased by ₱3,000,000, Accounts payable decreased by ₱2,500,000, and Prepaid expenses increased by ₱800,000. The firm also received ₱5,000,000 from a new bank loan. What is the year-end cash balance?", "solution": 26700000, "explanation": "Sales: ₱60,000,000 - Increase in accounts receivable: 4,000,000 + Increase in unearned revenue: 1,000,000 = Cash collected: ₱57,000,000. Cost of goods sold: ₱35,000,000 - Decrease in inventory: 3,000,000 + Decrease in accounts payable: 2,500,000 = Cash paid to suppliers: ₱34,500,000. Operating expenses: ₱12,000,000 + Increase in prepaid expenses: 800,000 = Cash paid for operating expenses: ₱12,800,000. Beginning cash balance: ₱12,000,000 + Cash collected: 57,000,000 - Cash paid to suppliers: 34,500,000 - Cash paid for operating expenses: 12,800,000 + Proceeds from bank loan: 5,000,000 = Ending cash balance: ₱26,700,000. The increase in unearned revenue represents additional cash collected upfront. An increase in prepaid expenses means cash was paid ahead of expense recognition." } },
  { "FAR-StatementOfCashFlows-204": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Comprehensive Cash Balance", "type": "Problem Solving", "competency": "Analyze", "question": "An entity started with ₱8,500,000 in cash. During the year: Gross sales ₱45,000,000; Sales returns credited to accounts receivable ₱1,000,000; Cost of goods sold ₱26,000,000; Operating expenses ₱15,000,000 including depreciation of ₱4,000,000 and bad debt expense of ₱1,000,000. Working capital shifts: Gross accounts receivable increased by ₱2,000,000, Inventory increased by ₱1,500,000, and Accounts payable increased by ₱3,000,000. The entity also purchased land for ₱4,500,000. Compute the ending cash balance.", "solution": 11500000, "explanation": "Gross sales: ₱45,000,000 - Sales returns: 1,000,000 - Increase in gross accounts receivable: 2,000,000 = Cash collected: ₱42,000,000. Cost of goods sold: ₱26,000,000 + Increase in inventory: 1,500,000 - Increase in accounts payable: 3,000,000 = Cash paid to suppliers: ₱24,500,000. Operating expenses: ₱15,000,000 - Depreciation: 4,000,000 - Bad debt expense: 1,000,000 = Cash paid for operating expenses: ₱10,000,000. Beginning cash balance: ₱8,500,000 + Cash collected: 42,000,000 - Cash paid to suppliers: 24,500,000 - Cash paid for operating expenses: 10,000,000 - Cash paid for land: 4,500,000 = Ending cash balance: ₱11,500,000. Both bad debt expense and depreciation are noncash operating expenses. Sales returns credited to receivables reduce the gross sales without providing cash." } },
  { "FAR-StatementOfCashFlows-205": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Comprehensive Cash Balance", "type": "Problem Solving", "competency": "Analyze", "question": "A firm reported a beginning cash balance of ₱15,000,000. Data for the year: Sales ₱70,000,000; Cost of goods sold ₱42,000,000; Operating expenses entirely paid in cash ₱14,000,000. Changes in balances: Accounts receivable decreased by ₱5,000,000, Inventory decreased by ₱2,500,000, and Accounts payable decreased by ₱4,500,000. The firm sold equipment for ₱2,000,000 cash and retired bonds by paying ₱6,000,000. What is the cash balance at year-end?", "solution": 28000000, "explanation": "Sales: ₱70,000,000 + Decrease in accounts receivable: 5,000,000 = Cash collected: ₱75,000,000. Cost of goods sold: ₱42,000,000 - Decrease in inventory: 2,500,000 + Decrease in accounts payable: 4,500,000 = Cash paid to suppliers: ₱44,000,000. Operating expenses paid in cash: ₱14,000,000. Beginning cash balance: ₱15,000,000 + Cash collected: 75,000,000 - Cash paid to suppliers: 44,000,000 - Cash paid for operating expenses: 14,000,000 + Cash proceeds from sale of equipment: 2,000,000 - Cash paid to retire bonds: 6,000,000 = Ending cash balance: ₱28,000,000." } },
  { "FAR-StatementOfCashFlows-206": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Comprehensive Cash Balance", "type": "Problem Solving", "competency": "Analyze", "question": "Beginning cash was ₱6,000,000. During the year: Sales ₱38,000,000; Cost of goods sold ₱20,000,000; Cash paid for operating expenses ₱10,000,000. Account changes: Accounts receivable increased by ₱3,500,000; Inventory increased by ₱1,200,000; Accounts payable increased by ₱1,800,000. The company received ₱4,000,000 from the sale of land and paid ₱3,000,000 in cash dividends. Calculate the year-end cash balance.", "solution": 12100000, "explanation": "Sales: ₱38,000,000 - Increase in accounts receivable: 3,500,000 = Cash collected: ₱34,500,000. Cost of goods sold: ₱20,000,000 + Increase in inventory: 1,200,000 - Increase in accounts payable: 1,800,000 = Cash paid to suppliers: ₱19,400,000. Beginning cash balance: ₱6,000,000 + Cash collected: 34,500,000 - Cash paid to suppliers: 19,400,000 - Cash paid for operating expenses: 10,000,000 + Proceeds from sale of land: 4,000,000 - Cash paid for dividends: 3,000,000 = Ending cash balance: ₱12,100,000." } },
  { "FAR-StatementOfCashFlows-207": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Comprehensive Cash Balance", "type": "Problem Solving", "competency": "Analyze", "question": "An entity started with ₱20,000,000 cash. Annual data: Sales ₱85,000,000; Cost of goods sold ₱50,000,000; Operating expenses ₱22,000,000 including ₱5,000,000 depreciation. Changes: Accounts receivable decreased by ₱6,000,000; Inventory decreased by ₱4,000,000; Accounts payable decreased by ₱7,000,000; Accrued operating expenses decreased by ₱1,500,000. The entity issued ordinary shares for ₱10,000,000. Determine the ending cash balance.", "solution": 49500000, "explanation": "Sales: ₱85,000,000 + Decrease in accounts receivable: 6,000,000 = Cash collected: ₱91,000,000. Cost of goods sold: ₱50,000,000 - Decrease in inventory: 4,000,000 + Decrease in accounts payable: 7,000,000 = Cash paid to suppliers: ₱53,000,000. Operating expenses: ₱22,000,000 - Depreciation: 5,000,000 + Decrease in accrued operating expenses: 1,500,000 = Cash paid for operating expenses: ₱18,500,000. Beginning cash balance: ₱20,000,000 + Cash collected: 91,000,000 - Cash paid to suppliers: 53,000,000 - Cash paid for operating expenses: 18,500,000 + Proceeds from issuing shares: 10,000,000 = Ending cash balance: ₱49,500,000. Decreasing accrued expenses requires an addition to cash payments because past liabilities were settled in the current period." } },
  { "FAR-StatementOfCashFlows-208": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Comprehensive Cash Balance", "type": "Problem Solving", "competency": "Analyze", "question": "Beginning cash balance was ₱4,500,000. Records show: Sales ₱32,000,000; Cost of goods sold ₱18,000,000; Operating expenses entirely in cash ₱9,000,000. Account changes: Accounts receivable increased by ₱2,500,000; Inventory increased by ₱3,000,000; Accounts payable increased by ₱4,500,000; Advances from customers increased by ₱1,200,000. The company bought new equipment for ₱5,000,000 cash. What is the year-end cash balance?", "solution": 4700000, "explanation": "Sales: ₱32,000,000 - Increase in accounts receivable: 2,500,000 + Increase in advances from customers: 1,200,000 = Cash collected: ₱30,700,000. Cost of goods sold: ₱18,000,000 + Increase in inventory: 3,000,000 - Increase in accounts payable: 4,500,000 = Cash paid to suppliers: ₱16,500,000. Beginning cash balance: ₱4,500,000 + Cash collected: 30,700,000 - Cash paid to suppliers: 16,500,000 - Cash paid for operating expenses: 9,000,000 - Cash paid for equipment: 5,000,000 = Ending cash balance: ₱4,700,000. Advances from customers generate upfront cash prior to revenue recognition, so an increase boosts collections." } },
  { "FAR-StatementOfCashFlows-209": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Comprehensive Cash Balance", "type": "Problem Solving", "competency": "Analyze", "question": "A firm began the year with ₱9,000,000 in cash. Financials indicate: Sales ₱55,000,000; Cost of goods sold ₱34,000,000; Operating expenses ₱16,000,000 including amortization of ₱2,000,000. Changes: Gross accounts receivable decreased by ₱3,000,000; Accounts written off ₱500,000; Inventory decreased by ₱1,800,000; Accounts payable decreased by ₱2,200,000; Prepaid rent decreased by ₱700,000. The firm repaid ₱4,000,000 of bank loan principal. Compute the ending cash balance.", "solution": 14800000, "explanation": "Sales: ₱55,000,000 + Decrease in gross accounts receivable: 3,000,000 - Accounts written off: 500,000 = Cash collected: ₱57,500,000. Cost of goods sold: ₱34,000,000 - Decrease in inventory: 1,800,000 + Decrease in accounts payable: 2,200,000 = Cash paid to suppliers: ₱34,400,000. Operating expenses: ₱16,000,000 - Amortization: 2,000,000 - Decrease in prepaid rent: 700,000 = Cash paid for operating expenses: ₱13,300,000. Beginning cash balance: ₱9,000,000 + Cash collected: 57,500,000 - Cash paid to suppliers: 34,400,000 - Cash paid for operating expenses: 13,300,000 - Payment of bank loan principal: 4,000,000 = Ending cash balance: ₱14,800,000. A decrease in prepaid rent indicates past cash outlays were expensed in the current year, reducing current cash needs." } },
  { "FAR-StatementOfCashFlows-210": { "subject": "FAR", "topic": "Statement of Cash Flows", "subtopic": "Comprehensive Cash Balance", "type": "Problem Solving", "competency": "Analyze", "question": "The beginning cash balance was ₱25,000,000. Current year data: Sales ₱90,000,000; Cost of goods sold ₱60,000,000; Cash paid directly for operating expenses ₱15,000,000. Working capital shifts: Accounts receivable increased by ₱8,000,000; Inventory increased by ₱5,000,000; Accounts payable decreased by ₱3,000,000; Advances to suppliers increased by ₱2,000,000. The company issued bonds for ₱12,000,000 and purchased treasury shares for ₱4,000,000. What is the year-end cash balance?", "solution": 30000000, "explanation": "Sales: ₱90,000,000 - Increase in accounts receivable: 8,000,000 = Cash collected: ₱82,000,000. Cost of goods sold: ₱60,000,000 + Increase in inventory: 5,000,000 + Decrease in accounts payable: 3,000,000 + Increase in advances to suppliers: 2,000,000 = Cash paid to suppliers: ₱70,000,000. Beginning cash balance: ₱25,000,000 + Cash collected: 82,000,000 - Cash paid to suppliers: 70,000,000 - Cash paid for operating expenses: 15,000,000 + Proceeds from issuing bonds: 12,000,000 - Cash paid for treasury shares: 4,000,000 = Ending cash balance: ₱30,000,000. Increasing advances to suppliers represents cash sent to vendors before goods are received, adding to the total cash disbursed for purchases." } }  
  
];
